# ── Vault root helper ──────────────────────────────────────────────────────────

def _resolve_vault(vault_root_arg: str | None) -> Path:
    if vault_root_arg:
        return Path(vault_root_arg)
    return _detect_vault_root()


def _block_runtime_operation(args: argparse.Namespace, operation: str, reason: str) -> int:
    if getattr(args, "output_json", False):
        print(json.dumps({"allowed": False, "operation": operation, "reason": reason}, indent=2))
    else:
        print(f"ERROR: runtime policy denied {operation}: {reason}", file=sys.stderr)
    return 1


def cmd_audit_secrets(args: argparse.Namespace) -> int:
    """chaseos audit secrets - repo-safe secret classifier."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None)).resolve()
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.repo_secret_audit import audit_repo_secrets, format_repo_secret_audit

    payload = audit_repo_secrets(vault_root, max_scan_files=getattr(args, "max_files", 5000))
    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2, default=str))
    else:
        print(format_repo_secret_audit(payload))
    return 0 if payload.get("ok") else 1


def _check_runtime_operation_or_block(
    args: argparse.Namespace,
    operation: str,
    *,
    write_targets: list[str] | None = None,
    external_api: str | None = None,
    external_side_effect: bool = False,
) -> int | None:
    allowed, reason = check_runtime_operation(
        operation,
        write_targets=write_targets,
        external_api=external_api,
        external_side_effect=external_side_effect,
    )
    if allowed:
        return None
    return _block_runtime_operation(args, operation, reason)


def _cli_scaffold_slug(name: str) -> str:
    slug = re.sub(r"[^a-z0-9]+", "-", str(name).strip().lower()).strip("-")
    return slug or "unnamed"


def _scaffold_operation_write_targets(scaffold_type: str, name: str) -> list[str]:
    slug = _cli_scaffold_slug(name)
    return [f"runtime/scaffold/generated/{scaffold_type}-{slug}/scaffold_request.json"]


def _runtime_registry_write_targets(runtime_id: str) -> list[str]:
    return [
        f"runtime/aor/runtime_registry/{runtime_id}/registry_entry.yaml",
        f"runtime/aor/runtime_registry/{runtime_id}/audit/lifecycle_log.jsonl",
    ]


def _runtime_lifecycle_write_targets() -> list[str]:
    return [
        "runtime/lifecycle/run/",
        "runtime/lifecycle/bootstrap/",
        "07_LOGS/Agent-Activity/",
    ]


def _run_coordination_preflight(
    workflow_id: str,
    *,
    manifest: dict,
    adapter_id: str | None,
    coordination_via: str | None,
) -> tuple[bool, str]:
    """Apply bus-first coordination enforcement for coordination-sensitive workflows."""
    coordination = manifest.get("coordination_requirements") or {}
    if coordination.get("coordination_sensitive") is not True:
        return True, "workflow is not coordination-sensitive"

    if not adapter_id:
        return (
            False,
            f"Workflow '{workflow_id}' is coordination-sensitive and requires --adapter so ChaseOS can enforce the bus-owned coordination path.",
        )

    expected_adapter = manifest.get("runtime_adapter")
    if expected_adapter and adapter_id != expected_adapter:
        return (
            False,
            f"Workflow '{workflow_id}' is bound to adapter '{expected_adapter}', not '{adapter_id}'.",
        )

    via_bus = coordination_via == "runtime/agent_bus/"
    target_runtime = coordination.get("partner_runtime")
    allowed, reason = check_coordination_path(
        adapter_id,
        coordination_sensitive=True,
        via_bus=via_bus,
        target_runtime=target_runtime,
    )
    if not allowed:
        return False, reason
    return True, reason


def _build_runtime_inventory() -> list[dict]:
    inventory: list[dict] = []
    for runtime_id in list_known_runtimes(includePartial=True):
        try:
            lifecycle = load_lifecycle_record(runtime_id)
        except Exception as exc:
            inventory.append({"runtime_id": runtime_id, "error": str(exc)})
            continue

        health = lifecycle.get("health", {}) if isinstance(lifecycle, dict) else {}
        inventory.append(
            {
                "runtime_id": runtime_id,
                "platform": lifecycle.get("platform"),
                "lifecycle_mode": lifecycle.get("lifecycle_mode"),
                "probe_kind": health.get("kind"),
                "probe_label": health.get("probe_label"),
                "candidate_ports": health.get("candidate_ports") or [],
                "candidate_urls": health.get("urls") or ([health.get("url")] if health.get("url") else []),
                "probe_notes": health.get("notes"),
            }
        )
    return inventory


def _print_runtime_inventory(inventory: list[dict], as_json: bool) -> int:
    if as_json:
        print(json.dumps(inventory, indent=2))
        return 0

    print("ChaseOS Runtime Inventory")
    print(f"  discovered_runtimes: {', '.join(item.get('runtime_id', 'unknown') for item in inventory)}")
    for item in inventory:
        print()
        print(f"Runtime: {item.get('runtime_id')}")
        if item.get("error"):
            print(f"  error: {item['error']}")
            continue
        print(f"  platform: {item.get('platform')}")
        print(f"  lifecycle_mode: {item.get('lifecycle_mode')}")
        print(f"  probe_kind: {item.get('probe_kind')}")
        if item.get("probe_label"):
            print(f"  probe_label: {item.get('probe_label')}")
        if item.get("candidate_ports"):
            print(f"  candidate_ports: {', '.join(str(port) for port in item['candidate_ports'])}")
        if item.get("candidate_urls"):
            print(f"  candidate_urls: {', '.join(item['candidate_urls'])}")
        if item.get("probe_notes"):
            print(f"  probe_notes: {item.get('probe_notes')}")
    return 0


def _print_one_runtime_status(state: dict) -> None:
    print(f"  runtime_id: {state.get('runtime_id')}")
    print(f"  adapter_id: {state.get('adapter_id')}")
    print(f"  platform_family: {state.get('platform_family')}")
    print(f"  attachment_mode: {state.get('attachment_mode')}")
    print(f"  user_binding_present: {state.get('user_binding_present')}")
    print(f"  trust_ceiling: {state.get('trust_ceiling')}")
    print(f"  approval_mode: {state.get('approval_mode')}")
    print(f"  protected_file_behavior: {state.get('protected_file_behavior')}")
    print(f"  external_side_effect_policy: {state.get('external_side_effect_policy')}")
    print(f"  bootstrap_status: {state.get('bootstrap_status')}")
    if state.get("active_task_types"):
        print(f"  active_task_types: {', '.join(state['active_task_types'])}")
    if state.get("allowed_write_targets"):
        print(f"  allowed_write_targets: {', '.join(state['allowed_write_targets'])}")
    sources = state.get("sources") or {}
    if any(sources.values()):
        print("  sources:")
        for key in ["adapter_manifest", "runtime_bootstrap", "user_attachment", "runtime_nav"]:
            if sources.get(key):
                print(f"    {key}: {sources[key]}")
    if state.get("notes"):
        print(f"  notes: {state['notes']}")


def _print_runtime_status(state: dict | list[dict], as_json: bool) -> int:
    if as_json:
        print(json.dumps(state, indent=2))
        return 0

    if isinstance(state, list):
        print("ChaseOS Runtime Status")
        print(f"  detected_runtimes: {', '.join(item.get('runtime_id', 'unknown') for item in state)}")
        for item in state:
            print()
            print(f"Runtime: {item.get('runtime_id')}")
            _print_one_runtime_status(item)
        return 0

    print("ChaseOS Runtime Status")
    _print_one_runtime_status(state)
    return 0


def _print_one_health_result(result: dict) -> None:
    print(f"Runtime health: {result['runtime_id']}")
    print(f"  kind: {result.get('kind')}")
    if result.get("probe_label"):
        print(f"  probe_label: {result['probe_label']}")
    if result.get("probe_notes"):
        print(f"  probe_notes: {result['probe_notes']}")
    if result.get("candidate_ports"):
        print(f"  candidate_ports: {', '.join(str(port) for port in result['candidate_ports'])}")
    if result.get("url"):
        print(f"  url: {result['url']}")
    if result.get("urls"):
        print(f"  candidate_urls: {', '.join(result['urls'])}")
    if result.get("command"):
        print(f"  command: {result['command']}")
    print(f"  healthy: {result['healthy']}")
    print(f"  timed_out: {result['timed_out']}")
    if result.get("status_code") is not None:
        print(f"  status_code: {result['status_code']}")
    if result.get("returncode") is not None:
        print(f"  returncode: {result['returncode']}")
    if result.get("failure_reason"):
        print(f"  failure_reason: {result['failure_reason']}")
    if result.get("stdout"):
        print(f"  stdout: {result['stdout']}")
    if result.get("stderr"):
        print(f"  stderr: {result['stderr']}")
    if result.get("probes"):
        print("  probes:")
        for probe in result["probes"]:
            print(f"    - url: {probe.get('url')}")
            print(f"      healthy: {probe.get('healthy')}")
            print(f"      timed_out: {probe.get('timed_out')}")
            if probe.get("status_code") is not None:
                print(f"      status_code: {probe.get('status_code')}")
            if probe.get("failure_reason"):
                print(f"      failure_reason: {probe.get('failure_reason')}")


def _print_health_result(result: dict | list[dict], as_json: bool) -> int:
    if as_json:
        print(json.dumps(result, indent=2))
        if isinstance(result, list):
            return 0 if all(item.get("healthy") for item in result) else 1
        return 0 if result.get("healthy") else 1

    if isinstance(result, list):
        print("ChaseOS Runtime Health")
        print(f"  detected_runtimes: {', '.join(item.get('runtime_id', 'unknown') for item in result)}")
        for item in result:
            print()
            _print_one_health_result(item)
        return 0 if all(item.get("healthy") for item in result) else 1

    _print_one_health_result(result)
    return 0 if result.get("healthy") else 1


