def _print_startup_surface_settings_result(result: dict, as_json: bool) -> int:
    if as_json:
        print(json.dumps(result, indent=2))
        return 0
    print("ChaseOS Runtime Startup Surface Settings")
    print(f"  read_only: {result.get('read_only')}")
    print(f"  settings_write_enabled: {result.get('settings_write_enabled')}")
    print(f"  mutation_enabled: {result.get('mutation_enabled')}")
    print(f"  runtime_count: {result.get('runtime_count')}")
    print(f"  surface_count: {result.get('surface_count')}")
    for runtime in result.get("runtimes", []):
        print(f"\n{runtime.get('runtime_id')} ({runtime.get('runtime_name')})")
        for setting in runtime.get("settings", []):
            print(
                "  - "
                f"{setting.get('surface_id')}: state={setting.get('current_state')} "
                f"user_manageable={setting.get('user_manageable')} "
                f"cli_mutation_enabled={setting.get('cli_mutation_enabled')} "
                f"studio_mutation_enabled={setting.get('studio_mutation_enabled')}"
            )
            launch_profile = setting.get("launch_profile") or {}
            if launch_profile:
                print(
                    "    launch: "
                    f"{launch_profile.get('launch_kind')} "
                    f"distro={launch_profile.get('wsl_distro')} "
                    f"user={launch_profile.get('wsl_user')}"
                )
            managed = setting.get("managed_target_launcher") or {}
            if managed:
                print(
                    "    managed_target_launcher: "
                    f"target_present={managed.get('target_present')} "
                    f"matches_expected={managed.get('matches_expected')}"
                )
    return 0


