def _print_startup_surface_host_boundary_policy_result(result: dict, as_json: bool) -> int:
    if as_json:
        print(json.dumps(result, indent=2))
        return 0

    print("ChaseOS Runtime Startup Surface Host-Boundary Policy")
    print(f"  runtime_id: {result.get('runtime_id')}")
    print(f"  surface_id: {result.get('surface_id')}")
    print(f"  intent: {result.get('intent')}")
    print(f"  policy_status: {result.get('policy_status')}")
    print(f"  executor_enabled_now: {result.get('executor_enabled_now')}")
    print(f"  host_mutation_attempted: {result.get('host_mutation_attempted')}")
    host_boundary = result.get("wsl_windows_boundary") or {}
