def cmd_mvp_operator_input_template(args: argparse.Namespace) -> int:
    """chaseos mvp operator-input-template - standalone fillable no-secret input template."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None)).resolve()
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.mvp_readiness_gate import (
        build_mvp_operator_input_template_packet,
        format_mvp_operator_input_template_packet,
    )

    payload = build_mvp_operator_input_template_packet(vault_root)
    write_template = getattr(args, "write_template", None)
    if write_template:
        requested = Path(write_template)
        target = requested if requested.is_absolute() else vault_root / requested
        target = target.resolve()
        try:
            target.relative_to(vault_root)
        except ValueError:
            message = f"operator input template path must stay inside vault root: {target}"
            if getattr(args, "output_json", False):
                payload["ok"] = False
                payload["error"] = message
                print(json.dumps(payload, indent=2, default=str))
            else:
                print(f"ERROR: {message}", file=sys.stderr)
            return 1
        template_artifact = {
            "surface": "chaseos_mvp_operator_input_values_template",
            "model_version": "chaseos.mvp_operator_input_values_template.v1",
            "generated_at_utc": payload.get("generated_at_utc"),
            "source_template_command": "python -m runtime.cli.main mvp operator-input-template --json",
            "validation_command": payload.get("validation_command"),
            "objective_achieved": bool(payload.get("objective_achieved")),
            "safe_to_call_update_goal_complete": bool(
                payload.get("safe_to_call_update_goal_complete")
            ),
            "operator_input_ids": list(payload.get("operator_input_ids") or []),
            "p0_blocker_ids": list(payload.get("p0_blocker_ids") or []),
            "p1_decision_ids": list(payload.get("p1_decision_ids") or []),
            "completion_decision": dict(payload.get("completion_decision") or {}),
            "autonomous_completion_barrier": dict(
                payload.get("autonomous_completion_barrier") or {}
            ),
            "completion_safety_contract": dict(
                payload.get("completion_safety_contract") or {}
            ),
            "required_operator_inputs": list(payload.get("required_operator_inputs") or []),
            "operator_input_values": payload.get("operator_input_values") or {},
            "operator_notes": list(payload.get("operator_notes") or []),
            "forbidden_values": list(
                (payload.get("operator_input_template") or {}).get("forbidden_values") or []
            ),
            "boundary": dict(payload.get("boundary") or {}),
        }
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(json.dumps(template_artifact, indent=2, default=str) + "\n", encoding="utf-8")
        payload["read_only"] = False
        payload["template_write"] = {
            "written": True,
            "path": str(target),
            "vault_relative_path": target.relative_to(vault_root).as_posix(),
            "contains_secret_values": False,
            "writes_only_template_artifact": True,
            "provider_call_performed": False,
            "setup_metadata_write_performed": False,
            "approval_consumption_performed": False,
            "agent_bus_task_write_performed": False,
            "browser_control_performed": False,
            "host_mutation_performed": False,
            "canonical_mutation_performed": False,
        }
    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2, default=str))
        return 0
    print(format_mvp_operator_input_template_packet(payload))
    return 0


def cmd_mvp_validate_operator_input(args: argparse.Namespace) -> int:
    """chaseos mvp validate-operator-input - validate filled no-secret MVP operator input."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None)).resolve()
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    input_path = Path(getattr(args, "input_path")).resolve()
    try:
        input_payload = json.loads(input_path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError) as exc:
        if getattr(args, "output_json", False):
            print(
                json.dumps(
                    {
                        "ok": False,
                        "surface": "chaseos_mvp_operator_input_validation",
                        "error": f"operator input JSON unreadable: {exc}",
                        "source_path": str(input_path),
                    },
                    indent=2,
                    default=str,
                )
            )
        else:
            print(f"ERROR: operator input JSON unreadable: {exc}", file=sys.stderr)
        return 1
    if not isinstance(input_payload, dict):
        if getattr(args, "output_json", False):
            print(
                json.dumps(
                    {
                        "ok": False,
                        "surface": "chaseos_mvp_operator_input_validation",
                        "error": "operator input JSON must be an object",
                        "source_path": str(input_path),
                    },
                    indent=2,
                    default=str,
                )
            )
        else:
            print("ERROR: operator input JSON must be an object", file=sys.stderr)
        return 1

    from runtime.mvp_readiness_gate import (
        build_mvp_operator_input_validation,
        format_mvp_operator_input_validation,
    )

    payload = build_mvp_operator_input_validation(vault_root, input_payload, source_path=str(input_path))
    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2, default=str))
        return 0
    print(format_mvp_operator_input_validation(payload))
    return 0


def _add_setup_subcommands(subparsers: argparse._SubParsersAction) -> None:
    setup = subparsers.add_parser("setup", help="Provider, integration, and onboarding setup commands")
    setup_sub = setup.add_subparsers(dest="setup_mode", metavar="MODE")
    setup_sub.required = True

    init_parser = setup_sub.add_parser("init", help="Show or apply setup init scaffold plan")
    init_parser.add_argument("--profile", default="personal", help="Setup init profile")
    init_parser.add_argument(
        "--include-family",
        action="append",
        choices=["canonical-folder-local", "convenience", "orientation", "os-core"],
        help="Include optional scaffold family",
    )
    init_parser.add_argument(
        "--exclude-family",
        action="append",
        choices=["canonical-folder-local", "convenience", "orientation", "os-core"],
        help="Exclude optional scaffold family",
    )
    init_parser.add_argument("--write", action="store_true", help="Create missing scaffold folders/files without overwriting existing ones")
    init_parser.add_argument("--json", action="store_true", help="Print JSON output")
    init_parser.set_defaults(func=setup_cli.cmd_init)

    status_parser = setup_sub.add_parser("status", help="Show current setup state example")
    status_parser.add_argument("--json", action="store_true", help="Print JSON output")
    status_parser.set_defaults(func=setup_cli.cmd_status)

    provider_parser = setup_sub.add_parser("provider", help="Provider setup surfaces")
    provider_parser.add_argument("setup_command", choices=["list", "show", "wizard", "validate"], help="Provider setup command")
    provider_parser.add_argument("target_id", nargs="?", default=None, help="Provider id for show/wizard")
    provider_parser.add_argument("--apply", action="store_true", help="Apply wizard-proposed non-secret setup state")
    provider_parser.add_argument("--json", action="store_true", help="Print JSON output")
    provider_parser.set_defaults(func=setup_cli.cmd_provider)

    integration_parser = setup_sub.add_parser("integration", help="Integration setup surfaces")
    integration_parser.add_argument("setup_command", choices=["list", "show", "wizard", "validate"], help="Integration setup command")
    integration_parser.add_argument("target_id", nargs="?", default=None, help="Integration id for show/wizard")
    integration_parser.add_argument("--apply", action="store_true", help="Apply wizard-proposed non-secret setup state")
    integration_parser.add_argument("--json", action="store_true", help="Print JSON output")
    integration_parser.set_defaults(func=setup_cli.cmd_integration)

    discord_parser = setup_sub.add_parser("discord", help="Discord control-plane binding setup surfaces")
    discord_parser.add_argument("setup_command", choices=["validate"], help="Discord setup command")
    discord_parser.add_argument("--vault-root", default=None, metavar="PATH", help="Override vault root path")
    discord_parser.add_argument("--json", action="store_true", help="Print JSON output")
    discord_parser.set_defaults(func=setup_cli.cmd_discord)

    validate_parser = setup_sub.add_parser("validate", help="Validate current setup state")
    validate_parser.add_argument("--json", action="store_true", help="Print JSON output")
    validate_parser.set_defaults(func=setup_cli.cmd_validate)

    set_parser = setup_sub.add_parser("set", help="Update non-secret setup state flags")
    set_parser.add_argument("target_kind", choices=["provider", "integration"], help="Target kind")
    set_parser.add_argument("target_id", help="Target id")
    set_parser.add_argument("items", nargs="+", help="Patch items in key=value form")
    set_parser.add_argument("--dry-run", action="store_true", help="Preview non-secret setup state update without writing")
    set_parser.add_argument("--json", action="store_true", help="Print JSON output")
    set_parser.set_defaults(func=setup_cli.cmd_set)

    menu_parser = setup_sub.add_parser("menu", help="Show the setup menu")
    menu_parser.add_argument("--json", action="store_true", help="Print JSON output")
    menu_parser.set_defaults(func=setup_cli.cmd_menu)

    path_parser = setup_sub.add_parser(
        "path",
        help="Add vault .venv/Scripts to Windows user PATH (one-time setup)",
    )
    path_parser.add_argument("--vault-root", dest="vault_root", default=None, metavar="PATH", help="Vault root (default: cwd)")
    path_parser.add_argument("--dry-run", dest="dry_run", action="store_true", help="Show what would be added without modifying PATH")
    path_parser.add_argument("--json", action="store_true", help="Print JSON output")
    path_parser.set_defaults(func=setup_cli.cmd_path)


