def _add_capture_args(p: argparse.ArgumentParser) -> None:
    """Add shared metadata args to a capture subparser."""
    p.add_argument(
        "--class",
        dest="input_class",
        required=True,
        choices=sorted(VALID_INPUT_CLASSES),
        metavar="CLASS",
        help=(
            "Intake class -- determines quarantine subfolder. "
            f"Choices: {', '.join(sorted(VALID_INPUT_CLASSES))}"
        ),
    )
    p.add_argument(
        "--source",
        dest="source_platform",
        required=True,
        metavar="SOURCE",
        help="Source platform (e.g. youtube, perplexity, web, pdf, manual)",
    )
    p.add_argument(
        "--title",
        required=True,
        help="Human-readable title (used in filename slug)",
    )
    p.add_argument("--url", dest="source_url", default=None, help="Source URL")
    p.add_argument("--author", default=None, help="Author or creator")
    p.add_argument(
        "--workspace",
        dest="workspace_hint",
        default=None,
        metavar="WORKSPACE",
        help=(
            "Optional Source Intelligence Core workspace hint for future ingestion after promotion. "
            "Does not trigger Source Intelligence Core at capture time."
        ),
    )

    # Semantic breadcrumb hints (Pass 3)
    p.add_argument(
        "--domain",
        dest="domain_hint",
        default=None,
        metavar="DOMAIN",
        help=(
            "ChaseOS domain hint for later Source Intelligence Core workspace grouping. "
            "E.g. trading-systems, ai-engineering, cybersecurity. "
            "Hint only -- does not trigger Source Intelligence Core or change routing."
        ),
    )
    p.add_argument(
        "--project",
        dest="project_hint",
        default=None,
        metavar="PROJECT",
        help=(
            "Active project hint for later project linking. "
            "E.g. chaseos, tradesync, strikezone. "
            "Hint only."
        ),
    )
    p.add_argument(
        "--topic",
        dest="topic_hint",
        default=None,
        metavar="TOPIC",
        help=(
            "Loose subject label for retrieval context. "
            "E.g. market-microstructure, semantic-routing. "
            "Hint only."
        ),
    )
    p.add_argument(
        "--event-date",
        dest="event_date_hint",
        default=None,
        metavar="DATE",
        help=(
            "ISO 8601 date (YYYY-MM-DD) of when the event/content occurred. "
            "E.g. 2026-03-15 for a lecture from that date. "
            "Use when capture date differs from content date. Hint only."
        ),
    )
    p.add_argument(
        "--origin-kind",
        dest="origin_kind",
        default=None,
        metavar="KIND",
        help=(
            "What kind of entity authored this content at source. "
            "Canonical values: human-authored, ai-generated, "
            "human-ai-collaborative, personal-reflection, raw-data. "
            "Hint only."
        ),
    )
    p.add_argument(
        "--output-kind",
        dest="desired_output_kind",
        default=None,
        metavar="KIND",
        help=(
            "What kind of output the operator wants this to feed. "
            "Canonical values: synthesis, briefing, generated-idea, "
            "source-note, reference. "
            "Hint only -- does not trigger Source Intelligence Core or auto-promote."
        ),
    )

    p.add_argument(
        "--auto-link",
        dest="auto_link",
        action="store_true",
        default=False,
        help=(
            "For meeting-transcript captures: automatically run the meeting_ingest_linker "
            "Agent Orchestration Runtime workflow after capture and write a link-proposal file to "
            "07_LOGS/Link-Proposals/. Fail-open -- capture always succeeds first."
        ),
    )
    p.add_argument(
        "--vault-root",
        default=None,
        metavar="PATH",
        help="Override vault root path (auto-detected by default)",
    )
    p.add_argument(
        "--json",
        action="store_true",
        dest="output_json",
        help="Output result as JSON",
    )


