def _add_capture_markdown_args(p: argparse.ArgumentParser) -> None:
    """Add shared Capture to Markdown source and metadata args."""

    source_group = p.add_mutually_exclusive_group(required=True)
    source_group.add_argument("--text", dest="text", default=None, metavar="TEXT", help="Operator-supplied visible text")
    source_group.add_argument("--from-file", dest="from_file", default=None, metavar="PATH", help="Explicit local text/Markdown file")
    source_group.add_argument("--from-html", dest="from_html", default=None, metavar="PATH", help="Explicit local saved HTML file")
    source_group.add_argument("--from-controlled-html", dest="from_controlled_html", default=None, metavar="PATH", help="Confined Browser Runtime or Studio webview HTML artifact")
    source_group.add_argument("--from-screenshot", dest="from_screenshot", default=None, metavar="PATH", help="Explicit vault-local screenshot image attachment; optical character recognition disabled")
    source_group.add_argument("--from-screenshot-text", dest="from_screenshot_text", default=None, metavar="PATH", help="Explicit vault-local screenshot image; extract text through a local optical character recognition command")
    source_group.add_argument("--from-stdin", dest="from_stdin", action="store_true", help="Read source text from stdin")
    p.add_argument("--profile", default="research_note", metavar="PROFILE", help="Capture profile id or alias")
    p.add_argument("--title", required=True, metavar="TITLE", help="Human-readable capture title")
    p.add_argument("--url", dest="source_url", default=None, metavar="URL", help="Original source URL, if known")
    p.add_argument("--allowed-origin", dest="allowed_origin", default=None, metavar="ORIGIN", help="Required source origin for controlled HTML artifacts")
    p.add_argument(
        "--controlled-source",
        dest="controlled_source",
        default="browser_runtime_artifact",
        choices=sorted(CONTROLLED_BROWSER_ARTIFACT_SOURCE_SELECTORS),
        metavar="SOURCE",
        help="Controlled HTML source selector",
    )
    p.add_argument("--user-intent", dest="user_intent", default=None, metavar="TEXT", help="Operator intent for later review")
    p.add_argument("--structured-notes", dest="structured_notes", default=None, metavar="TEXT", help="Operator notes kept separate from raw text")
    p.add_argument("--generated-summary", dest="generated_summary", default=None, metavar="TEXT", help="Generated summary, stored as untrusted metadata")
    p.add_argument("--generated-interpretation", dest="generated_interpretation", default=None, metavar="TEXT", help="Generated interpretation, stored separately from raw text")
    p.add_argument("--source-window-title", dest="source_window_title", default=None, metavar="TEXT", help="Visible source window title, if known")
    p.add_argument("--source-page-title", dest="source_page_title", default=None, metavar="TEXT", help="Visible source page title, if known")
    p.add_argument("--captured-by", dest="captured_by", default=None, metavar="NAME", help="Capture actor label")
    p.add_argument("--timezone", dest="timezone_name", default="Europe/London", metavar="TZ", help="Capture timezone label")
    p.add_argument("--confidence", dest="confidence", default="operator_supplied", metavar="LEVEL", help="Extraction confidence label")
    p.add_argument("--local-optical-character-recognition-command", dest="local_ocr_command", default=None, metavar="COMMAND", help="Local command for image text extraction; no cloud provider is called")
    p.add_argument("--local-optical-character-recognition-timeout-seconds", dest="local_ocr_timeout_seconds", type=int, default=20, metavar="SECONDS", help="Local image text extraction timeout")
    p.add_argument("--allow-secret-redaction", dest="allow_secret_redaction", action="store_true", help="Allow explicit redacted save when secret-like text is detected")
    p.add_argument("--vault-root", default=None, metavar="PATH", help="Override vault root path")
    p.add_argument("--json", action="store_true", dest="output_json", help="Output result as JSON")


def _print_capture_result(result: dict, output_json: bool) -> None:
    if output_json:
        print(json.dumps(result, indent=2))
    elif result.get("is_duplicate"):
        print(f"DUPLICATE: {result.get('title', '(no title)')}")
        print(f"  SHA-256:          {result['content_sha256'][:16]}...")
        print(f"  First captured:   {result.get('original_captured_at', 'unknown')}")
        print(f"  Capture ID:       {result.get('duplicate_of', 'unknown')}")
        print()
        print("  Content not re-captured (already in dedup registry).")
    else:
        print(f"Captured: {result['filename']}")
        print(f"  Quarantine: {result['quarantine_dir']}")
        print(f"  Content:    {result['content_path']}")
        print(f"  Sidecar:    {result['sidecar_path']}")
        print(f"  ID:         {result['capture_id']}")
        print(f"  SHA256:     {result['content_sha256'][:16]}...")
        print()
        print("  Next steps: review in quarantine, then promote via Gate.")
        print("  Source Intelligence Core ingestion happens after Gate promotion - not now.")


