def _capture_markdown_common_kwargs(args: argparse.Namespace) -> dict:
    return {
        "profile": getattr(args, "profile", None) or "research_note",
        "user_intent": getattr(args, "user_intent", None) or "",
        "structured_notes": getattr(args, "structured_notes", None) or "",
        "generated_summary": getattr(args, "generated_summary", None) or "",
        "generated_interpretation": getattr(args, "generated_interpretation", None) or "",
        "source_url": getattr(args, "source_url", None) or "",
        "source_window_title": getattr(args, "source_window_title", None) or "",
        "source_page_title": getattr(args, "source_page_title", None) or "",
        "captured_by": getattr(args, "captured_by", None) or "cli-operator",
        "timezone_name": getattr(args, "timezone_name", None) or "Europe/London",
        "confidence": getattr(args, "confidence", None) or "operator_supplied",
        "allow_secret_redaction": bool(getattr(args, "allow_secret_redaction", False)),
    }


def _capture_markdown_packet(args: argparse.Namespace):
    title = str(getattr(args, "title", "") or "").strip()
    common = _capture_markdown_common_kwargs(args)

    if getattr(args, "from_stdin", False):
        return capture_visual_from_text(
            text=sys.stdin.read(),
            title=title,
            capture_method="cli_stdin",
            declared_source="cli_stdin",
            source_app="cli",
            source_platform="visual-capture",
            **common,
        )

    text = getattr(args, "text", None)
    if text is not None:
        return capture_visual_from_text(
            text=text,
            title=title,
            capture_method="cli_text",
            declared_source="cli_text",
            source_app="cli",
            source_platform="visual-capture",
            **common,
        )

    from_file = getattr(args, "from_file", None)
    if from_file:
        file_common = {
            key: value
            for key, value in common.items()
            if key not in {"source_page_title", "source_url"}
        }
        return capture_visual_from_text_file(
            file_path=from_file,
            title=title,
            **file_common,
        )

    from_html = getattr(args, "from_html", None)
    if from_html:
        html_common = {
            key: value
            for key, value in common.items()
            if key not in {"source_page_title", "source_url"}
        }
        return capture_visual_from_saved_html(
            file_path=from_html,
            title=title,
            source_url=getattr(args, "source_url", None),
            **html_common,
        )

    from_controlled_html = getattr(args, "from_controlled_html", None)
    if from_controlled_html:
        declared_url = getattr(args, "source_url", None)
        if not str(declared_url or "").strip():
            raise ValueError("--url is required with --from-controlled-html.")
        controlled_common = {
            key: value
            for key, value in common.items()
            if key not in {"source_page_title", "source_url"}
        }
        return capture_visual_from_controlled_browser_artifact(
            file_path=from_controlled_html,
            vault_root=_resolve_vault(getattr(args, "vault_root", None)),
            declared_url=declared_url,
            allowed_origin=getattr(args, "allowed_origin", None),
            source_selector=getattr(args, "controlled_source", None) or "browser_runtime_artifact",
            title=title,
            **controlled_common,
        )

    from_screenshot = getattr(args, "from_screenshot", None)
    if from_screenshot:
        screenshot_common = {
            key: value
            for key, value in common.items()
            if key not in {"source_page_title", "source_url"}
        }
        return capture_visual_from_screenshot_attachment(
            file_path=from_screenshot,
            vault_root=_resolve_vault(getattr(args, "vault_root", None)),
            title=title,
            source_url=getattr(args, "source_url", None),
            **screenshot_common,
        )

    from_screenshot_text = getattr(args, "from_screenshot_text", None)
    if from_screenshot_text:
        screenshot_text_common = {
            key: value
            for key, value in common.items()
            if key not in {"source_page_title", "source_url"}
        }
        return capture_visual_from_screenshot_text(
            file_path=from_screenshot_text,
            vault_root=_resolve_vault(getattr(args, "vault_root", None)),
            title=title,
            source_url=getattr(args, "source_url", None),
            local_ocr_command=getattr(args, "local_ocr_command", None),
            local_ocr_timeout_seconds=getattr(args, "local_ocr_timeout_seconds", 20),
            **screenshot_text_common,
        )

    raise ValueError("One source is required: --text, --from-file, --from-html, --from-controlled-html, --from-screenshot, --from-screenshot-text, or --from-stdin.")


def _print_capture_markdown_payload(payload: dict, output_json: bool) -> None:
    if output_json:
        print(json.dumps(payload, indent=2))
        return

    action = payload.get("action")
    status = payload.get("status")
    print(f"Capture to Markdown: {action} [{status}]")
    if payload.get("blockers"):
        print(f"  Blockers: {', '.join(payload['blockers'])}")
    if action == "review":
        paths = payload.get("paths") or {}
        print(f"  Status:    {payload.get('old_status')} -> {payload.get('new_status')}")
        print(f"  Content:   {paths.get('content_path')}")
        print(f"  Sidecar:   {paths.get('sidecar_path')}")
        print(f"  Packet:    {paths.get('visual_capture_packet_path') or '(missing)'}")
        print("  Boundary: review-state sidecar/packet only; no promotion.")
    elif payload.get("write_performed"):
        print(f"  Content: {payload.get('content_path')}")
        print(f"  Sidecar: {payload.get('sidecar_path')}")
        print(f"  Packet:  {payload.get('visual_capture_packet_path')}")
        print("  Boundary: raw quarantine only; review before promotion.")
    elif action == "preview":
        print(f"  Save allowed: {payload.get('save_allowed')}")
        print("  Preview made no writes.")
    elif action == "recent":
        captures = payload.get("recent_captures") or []
        print(f"  Recent captures: {len(captures)}")
        for row in captures:
            print(f"  - {row.get('title')} -> {row.get('content_path')}")


def _capture_markdown_error(args: argparse.Namespace, message: str, *, status: str = "error") -> int:
    payload = {
        "ok": False,
        "surface": "capture-to-markdown-cli",
        "action": getattr(args, "markdown_mode", "unknown"),
        "status": status,
        "write_performed": False,
        "blockers": [status],
        "errors": [message],
        "authority": dict(_CAPTURE_MARKDOWN_CLI_AUTHORITY),
    }
    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
    else:
        print(f"ERROR: {message}", file=sys.stderr)
    return 1


def cmd_capture_markdown_preview(args: argparse.Namespace) -> int:
    """chaseos capture markdown preview -- no-write Capture to Markdown preview."""

    try:
        packet = _capture_markdown_packet(args)
        result = preview_visual_capture(
            vault_root=getattr(args, "vault_root", None),
            packet=packet,
        )
    except (FileNotFoundError, ValueError, VisualCaptureValidationError) as exc:
        return _capture_markdown_error(args, str(exc), status="preview_failed")

    payload = dict(result) | {
        "cli_surface": "capture-to-markdown-cli",
        "action": "preview",
        "authority_boundary": dict(_CAPTURE_MARKDOWN_CLI_AUTHORITY),
    }
    _print_capture_markdown_payload(payload, getattr(args, "output_json", False))
    return 0


def cmd_capture_markdown_save(args: argparse.Namespace) -> int:
    """chaseos capture markdown save -- write Capture to Markdown artifact to raw quarantine."""

    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        packet = _capture_markdown_packet(args)
        result = save_visual_capture(vault_root=vault_root, packet=packet)
    except (FileNotFoundError, ValueError, VisualCaptureValidationError) as exc:
        return _capture_markdown_error(args, str(exc), status="save_failed")
    except Exception as exc:
        return _capture_markdown_error(args, f"Error writing visual capture intake: {exc}", status="save_failed")

    payload = dict(result) | {
        "cli_surface": "capture-to-markdown-cli",
        "action": "save",
        "authority_boundary": dict(_CAPTURE_MARKDOWN_CLI_AUTHORITY),
    }
    if not payload.get("ok", False):
        payload.setdefault("errors", list(payload.get("blockers") or ["capture_markdown_save_failed"]))
        _print_capture_markdown_payload(payload, getattr(args, "output_json", False))
        return 1

    _print_capture_markdown_payload(payload, getattr(args, "output_json", False))
    return 0


