# ── Command: capture rss ──────────────────────────────────────────────────────

def cmd_capture_rss(args: argparse.Namespace) -> int:
    """
    chaseos capture rss FEED_URL [options]

    Fetch an RSS or Atom feed, parse each item into a ContentPacket, and write
    all items to the standard quarantine pipeline.

    Default behavior:
        - input_class: "source" (items are external source articles)
        - source_platform: derived from feed hostname (e.g. "feeds-reuters-com")
        - event_date_hint: per-item pubDate/published parsed to YYYY-MM-DD
          (override with --event-date to apply the same date to all items)

    Quarantine doctrine:
        All items land in 03_INPUTS/00_QUARANTINE/[class]/ (default: Sources/).
        Source Intelligence Core is NOT triggered. Promotion requires explicit Gate review.

    Supported feed formats:
        RSS 2.0 and Atom 1.0 (stdlib XML parser, no external dependencies).
    """
    vault_root = _resolve_vault(getattr(args, "vault_root", None))

    input_class = getattr(args, "input_class", None) or INPUT_CLASS_SOURCE
    source_platform_override = getattr(args, "source_platform", None) or None

    try:
        feed_title, feed_type, packets, skipped = fetch_and_parse_feed(
            args.feed_url,
            limit=args.limit,
            input_class=input_class,
            source_platform_override=source_platform_override,
            domain_hint=getattr(args, "domain_hint", None),
            project_hint=getattr(args, "project_hint", None),
            topic_hint=getattr(args, "topic_hint", None),
            event_date_hint_override=getattr(args, "event_date_hint", None),
            origin_kind=getattr(args, "origin_kind", None),
            desired_output_kind=getattr(args, "desired_output_kind", None),
            workspace_hint=getattr(args, "workspace_hint", None),
        )
    except FeedFetchError as exc:
        print(f"ERROR fetching feed: {exc}", file=sys.stderr)
        return 1
    except FeedParseError as exc:
        print(f"ERROR parsing feed: {exc}", file=sys.stderr)
        return 1

    captured_results: list[dict] = []
    duplicate_results: list[dict] = []
    write_errors: list[dict] = []

    for packet in packets:
        try:
            result = capture_content(packet, vault_root=vault_root)
            if result.get("is_duplicate"):
                duplicate_results.append({
                    "title":          packet.title,
                    "content_sha256": result["content_sha256"],
                    "duplicate_of":   result.get("duplicate_of"),
                })
            else:
                captured_results.append({
                    "title":        packet.title,
                    "filename":     result["filename"],
                    "capture_id":   result["capture_id"],
                    "source_url":   packet.source_url,
                    "content_path": result["content_path"],
                    "sidecar_path": result["sidecar_path"],
                })
        except Exception as exc:
            write_errors.append({"title": packet.title, "error": str(exc)})

    if args.output_json:
        print(json.dumps({
            "feed_url":        args.feed_url,
            "feed_title":      feed_title,
            "feed_type":       feed_type,
            "captured":        captured_results,
            "duplicates":      duplicate_results,
            "skipped":         skipped,
            "errors":          write_errors,
            "captured_count":  len(captured_results),
            "duplicate_count": len(duplicate_results),
            "skipped_count":   len(skipped),
            "error_count":     len(write_errors),
        }, indent=2))
        return 0 if not write_errors else 1

    # Human-readable output
    feed_label = f'"{feed_title}"' if feed_title else args.feed_url
    print(f"Feed: {feed_label} [{feed_type}]")

    if captured_results:
        quarantine_path = str(
            vault_root / "03_INPUTS" / QUARANTINE_SUBDIR / INPUT_CLASS_TO_SUBFOLDER.get(input_class, input_class)
        )
        print(f"Captured  {len(captured_results)} item{'s' if len(captured_results) != 1 else ''}"
              f" -> {quarantine_path}")
        for i, r in enumerate(captured_results, 1):
            print(f"  [{i}] {r['title']}")
            print(f"       -> {r['filename']}")
    else:
        print("  No new items captured.")

    if duplicate_results:
        print()
        print(f"Duplicates {len(duplicate_results)} item{'s' if len(duplicate_results) != 1 else ''}"
              f" (already in registry — not re-captured)")
        for d in duplicate_results:
            print(f"  [dup] {d['title']}")

    if skipped:
        print()
        print(f"  Skipped: {len(skipped)}")
        for s in skipped:
            print(f"    - {s['title']}: {s['reason']}")

    if write_errors:
        print()
        print(f"  Write errors: {len(write_errors)}")
        for e in write_errors:
            print(f"    - {e['title']}: {e['error']}", file=sys.stderr)

    print()
    print("  Next steps: review in quarantine, then promote via Gate.")
    print("  Source Intelligence Core ingestion happens after Gate promotion - not now.")

    return 0 if not write_errors else 1


# ── Command: capture browser file ─────────────────────────────────────────────

def cmd_capture_browser_file(args: argparse.Namespace) -> int:
    """
    chaseos capture browser file PATH [options]

    Load a local saved HTML file, extract title and body content, convert to
    markdown-like normalized text, and write to the standard quarantine pipeline.

    This connector is for:
        - Browser "save page" exports (.html files)
        - Saved web article pages
        - Any static HTML content file

    Default behavior:
        - input_class: "source" (browser pages are external source articles)
        - source_platform: "web" (override with --source for specific publications)
        - title: auto-extracted from HTML <title> or <h1> if --title not provided

    Title resolution precedence:
        1. --title argument (explicit operator override)
        2. HTML <title> element
        3. First <h1> in the document body
        4. Filename stem (fallback)

    HTML extraction strategy (stdlib only, no external deps):
        Headings, paragraphs, lists, links, emphasis preserved as markdown.
        Script, style, nav, footer, aside elements discarded.
        Static HTML only — JS-rendered content not captured.

    Quarantine doctrine:
        All captures land in 03_INPUTS/00_QUARANTINE/[class]/ (default: Sources/).
        Source Intelligence Core is NOT triggered. Promotion requires explicit Gate review.
    """
    vault_root = _resolve_vault(getattr(args, "vault_root", None))

    input_class = getattr(args, "input_class", None) or INPUT_CLASS_SOURCE
    source_platform = getattr(args, "source_platform", None) or "web"

    try:
        packet = capture_from_browser(
            file_path=args.path,
            title=getattr(args, "title", None),
            source_url=getattr(args, "source_url", None),
            author=getattr(args, "author", None),
            input_class=input_class,
            source_platform=source_platform,
            workspace_hint=getattr(args, "workspace_hint", None),
            domain_hint=getattr(args, "domain_hint", None),
            project_hint=getattr(args, "project_hint", None),
            topic_hint=getattr(args, "topic_hint", None),
            event_date_hint=getattr(args, "event_date_hint", None),
            origin_kind=getattr(args, "origin_kind", None),
            desired_output_kind=getattr(args, "desired_output_kind", None),
        )
    except FileNotFoundError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    except Exception as exc:
        print(f"ERROR parsing HTML file: {exc}", file=sys.stderr)
        return 1

    try:
        result = capture_content(packet, vault_root=vault_root)
    except Exception as exc:
        print(f"ERROR writing intake: {exc}", file=sys.stderr)
        return 1

    if not args.output_json:
        # Show title source if auto-detected (useful operator feedback)
        title_source = (packet.extra_metadata or {}).get("title_source", "")
        if title_source and title_source != "cli":
            print(f"Title: {packet.title!r} (from {title_source})")

    _print_capture_result(result, args.output_json)
    return 0


# ── Command: capture perplexity ───────────────────────────────────────────────

def cmd_capture_perplexity(args: argparse.Namespace) -> int:
    """
    chaseos capture perplexity --query "..." [options]

    Query the Perplexity API with an operator-supplied research question and
    capture the returned answer into the standard quarantine pipeline.

    Credentials:
        Requires the PERPLEXITY_API_KEY environment variable to be set.
        The key is never written to any vault file, sidecar, or log.
        If missing, the command fails immediately with an actionable error.

    Default behavior:
        - input_class: "digest" (Perplexity answers are research synthesis artifacts)
        - source_platform: "perplexity"
        - origin_kind: "ai-generated"
        - model: "sonar" (Perplexity web-search-augmented model)
        - title: derived from query text (truncated to 80 chars at word boundary)

    Citations:
        If the Perplexity response includes citation URLs, they are stored in
        extra_metadata.citations (list) and extra_metadata.citation_count (int).
        Citation content is NOT fetched — URLs only.

    Quarantine doctrine:
        All captures land in 03_INPUTS/00_QUARANTINE/Digests/ (default class).
        Source Intelligence Core is NOT triggered. Promotion requires explicit Gate review.
        Operator reviews the captured answer before any knowledge promotion.

    Dedup:
        Same returned content captured twice → second capture is a duplicate.
        SHA-256 dedup registry (Pass 6) applies transparently.

    Honest limitations:
        - One-shot query only (no multi-turn conversation)
        - No automatic polling or scheduled queries
        - No citation content fetching (URLs stored, content not fetched)
        - No Grok or other API connector (future pass)
        - No watched-folder automation
        - No auto-promotion or Source Intelligence Core trigger
    """
    vault_root      = _resolve_vault(getattr(args, "vault_root", None))
    input_class     = getattr(args, "input_class",    None) or INPUT_CLASS_DIGEST
    source_platform = getattr(args, "source_platform", None) or "perplexity"
    model           = getattr(args, "model",           "sonar")

    try:
        packet = capture_from_perplexity(
            query=args.query,
            model=model,
            title=getattr(args, "title", None),
            input_class=input_class,
            source_platform=source_platform,
            workspace_hint=getattr(args, "workspace_hint", None),
            domain_hint=getattr(args, "domain_hint", None),
            project_hint=getattr(args, "project_hint", None),
            topic_hint=getattr(args, "topic_hint", None),
            event_date_hint=getattr(args, "event_date_hint", None),
            origin_kind=getattr(args, "origin_kind", None),
            desired_output_kind=getattr(args, "desired_output_kind", None),
        )
    except PerplexityCredentialError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    except PerplexityAPIError as exc:
        print(f"ERROR: Perplexity API error: {exc}", file=sys.stderr)
        return 1
    except ValueError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    try:
        result = capture_content(packet, vault_root=vault_root)
    except Exception as exc:
        print(f"ERROR writing intake: {exc}", file=sys.stderr)
        return 1

    if not args.output_json:
        # Show query and citation feedback for the operator
        q_display = args.query if len(args.query) <= 80 else args.query[:80] + "..."
        print(f"Query:  {q_display}")
        citation_count = (packet.extra_metadata or {}).get("citation_count", 0)
        if citation_count:
            print(f"Citations: {citation_count} URL(s) stored in sidecar extra_metadata")

    _print_capture_result(result, args.output_json)
    return 0


