# ── Command: capture status ───────────────────────────────────────────────────

def cmd_capture_status(args: argparse.Namespace) -> int:
    """chaseos capture status -- read-only capture/intake boundary summary."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    inputs_dir = vault_root / "03_INPUTS"
    quarantine_dir = inputs_dir / QUARANTINE_SUBDIR
    class_counts = []
    total_quarantine = 0
    for input_class, subfolder in sorted(INPUT_CLASS_TO_SUBFOLDER.items()):
        q_dir = quarantine_dir / subfolder
        count = 0
        if q_dir.exists():
            count = len([
                path for path in q_dir.iterdir()
                if path.suffix == ".md" and not path.name.endswith("-Index.md")
            ])
        total_quarantine += count
        class_counts.append({
            "input_class": input_class,
            "subfolder": subfolder,
            "quarantine_count": count,
        })

    reg_path = registry_path(vault_root)
    registry = load_registry(vault_root)
    payload = {
        "status": "ok",
        "read_only": True,
        "mutates_capture": False,
        "mutates_intake": False,
        "vault_root": str(vault_root),
        "inputs_dir": str(inputs_dir),
        "quarantine_dir": str(quarantine_dir),
        "quarantine_exists": quarantine_dir.exists(),
        "total_quarantine": total_quarantine,
        "classes": class_counts,
        "dedup_registry": {
            "path": str(reg_path),
            "exists": reg_path.exists(),
            "entry_count": len(registry.get("entries", {})),
            "schema_version": registry.get("schema_version", "unknown"),
        },
        "connectors": {
            "file": {"safe_status_only": True, "external_call": False},
            "stdin": {"safe_status_only": True, "external_call": False},
            "browser_file": {"safe_status_only": True, "external_call": False},
            "markdown_preview": {"safe_status_only": True, "external_call": False, "write_call": False},
            "markdown_save": {"safe_status_only": True, "external_call": False, "write_call": True},
            "markdown_recent": {"safe_status_only": True, "external_call": False, "write_call": False},
            "rss": {"safe_status_only": True, "external_call": True},
            "perplexity": {"safe_status_only": True, "external_call": True},
            "grok": {"safe_status_only": True, "external_call": True},
        },
        "writes_performed": False,
        "authority_flags": {
            "read_only": True,
            "capture_allowed": False,
            "connector_calls_allowed": False,
            "promotion_allowed": False,
            "canonical_writeback_allowed": False,
        },
    }

    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
    else:
        print("ChaseOS Capture Status")
        print(f"  Vault:       {vault_root}")
        print(f"  Quarantine:  {total_quarantine} file{'s' if total_quarantine != 1 else ''}")
        print(f"  Registry:    {payload['dedup_registry']['entry_count']} entr{'ies' if payload['dedup_registry']['entry_count'] != 1 else 'y'}")
        print("  Mode:        read-only status; no capture or connector calls")
    return 0


def cmd_capture_validate(args: argparse.Namespace) -> int:
    """chaseos capture validate -- read-only capture fixture/no-write validation."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    inputs_dir = vault_root / "03_INPUTS"
    quarantine_dir = inputs_dir / QUARANTINE_SUBDIR
    reg_path = registry_path(vault_root)
    registry = load_registry(vault_root)

    local_modes = ("file", "stdin", "browser file", "markdown preview", "markdown recent")
    local_mutating_modes = ("markdown save",)
    external_modes = ("rss", "perplexity", "grok")
    payload = {
        "status": "valid",
        "valid": True,
        "read_only": True,
        "safe_validate_only": True,
        "fixture_root": str(vault_root),
        "inputs_dir": str(inputs_dir),
        "quarantine_dir": str(quarantine_dir),
        "quarantine_exists": quarantine_dir.exists(),
        "dedup_registry": {
            "path": str(reg_path),
            "exists": reg_path.exists(),
            "entry_count": len(registry.get("entries", {})),
            "schema_version": registry.get("schema_version", "unknown"),
        },
        "validated_modes": [
            {"mode": mode, "external_call": False, "capture_write": False}
            for mode in local_modes
        ]
        + [
            {"mode": mode, "external_call": False, "capture_write": False, "blocked": True}
            for mode in local_mutating_modes
        ]
        + [
            {"mode": mode, "external_call": False, "capture_write": False, "blocked": True}
            for mode in external_modes
        ],
        "forbidden_actions": [
            "quarantine_write",
            "dedup_registry_write",
            "connector_call",
            "external_fetch",
            "promotion",
            "canonical_writeback",
        ],
        "writes_performed": False,
        "authority_flags": {
            "read_only": True,
            "capture_allowed": False,
            "connector_calls_allowed": False,
            "external_fetch_allowed": False,
            "quarantine_write_allowed": False,
            "dedup_registry_write_allowed": False,
            "promotion_allowed": False,
            "canonical_writeback_allowed": False,
        },
    }

    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
    else:
        print("ChaseOS Capture Validate")
        print(f"  Vault:       {vault_root}")
        print("  Mode:        read-only validate; no capture, connector, or write calls")
        print("  Valid:       yes")
    return 0


# ── Command: intake ls ─────────────────────────────────────────────────────────

def cmd_intake_ls(args: argparse.Namespace) -> int:
    """chaseos intake ls [--class CLASS] [--vault-root PATH]"""
    try:
        vault_root = _resolve_vault(args.vault_root)
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    inputs_dir = vault_root / "03_INPUTS"
    quarantine_dir = inputs_dir / QUARANTINE_SUBDIR

    # Filter by class if requested
    class_filter = getattr(args, "input_class", None)

    class_rows: list[dict[str, object]] = []
    total_quarantine = 0
    total_legacy = 0
    for input_class, subfolder in sorted(INPUT_CLASS_TO_SUBFOLDER.items()):
        if class_filter and input_class != class_filter:
            continue
        q_dir = quarantine_dir / subfolder
        q_files = []
        if q_dir.exists():
            q_files = [
                f for f in q_dir.iterdir()
                if f.suffix == ".md" and not f.name.endswith("-Index.md")
            ]
        legacy_dir = inputs_dir / subfolder
        legacy_files = []
        if legacy_dir.exists():
            legacy_files = [
                f for f in legacy_dir.iterdir()
                if f.suffix == ".md" and not f.name.endswith("-Index.md")
            ]
        total_quarantine += len(q_files)
        total_legacy += len(legacy_files)
        class_rows.append({
            "input_class": input_class,
            "subfolder": subfolder,
            "quarantine_count": len(q_files),
            "legacy_count": len(legacy_files),
        })

    if getattr(args, "output_json", False):
        print(json.dumps({
            "status": "ok",
            "read_only": True,
            "mutates_intake": False,
            "vault_root": str(vault_root),
            "inputs_dir": str(inputs_dir),
            "quarantine_dir": str(quarantine_dir),
            "class_filter": class_filter,
            "classes": class_rows,
            "total_quarantine": total_quarantine,
            "total_legacy": total_legacy,
            "writes_performed": False,
            "authority_flags": {
                "read_only": True,
                "capture_allowed": False,
                "promotion_allowed": False,
                "canonical_writeback_allowed": False,
            },
        }, indent=2))
        return 0

    print(f"ChaseOS Intake -- {inputs_dir.relative_to(vault_root)}/")
    print()

    # Show quarantine contents
    print(f"  Quarantine ({QUARANTINE_SUBDIR}/):")
    for row in class_rows:
        count = int(row["quarantine_count"])
        label = f"{str(row['input_class']):<14} ({row['subfolder']}/)"
        print(f"    {label:<40} {count:>3} file{'s' if count != 1 else ''}")

    print()
    print(f"    Total in quarantine: {total_quarantine} file{'s' if total_quarantine != 1 else ''}")
    print()

    # Show legacy (flat 03_INPUTS/) contents if any
    legacy_found = False
    legacy_lines = []
    for row in class_rows:
        legacy_count = int(row["legacy_count"])
        if legacy_count:
            legacy_found = True
            legacy_lines.append(
                f"    {row['subfolder']}/: {legacy_count} legacy file{'s' if legacy_count != 1 else ''}"
            )

    if legacy_found:
        print("  Legacy (pre-quarantine, flat 03_INPUTS/[class]/):")
        for line in legacy_lines:
            print(line)
        print()
        print("  Legacy files are safe. Migrate to 00_QUARANTINE/ manually when ready.")
        print()

    return 0


# ── Command: intake inspect ────────────────────────────────────────────────────

def cmd_intake_inspect(args: argparse.Namespace) -> int:
    """
    chaseos intake inspect PATH

    Inspect the sidecar metadata for a quarantined file.

    PATH may be:
      - The .md content file (sidecar is derived by replacing suffix with .meta.json)
      - The .meta.json sidecar file directly

    Outputs a formatted, human-readable view of the sidecar.
    Use --json to get raw JSON output.
    """
    path = Path(args.path)

    # Resolve to the sidecar file
    # Note: .meta.json is a compound suffix — Path.suffix returns ".json" only.
    # We check the full filename string to detect both cases.
    name = path.name
    if name.endswith(".meta.json"):
        sidecar_path = path
    elif name.endswith(".md"):
        sidecar_path = path.with_name(name[:-3] + ".meta.json")
    else:
        # Try treating PATH as stem and append .meta.json
        sidecar_path = path.parent / (name + ".meta.json")

    if not sidecar_path.exists():
        print(f"ERROR: sidecar not found: {sidecar_path}", file=sys.stderr)
        print(
            "  Tip: provide either the .md content file or the .meta.json sidecar directly.",
            file=sys.stderr,
        )
        return 1

    try:
        sidecar = json.loads(sidecar_path.read_text(encoding="utf-8"))
    except Exception as exc:
        print(f"ERROR reading sidecar: {exc}", file=sys.stderr)
        return 1

    if args.output_json:
        print(json.dumps(sidecar, indent=2, ensure_ascii=False))
        return 0

    # Human-readable output
    def _row(label: str, value) -> None:
        if value is not None:
            print(f"  {label:<26} {value}")
        else:
            print(f"  {label:<26} (not set)")

    print(f"Sidecar: {sidecar_path.name}")
    print()
    print("  -- Core --")
    _row("schema_version",      sidecar.get("schema_version"))
    _row("capture_id",          sidecar.get("capture_id"))
    _row("content_filename",    sidecar.get("content_filename"))
    _row("captured_at",         sidecar.get("captured_at"))
    _row("capture_method",      sidecar.get("capture_method"))
    print()
    print("  -- Classification --")
    _row("input_class",         sidecar.get("input_class"))
    _row("source_platform",     sidecar.get("source_platform"))
    _row("title",               sidecar.get("title"))
    _row("knowledge_class",     sidecar.get("knowledge_class"))
    print()
    print("  -- Provenance --")
    _row("source_url",          sidecar.get("source_url"))
    _row("author",              sidecar.get("author"))
    _row("original_name",       sidecar.get("original_name"))
    _row("original_path_or_uri",sidecar.get("original_path_or_uri"))
    _row("detected_mime",       sidecar.get("detected_mime"))
    _row("content_sha256",      (sidecar.get("content_sha256") or "")[:32] + "...")
    print()
    print("  -- Semantic Breadcrumbs --")
    _row("domain_hint",         sidecar.get("domain_hint"))
    _row("project_hint",        sidecar.get("project_hint"))
    _row("topic_hint",          sidecar.get("topic_hint"))
    _row("event_date_hint",     sidecar.get("event_date_hint"))
    _row("origin_kind",         sidecar.get("origin_kind"))
    _row("desired_output_kind", sidecar.get("desired_output_kind"))
    _row("workspace_hint",      sidecar.get("workspace_hint"))
    print()
    print("  -- Status --")
    _row("quarantine_status",   sidecar.get("quarantine_status"))
    _row("promotion_status",    sidecar.get("promotion_status"))
    _row("source_package_status", sidecar.get("source_package_status"))
    _row("injection_scan",      sidecar.get("injection_scan"))
    print()
    print("  -- Routing --")
    _row("route_reason",        sidecar.get("route_reason"))

    extra = sidecar.get("extra_metadata")
    if extra:
        print()
        print("  -- Extra Metadata --")
        for k, v in extra.items():
            _row(k, v)

    print()
    print("  Source Intelligence Core ingestion has NOT occurred. Quarantine -> review -> Gate promotion -> Source Intelligence Core.")

    return 0


# ── Command: intake dedup-stats ───────────────────────────────────────────────

def cmd_intake_dedup_stats(args: argparse.Namespace) -> int:
    """
    chaseos intake dedup-stats [--vault-root PATH]

    Show dedup registry statistics.

    Outputs:
        - Registry file path
        - Schema version
        - Entry count
        - Breakdown by input_class (how many per class)

    The registry lives at <vault_root>/.chaseos/dedup_registry.json.
    It is human-readable JSON — inspect it directly if needed.
    """
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    reg_path = registry_path(vault_root)
    registry = load_registry(vault_root)
    entries = registry.get("entries", {})
    schema_version = registry.get("schema_version", "unknown")

    if args.output_json:
        # Count by class
        by_class: dict[str, int] = {}
        for entry in entries.values():
            cls = entry.get("input_class", "unknown")
            by_class[cls] = by_class.get(cls, 0) + 1
        print(json.dumps({
            "registry_path":  str(reg_path),
            "schema_version": schema_version,
            "entry_count":    len(entries),
            "by_class":       by_class,
            "registry_exists": reg_path.exists(),
        }, indent=2))
        return 0

    print("ChaseOS Dedup Registry")
    print()
    print(f"  Registry:       {reg_path}")
    print(f"  Exists:         {'yes' if reg_path.exists() else 'no (empty registry)'}")
    print(f"  Schema version: {schema_version}")
    print(f"  Total entries:  {len(entries)}")

    if entries:
        print()
        print("  By class:")
        by_class: dict[str, int] = {}
        for entry in entries.values():
            cls = entry.get("input_class", "unknown")
            by_class[cls] = by_class.get(cls, 0) + 1
        for cls, count in sorted(by_class.items()):
            print(f"    {cls:<18} {count:>4} item{'s' if count != 1 else ''}")
    else:
        print()
        print("  Registry is empty — no items captured yet.")

    print()
    print("  Tip: view registry directly at .chaseos/dedup_registry.json")
    return 0


# ── Command: context ──────────────────────────────────────────────────────────

def cmd_context_boot(args: argparse.Namespace) -> int:
    """chaseos context boot -- load and display the ChaseOS pre-execution context bundle"""
    from runtime.context.boot import load_boot_context  # local import to avoid cold-start cost
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    runtime_id = getattr(args, "runtime_id", None) or "openclaw"

    try:
        bundle = load_boot_context(vault_root=vault_root, runtime_id=runtime_id)
    except Exception as exc:
        print(f"ERROR: context boot failed: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        data = bundle.to_dict()
        data["frame"] = bundle.to_frame()
        print(json.dumps(data, indent=2))
    else:
        print(bundle.to_frame())
        if bundle.boot_warnings:
            print()
            for w in bundle.boot_warnings:
                print(f"  WARN: {w}", file=sys.stderr)

    return 0 if bundle.boot_status != "failed" else 1


# ── Command: doctor ────────────────────────────────────────────────────────────

def cmd_run(args: argparse.Namespace) -> int:
    """chaseos run WORKFLOW_ID -- execute a registered Agent Orchestration Runtime workflow"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    try:
        manifest = load_manifest(args.workflow_id, vault_root=vault_root)
    except ValueError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if manifest is None:
        print(
            f"ERROR: workflow '{args.workflow_id}' not found in runtime/workflows/registry/",
            file=sys.stderr,
        )
        return 1

    allowed, reason = _run_coordination_preflight(
        args.workflow_id,
        manifest=manifest,
        adapter_id=getattr(args, "adapter", None),
        coordination_via=getattr(args, "coordination_via", None),
    )
    if not allowed:
        print(f"ERROR: {reason}", file=sys.stderr)
        return 1

    inputs: dict[str, object] = {}
    if getattr(args, "date", None):
        inputs["date"] = args.date
    if getattr(args, "output_format", None):
        inputs["output_format"] = args.output_format
    for raw_input in getattr(args, "inputs", []) or []:
        if "=" not in raw_input:
            print(
                f"ERROR: invalid --input value {raw_input!r}; expected KEY=VALUE",
                file=sys.stderr,
            )
            return 1
        key, value = raw_input.split("=", 1)
        key = key.strip()
        if not key:
            print(f"ERROR: invalid --input value {raw_input!r}; empty key", file=sys.stderr)
            return 1
        inputs[key] = value

    result = run_workflow(
        args.workflow_id,
        inputs=inputs,
        vault_root=vault_root,
        dry_run=getattr(args, "dry_run", False),
    )
    if result.status == "success" and not getattr(args, "dry_run", False):
        try:
            allowed, reason = check_runtime_operation(
                "events.emit",
                write_targets=[
                    "runtime/events/queue/",
                    "runtime/events/event_log.jsonl",
                ],
            )
            if allowed:
                emitted_events = emit_post_workflow_events(
                    args.workflow_id,
                    result,
                    vault_root=vault_root,
                )
                if emitted_events:
                    result.outputs.setdefault("events", {})["emitted"] = emitted_events
            else:
                result.outputs.setdefault("events", {})["warning"] = reason
        except Exception as exc:  # noqa: BLE001
            result.outputs.setdefault("events", {})["warning"] = str(exc)

    dry_run = bool(getattr(args, "dry_run", False))
    files_written = result.outputs.get("writeback", {}).get("files_written", [])
    emitted_events = result.outputs.get("events", {}).get("emitted", [])
    writes_performed = bool(files_written or emitted_events)

    if getattr(args, "output_json", False):
        print(json.dumps({
            "workflow_id": result.workflow_id,
            "status": result.status,
            "dry_run": dry_run,
            "audit_id": result.audit_id,
            "stage_reached": result.stage_reached,
            "outputs": result.outputs,
            "escalation_reason": result.escalation_reason,
            "error": result.error,
            "writes_performed": writes_performed,
            "authority_flags": {
                "read_only": dry_run,
                "workflow_execution_allowed": not dry_run,
                "workflow_execution_performed": (not dry_run and result.status == "success"),
                "writeback_allowed": not dry_run,
                "agent_bus_write_allowed": False,
                "canonical_writeback_allowed": False,
            },
        }, indent=2))
    else:
        print(f"Workflow: {result.workflow_id}")
        print(f"Status:   {result.status}")
        print(f"Audit ID: {result.audit_id}")
        if result.stage_reached:
            print(f"Stage:    {result.stage_reached}")
        if result.status in {"failed", "escalated"}:
            reason = result.error or result.escalation_reason or "unknown error"
            print(f"Reason:   {reason}")
        if result.status == "waiting_approval":
            approval_gate = result.outputs.get("approval_gate", {})
            approval_id = approval_gate.get("approval_id")
            if approval_id:
                print(f"Approval: {approval_id}")
            response_hint = approval_gate.get("response_command_hint")
            if response_hint:
                print(f"Respond:  {response_hint}")
            resume_hint = approval_gate.get("resume_command_hint")
            if resume_hint:
                print(f"Resume:   {resume_hint}")
        files_written = result.outputs.get("writeback", {}).get("files_written", [])
        if files_written:
            print("Writes:")
            for path in files_written:
                print(f"  - {path}")
        emitted_events = result.outputs.get("events", {}).get("emitted", [])
        if emitted_events:
            print("Events:")
            for event in emitted_events:
                print(f"  - {event.get('event_type')} {event.get('event_id')}")
        event_warning = result.outputs.get("events", {}).get("warning")
        if event_warning:
            print(f"Event warning: {event_warning}")

    return 0 if result.status in {"success", "dry_run_ok"} else 1


def cmd_develop_explain(args: argparse.Namespace) -> int:
    """chaseos develop explain -- friendly alias for developer_repo_explain_shadow."""
    workflow_inputs: list[str] = []
    if getattr(args, "focus_area", None):
        workflow_inputs.append(f"focus_area={args.focus_area}")
    if getattr(args, "question", None):
        workflow_inputs.append(f"question={args.question}")
    if getattr(args, "target_paths", None):
        workflow_inputs.append(f"target_paths={','.join(args.target_paths)}")
    if getattr(args, "project_scope", None):
        workflow_inputs.append(f"project_scope={args.project_scope}")

    if getattr(args, "dry_run", False):
        payload = {
            "workflow_id": "developer_repo_explain_shadow",
            "status": "dry_run_ok",
            "dry_run": True,
            "audit_id": None,
            "stage_reached": "alias_preflight",
            "outputs": {
                "dry_run": {
                    "workflow_id": "developer_repo_explain_shadow",
                    "inputs": workflow_inputs,
                    "workflow_execution_performed": False,
                    "writes_performed": False,
                    "deprecated_workflow_execution_blocked": True,
                }
            },
            "escalation_reason": None,
            "error": None,
            "writes_performed": False,
            "authority_flags": {
                "read_only": True,
                "workflow_execution_allowed": False,
                "workflow_execution_performed": False,
                "writeback_allowed": False,
                "agent_bus_write_allowed": False,
                "canonical_writeback_allowed": False,
            },
        }
        if getattr(args, "output_json", False):
            print(json.dumps(payload, indent=2))
        else:
            print("Develop explain dry run: developer_repo_explain_shadow")
        return 0

    args.workflow_id = "developer_repo_explain_shadow"
    args.date = None
    args.output_format = None
    args.inputs = workflow_inputs
    args.coordination_via = None
    return cmd_run(args)
