# ── Command: schedule list ────────────────────────────────────────────────────

def _parse_key_value_items(raw_items: list[str] | None) -> dict[str, str]:
    values: dict[str, str] = {}
    for raw in raw_items or []:
        if "=" not in raw:
            raise ValueError(f"invalid KEY=VALUE item: {raw!r}")
        key, value = raw.split("=", 1)
        key = key.strip()
        if not key:
            raise ValueError(f"invalid KEY=VALUE item with empty key: {raw!r}")
        values[key] = value
    return values


def cmd_events_validate(args: argparse.Namespace) -> int:
    """chaseos events validate -- validate event rules and queued events"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        errors = validate_event_substrate(vault_root)
    except (RuntimeError, DispatchError, ValueError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps({
            "valid": not errors,
            "error_count": len(errors),
            "errors": errors,
        }, indent=2))
        return 0 if not errors else 1

    if not errors:
        print("Event validation: OK")
        return 0

    print(f"Event validation: {len(errors)} error(s) found")
    for error in errors:
        print(f"  - {error['kind']}: {error['path']}")
        print(f"    {error['error']}")
    return 1


def cmd_events_rules(args: argparse.Namespace) -> int:
    """chaseos events rules -- list event dispatch rules"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        rules = load_rules(vault_root, enabled_only=getattr(args, "enabled_only", False))
    except (RuntimeError, DispatchError, ValueError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    payload = {
        "count": len(rules),
        "rules": [
            {
                "rule_id": rule.rule_id,
                "event_type": rule.event_type,
                "enabled": rule.enabled,
                "target_workflow_id": rule.target_workflow_id,
                "runtime_adapter": rule.runtime_adapter,
                "path": str(rule.source_path) if rule.source_path else None,
            }
            for rule in rules
        ],
    }
    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
        return 0

    print(f"ChaseOS Event Rules ({payload['count']})")
    for rule in payload["rules"]:
        status = "ENABLED" if rule["enabled"] else "disabled"
        print(f"  [{status}] {rule['rule_id']}")
        print(f"    event:    {rule['event_type']}")
        print(f"    workflow: {rule['target_workflow_id']}")
        print(f"    adapter:  {rule['runtime_adapter']}")
    return 0


def cmd_events_pending(args: argparse.Namespace) -> int:
    """chaseos events pending -- list pending event envelopes"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        events = list_pending_events(vault_root)
    except (RuntimeError, DispatchError, ValueError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    payload = {"count": len(events), "events": [event.to_dict() for event in events]}
    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
        return 0

    print(f"ChaseOS Pending Events ({payload['count']})")
    for event in events:
        print(f"  {event.event_id}")
        print(f"    type:    {event.event_type}")
        print(f"    source:  {event.source_workflow_id or event.source.get('kind')}")
        print(f"    subject: {event.subject_ref}")
    return 0


def cmd_events_emit(args: argparse.Namespace) -> int:
    """chaseos events emit EVENT_TYPE -- emit a vault-local runtime event"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        payload = _parse_key_value_items(getattr(args, "data", None))
    except (RuntimeError, ValueError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if not getattr(args, "dry_run", False):
        blocked = _check_runtime_operation_or_block(
            args,
            "events.emit",
            write_targets=[
                "runtime/events/queue/",
                "runtime/events/event_log.jsonl",
            ],
        )
        if blocked is not None:
            return blocked

    try:
        event = emit_event(
            args.event_type,
            vault_root=vault_root,
            source_kind=getattr(args, "source_kind", "workflow"),
            source_workflow_id=getattr(args, "source_workflow", "") or "",
            subject_ref=args.subject,
            subject_kind=getattr(args, "subject_kind", "artifact"),
            payload=payload,
            audit_id=getattr(args, "audit_id", None),
            dry_run=getattr(args, "dry_run", False),
        )
    except (DispatchError, RuntimeError, ValueError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    out = {"dry_run": bool(getattr(args, "dry_run", False)), "event": event.to_dict()}
    if getattr(args, "output_json", False):
        print(json.dumps(out, indent=2))
        return 0

    prefix = "Would emit" if out["dry_run"] else "Emitted"
    print(f"{prefix}: {event.event_type} {event.event_id}")
    print(f"  Subject: {event.subject_ref}")
    return 0


def cmd_events_dispatch(args: argparse.Namespace) -> int:
    """chaseos events dispatch --pending -- dry-run or execute pending dispatch"""
    blocked = _check_runtime_operation_or_block(
        args,
        "events.dispatch",
        write_targets=[
            "runtime/events/dispatch_log.jsonl",
            "runtime/events/state.json",
        ],
    )
    if blocked is not None:
        return blocked

    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        result = dispatch_pending_events(
            vault_root=vault_root,
            execute=bool(getattr(args, "execute", False)),
            event_id=getattr(args, "event_id", None),
        )
    except (RuntimeError, DispatchError, ValueError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    failed = any(item.get("status") == "dispatch_failed" for item in result.get("results", []))
    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2))
        return 1 if failed else 0

    mode = "execute" if result["execute"] else "dry-run"
    print(f"Event dispatch ({mode}): {result['event_count']} event(s)")
    for item in result["results"]:
        print(f"  {item['event_id']} -> {item['status']}")
        for dispatch in item.get("dispatches", []):
            print(f"    rule:     {dispatch['rule_id']}")
            print(f"    workflow: {dispatch['target_workflow_id']}")
            print(f"    command:  {dispatch['command']}")
            if dispatch.get("status"):
                print(f"    status:   {dispatch['status']}")
    if not result["execute"]:
        print("  No workflows executed. Add --execute to run matching targets.")
    return 1 if failed else 0


def cmd_events_watch(args: argparse.Namespace) -> int:
    """chaseos events watch --once|--interval N -- run event dispatch loop"""
    blocked = _check_runtime_operation_or_block(
        args,
        "events.dispatch",
        write_targets=[
            "runtime/events/dispatch_log.jsonl",
            "runtime/events/state.json",
        ],
    )
    if blocked is not None:
        return blocked

    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        interval = getattr(args, "interval", None)
        max_cycles = getattr(args, "max_cycles", None)
        if getattr(args, "once", False):
            interval = None
            max_cycles = 1
        result = watch_pending_events(
            vault_root=vault_root,
            execute=bool(getattr(args, "execute", False)),
            interval_seconds=interval,
            max_cycles=max_cycles,
        )
    except (RuntimeError, DispatchError, ValueError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    failed = any(
        item.get("status") == "dispatch_failed"
        for cycle in result.get("cycles", [])
        for item in cycle.get("results", [])
    )
    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2))
        return 1 if failed else 0

    mode = "execute" if result["execute"] else "dry-run"
    print(f"Event watch ({result['mode']}, {mode}): {result['cycle_count']} cycle(s)")
    for cycle in result["cycles"]:
        print(f"  cycle {cycle['cycle']}: {cycle['event_count']} event(s)")
        for item in cycle.get("results", []):
            print(f"    {item['event_id']} -> {item['status']}")
            for dispatch in item.get("dispatches", []):
                print(f"      rule:     {dispatch['rule_id']}")
                print(f"      workflow: {dispatch['target_workflow_id']}")
                print(f"      status:   {dispatch['status']}")
    if not result["execute"]:
        print("  No workflows executed. Add --execute to run matching targets.")
    return 1 if failed else 0


