def cmd_osril_wait_resume(args: argparse.Namespace) -> int:
    """chaseos osril wait-resume -- inspect approval wait/resume state."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        approval_id = getattr(args, "approval_id", None)
        timeout_seconds = float(getattr(args, "timeout_seconds", 0) or 0)
        if approval_id:
            payload = wait_for_osril_resume_state(
                vault_root,
                approval_id=approval_id,
                runtime_id=getattr(args, "runtime_id", None),
                workflow_id=getattr(args, "workflow_id", None),
                session_id=getattr(args, "session_id", None),
                decision=getattr(args, "decision", None),
                wait_status=getattr(args, "wait_status", None),
                timeout_seconds=timeout_seconds,
                poll_interval_seconds=float(getattr(args, "poll_interval_seconds", 2) or 2),
            )
        else:
            payload = build_osril_wait_resume_state(
                vault_root,
                runtime_id=getattr(args, "runtime_id", None),
                workflow_id=getattr(args, "workflow_id", None),
                session_id=getattr(args, "session_id", None),
                decision=getattr(args, "decision", None),
                wait_status=getattr(args, "wait_status", None),
                limit=getattr(args, "limit", None),
            )
            payload["timed_out"] = False
    except (RuntimeError, ValueError) as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"error": str(exc)}, indent=2))
            return 1
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
        return 0

    print(
        "ChaseOS OSRIL Wait/Resume "
        f"({payload['count']} items, {payload['ready_count']} ready)"
    )
    for item in payload.get("items", []):
        print(f"  {item.get('approval_id')} -> {item.get('wait_status')}")
        print(f"    workflow: {item.get('workflow_id')}")
        print(f"    runtime:  {item.get('runtime_id')}")
        if item.get("next_action"):
            print(f"    next:     {item.get('next_action')}")
        if item.get("response_command_hint"):
            print(f"    respond:  {item.get('response_command_hint')}")
        if item.get("resume_command_hint"):
            print(f"    resume:   {item.get('resume_command_hint')}")
    if payload.get("timed_out"):
        print("  wait timed out before approval state changed")
    return 0


def cmd_osril_resume_ready(args: argparse.Namespace) -> int:
    """chaseos osril resume-ready -- resume approved-ready OSRIL approval gates."""
    approval_id = getattr(args, "approval_id", None)
    if not getattr(args, "dry_run", False):
        if approval_id:
            write_targets = [
                f"runtime/osril/approvals/{approval_id}.resume.json",
                "runtime/osril/run/",
            ]
        else:
            write_targets = ["runtime/osril/approvals/", "runtime/osril/run/"]
        blocked = _check_runtime_operation_or_block(
            args,
            "osril.approval_resume",
            write_targets=write_targets,
        )
        if blocked is not None:
            return blocked

    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        payload = resume_osril_ready_approvals(
            vault_root,
            approval_id=approval_id,
            runtime_id=getattr(args, "runtime_id", None),
            workflow_id=getattr(args, "workflow_id", None),
            session_id=getattr(args, "session_id", None),
            limit=getattr(args, "limit", None),
            dry_run=bool(getattr(args, "dry_run", False)),
        )
    except (RuntimeError, ValueError) as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"error": str(exc)}, indent=2))
            return 1
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
        return 1 if payload.get("failed_count") else 0

    print(
        "ChaseOS OSRIL Resume Ready "
        f"({payload['ready_count']} ready, {payload['resumed_count']} resumed, "
        f"{payload['failed_count']} failed)"
    )
    for item in payload.get("results", []):
        print(f"  {item.get('approval_id')} -> {item.get('status')}")
        print(f"    workflow: {item.get('workflow_id')}")
        print(f"    runtime:  {item.get('runtime_id')}")
        if item.get("resume_path"):
            print(f"    resume:   {item.get('resume_path')}")
        if item.get("command_hint"):
            print(f"    command:  {item.get('command_hint')}")
        if item.get("escalation_reason") or item.get("error"):
            print(f"    reason:   {item.get('escalation_reason') or item.get('error')}")
    for item in payload.get("skipped", []):
        print(f"  {item.get('approval_id')} -> skipped ({item.get('reason')})")
    return 1 if payload.get("failed_count") else 0


def cmd_osril_respond(args: argparse.Namespace) -> int:
    """chaseos osril respond APPROVAL_ID -- record and apply an approval response."""
    approval_id = str(getattr(args, "approval_id", "") or "").strip()
    write_target = f"runtime/osril/approvals/{approval_id}.response.json"
    application_target = f"runtime/osril/approvals/{approval_id}.application.json"
    blocked = _check_runtime_operation_or_block(
        args,
        "osril.approval_response",
        write_targets=[write_target, application_target, "runtime/osril/run/"],
    )
    if blocked is not None:
        return blocked

    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        payload = record_osril_approval_response(
            vault_root,
            approval_id=approval_id,
            decision=getattr(args, "decision", ""),
            operator_id=getattr(args, "operator_id", None) or "operator",
            operator_note=getattr(args, "operator_note", None),
            runtime_id=getattr(args, "runtime_id", None),
            workflow_id=getattr(args, "workflow_id", None),
            session_id=getattr(args, "session_id", None),
        )
    except (RuntimeError, ApprovalResponseError, ValueError) as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"error": str(exc)}, indent=2))
            return 1
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
        return 0

    print(f"Recorded OSRIL approval response: {payload['approval_id']} -> {payload['decision']}")
    print(f"  response_id: {payload['response_id']}")
    print(f"  runtime:     {payload['runtime_id']}")
    print(f"  workflow:    {payload['workflow_id']}")
    print(f"  session:     {payload['session_id']}")
    print(f"  applied:     {payload.get('applied_to_execution')}")
    if payload.get("application_path"):
        print(f"  application: {payload['application_path']}")
    print(f"  path:        {payload['response_path']}")
    return 0


def cmd_schedule_list(args: argparse.Namespace) -> int:
    """chaseos schedule list -- list all registered schedule intents"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    schedules = list_schedules(vault_root, check_registry=False)

    if getattr(args, "output_json", False):
        out = []
        for s in schedules:
            out.append({
                "schedule_id": s.schedule_id,
                "schedule_kind": s.schedule_kind,
                "workflow_id": s.workflow_id,
                "command_id": s.command_id,
                "enabled": s.enabled,
                "shadow_mode": s.shadow_mode,
                "cadence_type": s.cadence.type,
                "cron_expression": s.cadence.cron_expression,
                "timezone": s.cadence.timezone,
                "runtime_adapter_target": s.runtime_adapter_target,
                "approval_policy": s.approval_policy,
                "delivery_primary": s.delivery.primary_target,
            })
        print(json.dumps({"schedules": out, "count": len(out)}, indent=2))
        return 0

    print(f"ChaseOS Schedules  ({len(schedules)} registered)")
    print(f"  Source: runtime/schedules/")
    print()

    if not schedules:
        print("  No schedule intents registered.")
        print()
        print("  Add schedule intent files to runtime/schedules/ to register them.")
        return 0

    for s in schedules:
        status_tag = "ENABLED" if s.enabled else "disabled"
        shadow_tag = "  [shadow]" if s.shadow_mode else ""
        print(f"  {s.schedule_id}")
        if s.schedule_kind == "command":
            print(f"    Command:     {s.command_id}")
        else:
            print(f"    Workflow:    {s.workflow_id}")
        print(f"    Status:      {status_tag}{shadow_tag}")
        adapter_tag = s.runtime_adapter_target
        print(f"    Adapter:     {adapter_tag}")
        if s.cadence.type == "cron":
            print(f"    Cadence:     {s.cadence.cron_expression}  ({s.cadence.timezone})")
        else:
            print(f"    Cadence:     {s.cadence.type}")
        print(f"    Approval:    {s.approval_policy}")
        print(f"    Delivery:    {s.delivery.primary_target}")
        print()

    print("  To show detail: chaseos schedule show SCHEDULE_ID")
    print("  To enable/disable: chaseos schedule enable/disable SCHEDULE_ID")
    print("  To validate: chaseos schedule validate")
    return 0


# ── Command: schedule show ────────────────────────────────────────────────────

def cmd_schedule_show(args: argparse.Namespace) -> int:
    """chaseos schedule show SCHEDULE_ID -- show full detail for a schedule intent"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    try:
        intent = load_schedule(args.schedule_id, vault_root, check_registry=False)
    except (ValueError, RuntimeError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if intent is None:
        print(f"ERROR: schedule '{args.schedule_id}' not found in runtime/schedules/", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        out = {
            "schedule_id": intent.schedule_id,
            "schedule_kind": intent.schedule_kind,
            "workflow_id": intent.workflow_id,
            "command_id": intent.command_id,
            "command": intent.command,
            "owner": intent.owner,
            "enabled": intent.enabled,
            "shadow_mode": intent.shadow_mode,
            "cadence": {
                "type": intent.cadence.type,
                "cron_expression": intent.cadence.cron_expression,
                "timezone": intent.cadence.timezone,
                "event_type": intent.cadence.event_type,
            },
            "trigger_source": intent.trigger_source,
            "runtime_adapter_target": intent.runtime_adapter_target,
            "delivery": {
                "primary_target": intent.delivery.primary_target,
                "vault_writeback_targets": intent.delivery.vault_writeback_targets,
                "external_delivery_declared": intent.delivery.external_delivery_declared,
                "vault_local_only": intent.delivery.vault_local_only,
            },
            "approval_policy": intent.approval_policy,
            "failure_behavior": intent.failure_behavior,
            "audit_requirements": intent.audit_requirements,
            "allowed_workflow_task_types": intent.allowed_workflow_task_types,
            "allowed_command_ids": intent.allowed_command_ids,
            "provenance": {
                "created_by": intent.provenance.created_by,
                "created_at": intent.provenance.created_at,
                "rationale": intent.provenance.rationale,
            },
            "notes": intent.notes,
        }
        print(json.dumps(out, indent=2))
        return 0

    def _row(label: str, value) -> None:
        if value is not None:
            print(f"  {label:<28} {value}")

    print(f"Schedule: {intent.schedule_id}")
    print()
    print("  -- Core --")
    _row("schedule_kind", intent.schedule_kind)
    if intent.schedule_kind == "command":
        _row("command_id", intent.command_id)
        _row("command", intent.command)
    else:
        _row("workflow_id", intent.workflow_id)
    _row("owner", intent.owner)
    _row("enabled", intent.enabled)
    _row("shadow_mode", intent.shadow_mode)
    _row("approval_policy", intent.approval_policy)
    _row("failure_behavior", intent.failure_behavior)
    print()
    print("  -- Cadence --")
    _row("type", intent.cadence.type)
    _row("cron_expression", intent.cadence.cron_expression)
    _row("timezone", intent.cadence.timezone)
    _row("event_type", intent.cadence.event_type)
    print()
    print("  -- Runtime --")
    _row("trigger_source", intent.trigger_source)
    _row("runtime_adapter_target", intent.runtime_adapter_target)
    print()
    print("  -- Delivery --")
    _row("primary_target", intent.delivery.primary_target)
    _row("vault_local_only", intent.delivery.vault_local_only)
    _row("external_delivery_declared", intent.delivery.external_delivery_declared)
    for wt in intent.delivery.vault_writeback_targets:
        _row("vault_writeback_target", wt)
    print()
    print("  -- Governance --")
    for at in intent.allowed_workflow_task_types:
        _row("allowed_task_type", at)
    for ac in intent.allowed_command_ids:
        _row("allowed_command_id", ac)
    for ar in intent.audit_requirements:
        _row("audit_requirement", ar)
    print()
    print("  -- Provenance --")
    _row("created_by", intent.provenance.created_by)
    _row("created_at", intent.provenance.created_at)
    if intent.provenance.rationale:
        print(f"  {'rationale':<28} {intent.provenance.rationale[:80]}")
    if intent.notes:
        print()
        print(f"  Notes: {intent.notes[:120]}")
    print()
    print("  ChaseOS owns this schedule intent. OpenClaw executes it.")
    if intent.schedule_kind == "command":
        print("  Execution: OpenClaw cron -> {0}".format(intent.command))
    else:
        print("  Execution: OpenClaw cron -> chaseos run {0} -> Agent Orchestration Runtime path".format(intent.workflow_id))
    return 0


# ── Command: schedule enable ──────────────────────────────────────────────────

def cmd_schedule_enable(args: argparse.Namespace) -> int:
    """chaseos schedule enable SCHEDULE_ID"""
    operation = check_runtime_operation(
        "schedule.enable",
        write_targets=[
            f"runtime/schedules/{args.schedule_id}.yaml",
            "runtime/schedules/index.yaml",
            "07_LOGS/Schedule-State/schedule_state_log.jsonl",
        ],
    )
    if not operation[0]:
        payload = {"allowed": False, "operation": "schedule.enable", "reason": operation[1]}
        if getattr(args, "output_json", False):
            print(json.dumps(payload, indent=2))
        else:
            print(f"ERROR: {operation[1]}", file=sys.stderr)
        return 1
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    try:
        changed = enable_schedule(args.schedule_id, vault_root)
    except (ValueError, RuntimeError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps({
            "schedule_id": args.schedule_id,
            "action": "enable",
            "changed": changed,
            "enabled": True,
        }, indent=2))
        return 0

    if changed:
        print(f"Schedule enabled: {args.schedule_id}")
        print()
        print("  State change logged to 07_LOGS/Schedule-State/schedule_state_log.jsonl")
        print("  index.yaml regenerated.")
        print()
        print("  Note: ChaseOS owns the intent. OpenClaw must be reloaded to pick up the change.")
    else:
        print(f"Schedule already enabled: {args.schedule_id}")
        print("  No change made.")
    return 0


