# ── Command: schedule validate ────────────────────────────────────────────────

def cmd_schedule_validate(args: argparse.Namespace) -> int:
    """chaseos schedule validate -- validate all schedule intents against the workflow registry"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    errors = validate_all_schedules(vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps({
            "valid": len(errors) == 0,
            "error_count": len(errors),
            "errors": [{"schedule_id": e[0], "error": e[1]} for e in errors],
        }, indent=2))
        return 0 if not errors else 1

    if not errors:
        schedules = list_schedules(vault_root, check_registry=False)
        print(f"Schedule validation: OK ({len(schedules)} schedule(s) valid)")
        return 0

    print(f"Schedule validation: {len(errors)} error(s) found")
    print()
    for schedule_id, error in errors:
        print(f"  [{schedule_id}]")
        print(f"    {error}")
        print()
    return 1


# ── Command: schedule export ──────────────────────────────────────────────────

def cmd_schedule_export(args: argparse.Namespace) -> int:
    """chaseos schedule export --adapter ID -- export schedule intents for a runtime adapter"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    adapter_id = args.adapter
    enabled_only = not getattr(args, "all", False)

    try:
        entries = export_schedules_for_adapter(
            adapter_id, vault_root, enabled_only=enabled_only
        )
    except ValueError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps({
            "adapter": adapter_id,
            "schedule_count": len(entries),
            "schedules": entries,
        }, indent=2))
        return 0

    print(f"ChaseOS Schedules for adapter: {adapter_id}")
    print(f"  Source: runtime/schedules/  (ChaseOS owns this — adapter executes only)")
    print()

    if not entries:
        filter_note = "enabled" if enabled_only else "registered"
        print(f"  No {filter_note} schedules target adapter '{adapter_id}'.")
        print()
        print("  Use --all to include disabled schedules.")
        return 0

    for e in entries:
        status = "ENABLED" if e["enabled"] else "DISABLED"
        shadow = " [shadow-mode]" if e["shadow_mode"] else ""
        print(f"  [{status}{shadow}] {e['schedule_id']}")
        if e.get("schedule_kind") == "command":
            print(f"    command_id:  {e['command_id']}")
        else:
            print(f"    workflow:    {e['workflow_id']}")
        if e["cron_expression"] and e["timezone"]:
            print(f"    cron:        {e['cron_expression']} ({e['timezone']})")
        print(f"    command:     {e['command']}")
        print(f"    writeback:   {', '.join(e['vault_writeback_targets'])}")
        print(f"    on-failure:  {e['failure_behavior']}")
        print()

    print("  Governance:")
    print("    ChaseOS owns schedule intent. This adapter is the designated executor.")
    print("    Run 'chaseos schedule validate' to verify all intents are registry-aligned.")
    print("    Run 'chaseos schedule enable/disable SCHEDULE_ID' to change active state.")
    print("    ChaseOS native cron execution is not built — adapter cron must match this output.")
    return 0


