    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
        return 0 if payload.get("settings_posture") != "blocked" else 1

    print("ChaseOS Config Summary")
    print(f"  settings_posture: {payload.get('settings_posture')}")
    print(f"  read_only: {payload.get('read_only')}")
    config = payload.get("config") or {}
    print(f"  config_present: {config.get('config_present')}")
    print(f"  config_path: {config.get('config_path')}")
    provider_summary = payload.get("provider_summary") or {}
    runtime_summary = payload.get("runtime_summary") or {}
    print(f"  providers: {provider_summary.get('valid_count')}/{provider_summary.get('known_count')} valid")
    print(f"  runtimes: {runtime_summary.get('known_count')} known")
    attention_items = payload.get("attention_items") or []
    if attention_items:
        print("  attention:")
