def cmd_agent_register(args: argparse.Namespace) -> int:
    runtime_id = getattr(args, "runtime_id", None) or f"{args.provider}-{args.surface}"
    blocked = _check_runtime_operation_or_block(
        args,
        "agent.register",
        write_targets=_runtime_registry_write_targets(runtime_id),
    )
    if blocked is not None:
        return blocked
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        result = register_runtime(
            runtime_id=runtime_id,
            provider=args.provider,
            surface_type=args.surface,
            vault_root=vault_root,
            trust_ceiling=getattr(args, "trust_ceiling", "tier-4"),
            notes=getattr(args, "notes", None),
        )
    except (RuntimeError, ValueError, FileNotFoundError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    entry = result["entry"]
    path = result["path"]

    # Brain bootstrap: seed empty Layer C memory surfaces for the new runtime
    bootstrap: dict = {}
    try:
        from runtime.aor.brain_bootstrap import run_brain_bootstrap
        bootstrap = run_brain_bootstrap(entry["runtime_id"], vault_root=vault_root)
    except Exception:  # noqa: BLE001
        bootstrap = {"ok": False, "seeds_written": [], "seeds_skipped": []}

    payload = {
        "runtime_id": entry["runtime_id"],
        "provider": entry["provider"],
        "surface_type": entry["surface_type"],
        "lifecycle_state": entry["lifecycle_state"],
        "trust_ceiling": entry["trust_ceiling"],
        "created": True,
        "registry_entry_path": str(path),
        "brain_bootstrap": bootstrap,
    }
    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
        return 0

    print(f"Registered runtime: {entry['runtime_id']}")
    print(f"  provider: {entry['provider']}")
    print(f"  surface_type: {entry['surface_type']}")
    print(f"  lifecycle_state: {entry['lifecycle_state']}")
    print(f"  trust_ceiling: {entry['trust_ceiling']}")
    print(f"  registry_entry_path: {path}")
    seeds = bootstrap.get("seeds_written", [])
    skipped = bootstrap.get("seeds_skipped", [])
    if seeds:
        print(f"  brain_bootstrap: seeded {len(seeds)} surface(s)")
        for s in seeds:
            print(f"    + {s}")
    if skipped:
        print(f"  brain_bootstrap: skipped {len(skipped)} (already present)")
    return 0


def cmd_agent_status(args: argparse.Namespace) -> int:
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        entry = load_runtime_entry(args.runtime_id, vault_root=vault_root)
    except (RuntimeError, ValueError, FileNotFoundError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if entry is None:
        print(f"ERROR: Runtime '{args.runtime_id}' is not registered", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(entry, indent=2))
        return 0

    print("ChaseOS Agent Status")
    for key in [
        "runtime_id",
        "provider",
        "surface_type",
        "adapter_binding_status",
        "trust_ceiling",
        "lifecycle_state",
        "initial_scope_posture",
        "policy_binding_record",
        "registered",
        "last_evaluated",
    ]:
        print(f"  {key}: {entry.get(key)}")
    if entry.get("allowed_task_families"):
        print(f"  allowed_task_families: {', '.join(entry['allowed_task_families'])}")
    return 0


def cmd_agent_lifecycle(args: argparse.Namespace) -> int:
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        if getattr(args, "state", None):
            if not getattr(args, "decision_ref", None):
                print("ERROR: --decision-ref is required when changing lifecycle state", file=sys.stderr)
                return 1
            blocked = _check_runtime_operation_or_block(
                args,
                "agent.lifecycle.transition",
                write_targets=_runtime_registry_write_targets(args.runtime_id),
            )
            if blocked is not None:
                return blocked
            result = transition_lifecycle_state(
                args.runtime_id,
                args.state,
                decision_ref=args.decision_ref,
                vault_root=vault_root,
            )
            entry = result["entry"]
            payload = {
                "runtime_id": entry["runtime_id"],
                "lifecycle_state": entry["lifecycle_state"],
                "transition_performed": bool(result["changed"]),
                "audit_path": str(result["audit_path"]) if result.get("audit_path") else None,
            }
        else:
            entry = load_runtime_entry(args.runtime_id, vault_root=vault_root)
            if entry is None:
                print(f"ERROR: Runtime '{args.runtime_id}' is not registered", file=sys.stderr)
                return 1
            payload = {
                "runtime_id": entry["runtime_id"],
                "lifecycle_state": entry["lifecycle_state"],
                "transition_performed": False,
                "trust_ceiling": entry.get("trust_ceiling"),
            }
    except (RuntimeError, ValueError, FileNotFoundError) as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
        return 0

    print("ChaseOS Agent Lifecycle")
    print(f"  runtime_id: {payload['runtime_id']}")
    print(f"  lifecycle_state: {payload['lifecycle_state']}")
    print(f"  transition_performed: {payload['transition_performed']}")
    if payload.get("audit_path"):
        print(f"  audit_path: {payload['audit_path']}")
    if payload.get("trust_ceiling"):
        print(f"  trust_ceiling: {payload['trust_ceiling']}")
    return 0


