def cmd_chaser_gateway_diagnose(args: argparse.Namespace) -> int:
    """chaseos chaser gateway diagnose -- read-only Chaser Gateway readiness probe"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    from runtime.chaser.gateway_diagnostic import run_gateway_diagnostic, STATE_RUNNING

    result = run_gateway_diagnostic(
        vault_root, runtime_id=getattr(args, "runtime_id", "openclaw") or "openclaw"
    )
    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2))
    else:
        print(f"Chaser Gateway Diagnostic — state: {result['overall_state'].upper()} "
              f"(ready={result['ready']})")
        for c in result["checks"]:
            print(f"  [{c['status']:>8}] {c['name']}: {c['detail']}")
        if result["next_actions"]:
            print("\nRepair plan (operator review — nothing is auto-applied):")
            for a in result["next_actions"]:
                print(f"  - ({a['check']}) {a['action']}")
    return 0 if result["overall_state"] == STATE_RUNNING else 2


def cmd_chaser_gateway_ingress(args: argparse.Namespace) -> int:
    """chaseos chaser gateway ingress -- route one governed structured request"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    try:
        payload = json.loads(getattr(args, "payload_json", "{}") or "{}")
    except json.JSONDecodeError as exc:
        print(f"ERROR: invalid --payload-json: {exc}", file=sys.stderr)
        return 1
    if not isinstance(payload, dict):
        print("ERROR: --payload-json must decode to an object", file=sys.stderr)
        return 1
    if getattr(args, "confirm_approved_terminal_write", False):
        payload["confirm_approved_terminal_write"] = True

    from runtime.chaser.gateway import handle_gateway_ingress

    request = {
        "request_id": getattr(args, "request_id", "") or "",
        "session_id": getattr(args, "session_id", "") or "",
        "intent": getattr(args, "intent", "") or "",
        "payload": payload,
        "auth": {
            "mode": "local_operator" if getattr(args, "confirm_local_operator", False) else "",
            "operator_confirmed": bool(getattr(args, "confirm_local_operator", False)),
            "approval_queue_write_confirmed": bool(getattr(args, "confirm_approval_queue_write", False)),
            "operator_approved_terminal_write": bool(getattr(args, "confirm_approved_terminal_write", False)),
        },
    }
    result = handle_gateway_ingress(vault_root, request)
    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2))
    else:
        print(f"Chaser gateway ingress: {result.get('status')}")
        print(f"  intent:  {result.get('intent')}")
        print(f"  request: {result.get('request_id')}")
        print("  authority: no Studio execution, Agent Bus write, provider call, or canonical writeback")
        for reason in result.get("blockers") or []:
            print(f"  blocked: {reason}")
    return 0 if result.get("ok") else 2


