def cmd_operate_browser_screenshot(args: argparse.Namespace) -> int:
    """chaseos operate browser screenshot URL -- capture full-page screenshot"""
    screenshot_target = getattr(args, "output", None) or "07_LOGS/Operator-Screenshots/"
    blocked = _check_runtime_operation_or_block(
        args,
        "browser.screenshot",
        write_targets=["07_LOGS/Agent-Activity/", screenshot_target],
        external_api="browser.navigation",
        external_side_effect=True,
    )
    if blocked is not None:
        return blocked
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    extra_origins = getattr(args, "allowed_origin", None) or []
    return run_screenshot(
        url=args.url,
        output_path=getattr(args, "output", None),
        extra_origins=extra_origins,
        vault_root=vault_root,
        output_json=getattr(args, "output_json", False),
        wait_for_selector=getattr(args, "wait_for", "body"),
        wait_timeout_ms=getattr(args, "wait_timeout_ms", 5000),
        settle_ms=getattr(args, "settle_ms", 250),
        full_page=not getattr(args, "viewport_only", False),
        clip_selector=getattr(args, "clip_selector", None),
        require_nonblank=getattr(args, "require_nonblank", False),
        min_unique_colors=getattr(args, "min_unique_colors", 2),
        max_dominant_ratio=getattr(args, "max_dominant_ratio", 0.995),
    )


