def _doctor_check(checks: list[dict], name: str, ok: bool, detail: str, *, severity: str = "error") -> None:
    checks.append({"name": name, "ok": ok, "severity": severity, "detail": detail})


def _doctor_payload(checks: list[dict], **extra) -> dict:
    errors = [check["detail"] for check in checks if not check["ok"] and check["severity"] == "error"]
    warnings = [check["detail"] for check in checks if not check["ok"] and check["severity"] == "warning"]
    payload = {
        "checks": checks,
        "errors": errors,
        "warnings": warnings,
    }
    payload.update(extra)
    return payload


def _print_doctor_checks(title: str, checks: list[dict], success_message: str) -> None:
    print(title)
    print()
    for check in checks:
        if check["ok"]:
            _ok(check["name"])
        elif check["severity"] == "warning":
            _warn(check["name"], check["detail"])
        else:
            _err(check["name"], check["detail"])
    print()
    issues = sum(1 for check in checks if not check["ok"] and check["severity"] == "error")
    if issues == 0:
        print(f"  {success_message}")
    else:
        print(f"  {issues} issue(s) found. See above.")


def _load_pyproject_scripts(vault_root: Path) -> dict[str, str]:
    pyproject = vault_root / "pyproject.toml"
    if not pyproject.exists():
        return {}
    data = tomllib.loads(pyproject.read_text(encoding="utf-8"))
    scripts = data.get("project", {}).get("scripts", {})
    return {str(name): str(target) for name, target in scripts.items()}


def _console_script_targets() -> dict[str, list[str]]:
    try:
        entry_points = importlib_metadata.entry_points()
        console_scripts = entry_points.select(group="console_scripts")
    except Exception:
        return {}

    targets: dict[str, list[str]] = {}
    for entry_point in console_scripts:
        if entry_point.name in {"chaseos", "chase"}:
            targets.setdefault(entry_point.name, []).append(entry_point.value)
    return targets


_CREDENTIAL_KEY_FRAGMENTS = frozenset(
    {"api_key", "token", "webhook", "password", "client_secret", "private_key", "secret"}
)
_ALLOWED_CREDENTIAL_RE = re.compile(r"^[A-Z][A-Z0-9_]{2,}$")
_TEMPLATE_PLACEHOLDER_RE = re.compile(r"\$\{[^}]+\}|<[^>]+>|REPLACE_ME|\.\.\.|env:")
# Known policy enum strings — never literal credentials
_SAFE_POLICY_STRINGS = frozenset({
    "none", "forbidden", "required", "optional", "allowed", "blocked",
    "restricted", "disabled", "enabled", "read-only", "read_only",
    "operator", "audit", "standard", "true", "false",
})
# snake_case reference identifier (e.g. "discord_draft_webhook_reference") — not a literal value
_SNAKE_CASE_IDENTIFIER_RE = re.compile(r"^[a-z][a-z0-9]*(_[a-z0-9]+)+$")


def _walk_yaml_values(obj: object, *, prefix: str = "") -> list[tuple[str, object]]:
    results: list[tuple[str, object]] = []
    if isinstance(obj, dict):
        for k, v in obj.items():
            child_prefix = f"{prefix}.{k}" if prefix else str(k)
            results.extend(_walk_yaml_values(v, prefix=child_prefix))
    elif isinstance(obj, list):
        for i, item in enumerate(obj):
            results.extend(_walk_yaml_values(item, prefix=f"{prefix}[{i}]"))
    else:
        results.append((prefix, obj))
    return results


def _is_credential_key(key_path: str) -> bool:
    last = key_path.split(".")[-1].rstrip("0123456789[]")
    lower = last.lower()
    return any(frag in lower for frag in _CREDENTIAL_KEY_FRAGMENTS)


def _is_allowed_credential_value(value: object) -> bool:
    if value is None or isinstance(value, bool) or isinstance(value, (int, float)):
        return True
    if not isinstance(value, str):
        return True
    stripped = value.strip()
    if not stripped:
        return True
    if stripped.lower() in _SAFE_POLICY_STRINGS:
        return True  # known policy enum — never a credential
    if _ALLOWED_CREDENTIAL_RE.match(stripped):
        return True  # env var name (ALL_CAPS pattern)
    if _TEMPLATE_PLACEHOLDER_RE.search(stripped):
        return True  # template placeholder or env: reference
    if _SNAKE_CASE_IDENTIFIER_RE.match(stripped):
        return True  # snake_case reference identifier — not a literal value
    return False


def _check_credential_literals(vault_root: Path, checks: list[dict]) -> None:
    """L-3: warn if any runtime YAML contains a potential literal credential value."""
    import yaml as _yaml

    runtime_dir = vault_root / "runtime"
    if not runtime_dir.is_dir():
        _doctor_check(checks, "credential literal scan", True, "runtime/ dir absent — scan skipped", severity="warning")
        return

    flagged: list[str] = []
    for yaml_file in sorted(runtime_dir.rglob("*.yaml")):
        if yaml_file.name.startswith("_"):
            continue
        try:
            text = yaml_file.read_text(encoding="utf-8", errors="replace")
            obj = _yaml.safe_load(text)
        except Exception:
            continue
        if obj is None:
            continue
        for key_path, value in _walk_yaml_values(obj):
            if _is_credential_key(key_path) and not _is_allowed_credential_value(value):
                rel = str(yaml_file.relative_to(vault_root))
                snippet = repr(value)[:60]
                flagged.append(f"{rel}: {key_path}={snippet}")

    ok = not flagged
    if ok:
        detail = "No literal credentials detected in runtime YAML files."
    else:
        joined = "; ".join(flagged[:5])
        suffix = "…" if len(flagged) > 5 else ""
        detail = f"Potential literal credentials in YAML ({len(flagged)} hit(s)): {joined}{suffix}"
    _doctor_check(checks, "credential literal scan", ok, detail, severity="warning")


def _check_protected_files_sync(vault_root: Path, checks: list[dict]) -> None:
    """P-D1: error if protected_files.yaml and Permission-Matrix.md Section 2 table diverge."""
    import yaml as _yaml

    yaml_path = vault_root / "runtime" / "policy" / "protected_files.yaml"
    matrix_path = vault_root / "06_AGENTS" / "Permission-Matrix.md"

    if not yaml_path.exists():
        _doctor_check(checks, "protected files sync", False, f"protected_files.yaml not found at {yaml_path}")
        return
    if not matrix_path.exists():
        _doctor_check(checks, "protected files sync", False, f"Permission-Matrix.md not found at {matrix_path}")
        return

    try:
        yaml_data = _yaml.safe_load(yaml_path.read_text(encoding="utf-8"))
        yaml_paths: set[str] = set(yaml_data.get("protected_files", []))
    except Exception as exc:
        _doctor_check(checks, "protected files sync", False, f"Failed to parse protected_files.yaml: {exc}")
        return

    matrix_text = matrix_path.read_text(encoding="utf-8")
    # Scope extraction to the ### Protected Files section only — prevents false
    # positives from other tables in the document (git ops, approval rules, etc.).
    section_match = re.search(
        r"### Protected Files\b(.*?)(?=\n[ \t]*---|\n[ \t]*###)",
        matrix_text,
        re.DOTALL,
    )
    section_text = section_match.group(1) if section_match else matrix_text
    md_paths: set[str] = set(re.findall(r"\|\s*`([^`]+)`\s*\|", section_text))

    in_yaml_not_md = yaml_paths - md_paths
    in_md_not_yaml = md_paths - yaml_paths

    if not in_yaml_not_md and not in_md_not_yaml:
        _doctor_check(
            checks, "protected files sync", True,
            f"protected_files.yaml and Permission-Matrix.md Section 2 are in sync ({len(yaml_paths)} files).",
        )
    else:
        parts: list[str] = []
        if in_yaml_not_md:
            parts.append(f"in YAML not Matrix: {sorted(in_yaml_not_md)}")
        if in_md_not_yaml:
            parts.append(f"in Matrix not YAML: {sorted(in_md_not_yaml)}")
        _doctor_check(
            checks, "protected files sync", False,
            "protected_files.yaml ↔ Permission-Matrix.md drift — " + "; ".join(parts),
        )


def _build_cli_doctor_payload(
    vault_root: Path,
    *,
    run_contract_ratchet: bool = False,
    run_contract_ratchet_smoke: bool = False,
) -> dict:
    expected = "runtime.cli.main:main"
    checks: list[dict] = []
    if run_contract_ratchet_smoke:
        run_contract_ratchet = True
    ratchet_result: dict = {
        "requested": False,
        "run_smokes": False,
        "status": "skipped",
    }

    scripts = _load_pyproject_scripts(vault_root)
    for name in ("chaseos", "chase"):
        target = scripts.get(name)
        _doctor_check(
            checks,
            f"pyproject script: {name}",
            target == expected,
            f"{name} targets {target or 'missing'}, expected {expected}",
        )

    root_shim = vault_root / "chaseos.py"
    root_shim_text = root_shim.read_text(encoding="utf-8") if root_shim.exists() else ""
    root_shim_uses_canonical_cli = (
        "from runtime.cli.main import build_parser, main" in root_shim_text
        or (
            "from runtime.cli.main import main as canonical_main" in root_shim_text
            and "def build_parser(" not in root_shim_text
        )
    )
    _doctor_check(
        checks,
        "root shim: chaseos.py",
        root_shim_uses_canonical_cli,
        "chaseos.py must route to runtime.cli.main and define no parser",
    )

    runtime_cli_shim = vault_root / "runtime" / "cli.py"
    runtime_cli_text = runtime_cli_shim.read_text(encoding="utf-8") if runtime_cli_shim.exists() else ""
    _doctor_check(
        checks,
        "runtime shim: runtime/cli.py",
        "from runtime.cli.main import build_parser, main" in runtime_cli_text,
        "runtime/cli.py must import build_parser/main from runtime.cli.main and define no parser",
    )

    installed_targets = _console_script_targets()
    for name in ("chaseos", "chase"):
        targets = installed_targets.get(name, [])
        if not targets:
            _doctor_check(
                checks,
                f"installed entry point: {name}",
                False,
                f"{name} console script not visible in installed package metadata",
                severity="warning",
            )
            continue
        _doctor_check(
            checks,
            f"installed entry point: {name}",
            expected in targets,
            f"{name} installed targets {targets}, expected {expected}",
        )

    for name in ("chaseos", "chase"):
        resolved = shutil.which(name)
        _doctor_check(
            checks,
            f"PATH command: {name}",
            bool(resolved),
            f"{name} not found on PATH; reinstall with pip install -e . and reactivate shell",
            severity="warning",
        )

    if run_contract_ratchet:
        try:
            from runtime.cli.contract_ratchet import verify_cli_contract_ratchet

            ratchet_result = verify_cli_contract_ratchet(run_smokes=run_contract_ratchet_smoke)
            ratchet_result["requested"] = True
            ratchet_result["run_smokes"] = run_contract_ratchet_smoke
        except Exception as exc:
            ratchet_result = {
                "ok": False,
                "requested": True,
                "run_smokes": run_contract_ratchet_smoke,
                "status": "failed",
                "failures": [f"cli contract ratchet raised {type(exc).__name__}: {exc}"],
            }

        if ratchet_result.get("ok"):
            detail = (
                "CLI contract ratchet passed with read-only JSON smokes."
                if run_contract_ratchet_smoke
                else "CLI contract ratchet passed without live smokes."
            )
        else:
            failures = ratchet_result.get("failures") or ["no failure detail returned"]
            detail = (
                "CLI contract ratchet failed; run "
                "`python -m runtime.cli.main test cli-contract --json` for exact failures: "
                + "; ".join(str(failure) for failure in failures[:5])
            )
        _doctor_check(
            checks,
            "cli contract ratchet",
            bool(ratchet_result.get("ok")),
            detail,
        )

    _check_credential_literals(vault_root, checks)
    _check_protected_files_sync(vault_root, checks)

    return _doctor_payload(
        checks,
        expected_entrypoint=expected,
        pyproject_scripts=scripts,
        installed_entrypoints=installed_targets,
        path_commands={name: shutil.which(name) for name in ("chaseos", "chase")},
        cli_contract_ratchet=ratchet_result,
    )


def cmd_n8n_execute(args: argparse.Namespace) -> int:
    """chaseos n8n execute WORKFLOW_ID -- trigger an n8n workflow live."""
    import json as _json
    from pathlib import Path as _Path

    vault_root = _resolve_vault(getattr(args, "vault_root", None))
    config_path = _Path(vault_root) / "runtime/policy/adapters/n8n_config.yaml"
    registry_path = _Path(vault_root) / "runtime/policy/adapters/n8n_workflows.yaml"

    payload_raw = getattr(args, "payload", None) or "{}"
    try:
        payload = _json.loads(payload_raw)
    except _json.JSONDecodeError as exc:
        print(f"error: --payload is not valid JSON: {exc}")
        return 1

    try:
        from runtime.adapters.n8n.executor import N8NExecutionError, execute_n8n_workflow
        result = execute_n8n_workflow(
            args.workflow_id,
            caller=getattr(args, "caller", "chaseos"),
            config_path=config_path,
            registry_path=registry_path,
            payload=payload,
            production=getattr(args, "production", False),
            approved=getattr(args, "approved", False),
        )
    except N8NExecutionError as exc:
        print(f"n8n: policy blocked — {exc}")
        return 1

    if result.get("ok"):
        print(f"n8n: ok — workflow '{result['workflow_id']}' executed via {result['trigger_type']}")
        if result.get("response"):
            print(f"n8n: response — {_json.dumps(result['response'])}")
    else:
        print(f"n8n: failed — {result.get('error', 'unknown')} (http_status={result.get('http_status')})")
        if result.get("reason"):
            print(f"n8n: reason — {result['reason']}")
    return 0 if result.get("ok") else 1


def cmd_n8n_dry_run(args: argparse.Namespace) -> int:
    """chaseos n8n dry-run WORKFLOW_ID -- build a no-live-call workflow draft."""
    import json as _json
    from pathlib import Path as _Path

    vault_root = _resolve_vault(getattr(args, "vault_root", None))
    registry_path = _Path(vault_root) / "runtime/policy/adapters/n8n_workflows.yaml"

    payload_raw = getattr(args, "payload", None) or "{}"
    try:
        payload = _json.loads(payload_raw)
    except _json.JSONDecodeError as exc:
        print(_json.dumps({"status": "invalid_payload", "errors": [f"--payload is not valid JSON: {exc}"]}))
        return 1
    if not isinstance(payload, dict):
        print(_json.dumps({"status": "invalid_payload", "errors": ["--payload must decode to a JSON object"]}))
        return 1

    try:
        from runtime.adapters.n8n.workflow_policy import N8NWorkflowPolicyError, build_n8n_call_draft

        draft = build_n8n_call_draft(
            workflow_id=args.workflow_id,
            registry_path=registry_path,
            caller=getattr(args, "caller", "chaseos_runtime_mcp"),
            payload=payload,
            production=getattr(args, "production", False),
            approved=getattr(args, "approved", False),
        )
    except N8NWorkflowPolicyError as exc:
        result = {
            "status": "blocked",
            "readiness_status": "blocked",
            "workflow_id": args.workflow_id,
            "caller": getattr(args, "caller", "chaseos_runtime_mcp"),
            "blocked_reasons": [str(exc)],
            "dry_run": True,
            "live_http_call": False,
            "writes_performed": False,
            "authority_flags": {
                "read_only": True,
                "workflow_execution_allowed": False,
                "live_http_call_allowed": False,
                "draft_write_allowed": False,
                "connector_calls_allowed": False,
                "canonical_writeback_allowed": False,
            },
        }
        print(_json.dumps(result, indent=2))
        return 1

    result = {
        "status": "dry_run_ready",
        "readiness_status": "ready",
        "workflow_id": draft["workflow_id"],
        "caller": draft["caller"],
        "dry_run": True,
        "live_http_call": False,
        "writes_performed": False,
        "draft": draft,
        "blocked_reasons": [],
        "forbidden_actions": [
            "workflow_execution",
            "live_http_call",
            "connector_call",
            "external_side_effect",
            "draft_write",
            "canonical_writeback",
        ],
        "authority_flags": {
            "read_only": True,
            "workflow_execution_allowed": False,
            "live_http_call_allowed": False,
            "draft_write_allowed": False,
            "connector_calls_allowed": False,
            "canonical_writeback_allowed": False,
        },
    }
    if getattr(args, "output_json", False):
        print(_json.dumps(result, indent=2))
    else:
        print(f"n8n dry-run: {draft['workflow_id']} ready")
        print("  live_http_call: false")
        print("  writes_performed: false")
    return 0


def cmd_n8n_readiness(args: argparse.Namespace) -> int:
    """chaseos n8n readiness -- show n8n connection and registry readiness."""
    import json as _json
    from pathlib import Path as _Path

    vault_root = _resolve_vault(getattr(args, "vault_root", None))
    config_path = _Path(vault_root) / "runtime/policy/adapters/n8n_config.yaml"
    registry_path = _Path(vault_root) / "runtime/policy/adapters/n8n_workflows.yaml"

    from runtime.adapters.n8n.mcp_connection import build_connection_readiness
    result = build_connection_readiness(config_path=config_path, registry_path=registry_path)
    if getattr(args, "output_json", False):
        print(_json.dumps(result, indent=2))
        return 0 if result.get("ok") else 1

    print(f"n8n readiness: {result.get('status')}")
    print(f"  live_http_call: {result.get('live_http_call')}")
    print(f"  writes_performed: {result.get('writes_performed')}")
    connection = result.get("connection") or {}
    print(f"  base_url_configured: {connection.get('base_url_configured')}")
    print(f"  token_present: {connection.get('token_present')}")
    print(f"  safe_to_probe: {connection.get('safe_to_probe')}")
    blocked = result.get("blocked_reasons") or []
    if blocked:
        print("  blocked_reasons:")
        for reason in blocked:
            print(f"    - {reason}")
    return 0 if result.get("ok") else 1


def cmd_doctor_cli(args: argparse.Namespace) -> int:
    """chaseos doctor cli -- verify CLI entrypoint installation and shims"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        payload = _doctor_payload(
            [{"name": "vault-root", "ok": False, "severity": "error", "detail": str(exc)}],
            expected_entrypoint="runtime.cli.main:main",
        )
        if getattr(args, "output_json", False):
            print(json.dumps(payload, indent=2))
        else:
            _err("vault-root", str(exc))
        return 1

    payload = _build_cli_doctor_payload(
        vault_root,
        run_contract_ratchet=getattr(args, "contract_ratchet", False),
        run_contract_ratchet_smoke=getattr(args, "contract_ratchet_smoke", False),
    )
    exit_code = 0 if not payload["errors"] else 1

    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
    else:
        _print_doctor_checks(
            "ChaseOS Doctor - CLI",
            payload["checks"],
            "CLI entrypoint checks passed.",
        )
    return exit_code


def cmd_doctor(args: argparse.Namespace) -> int:
    """chaseos doctor -- vault health check"""
    if getattr(args, "doctor_target", None) == "cli":
        return cmd_doctor_cli(args)

    checks: list[dict] = []

    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
        _doctor_check(checks, "vault-root", True, str(vault_root))
    except RuntimeError as exc:
        _doctor_check(checks, "vault-root", False, str(exc))
        payload = _doctor_payload(checks)
        if getattr(args, "output_json", False):
            print(json.dumps(payload, indent=2))
        else:
            _print_doctor_checks("ChaseOS Doctor", checks, "ChaseOS capture layer is ready.")
        return 1

    inputs_dir = vault_root / "03_INPUTS"
    _doctor_check(
        checks,
        "03_INPUTS/",
        inputs_dir.exists(),
        "present" if inputs_dir.exists() else "directory does not exist -- run: mkdir 03_INPUTS",
    )

    q_dir = inputs_dir / QUARANTINE_SUBDIR
    _doctor_check(
        checks,
        f"03_INPUTS/{QUARANTINE_SUBDIR}/",
        q_dir.exists(),
        "present" if q_dir.exists() else "quarantine dir missing - will be created on first capture",
        severity="warning",
    )

    pyproject = vault_root / "pyproject.toml"
    _doctor_check(
        checks,
        "pyproject.toml",
        pyproject.exists(),
        "present" if pyproject.exists() else "not found -- CLI console_scripts not configured",
    )

    chaseos_path = shutil.which("chaseos")
    _doctor_check(
        checks,
        "chaseos command",
        bool(chaseos_path),
        chaseos_path or "not in PATH - run: .venv/Scripts/pip install -e . then add .venv/Scripts to user PATH",
        severity="warning",
    )

    claude_path = vault_root / "CLAUDE.md"
    _doctor_check(
        checks,
        "CLAUDE.md",
        claude_path.exists(),
        "present" if claude_path.exists() else "not found -- may not be in a ChaseOS vault",
        severity="warning",
    )

    bridge_doc = vault_root / "06_AGENTS" / "AI-Generated-Output-Bridge.md"
    _doctor_check(
        checks,
        "AI-Generated-Output-Bridge.md",
        bridge_doc.exists(),
        "present" if bridge_doc.exists() else "Pass 3 bridge doc not found (non-critical)",
        severity="warning",
    )

    payload = _doctor_payload(checks, vault_root=str(vault_root))
    exit_code = 0 if not payload["errors"] else 1

    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2))
    else:
        _print_doctor_checks("ChaseOS Doctor", checks, "All checks passed. ChaseOS capture layer is ready.")

    return exit_code


def _ok(label: str) -> None:
    print(f"  [OK]   {label}")


def _warn(label: str, msg: str) -> None:
    print(f"  [WARN] {label}: {msg}")


def _err(label: str, msg: str) -> None:
    print(f"  [ERR]  {label}: {msg}")


