def cmd_watch_add(args: argparse.Namespace) -> int:
    """chaseos watch add PATH --class CLASS [options]"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    try:
        folder_def = add_folder(
            vault_root=vault_root,
            folder_path=args.path,
            input_class=args.input_class,
            source_platform=getattr(args, "source_platform", "watched-folder") or "watched-folder",
            extensions=getattr(args, "extensions", None) or [],
            workspace_hint=getattr(args, "workspace_hint", None),
            domain_hint=getattr(args, "domain_hint", None),
            project_hint=getattr(args, "project_hint", None),
            topic_hint=getattr(args, "topic_hint", None),
            origin_kind=getattr(args, "origin_kind", None),
            desired_output_kind=getattr(args, "desired_output_kind", None),
        )
    except ValueError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(folder_def, indent=2))
        return 0

    print(f"Watch folder added: {folder_def['path']}")
    print(f"  Class:      {folder_def['input_class']}")
    print(f"  Platform:   {folder_def['source_platform']}")
    print(f"  Extensions: {', '.join(folder_def['extensions'])}")
    print(f"  Enabled:    {folder_def['enabled']}")
    if folder_def.get("domain_hint"):
        print(f"  Domain:     {folder_def['domain_hint']}")
    if folder_def.get("project_hint"):
        print(f"  Project:    {folder_def['project_hint']}")
    if folder_def.get("workspace_hint"):
        print(f"  Workspace:  {folder_def['workspace_hint']}")
    print()
    config_file = watch_config_path(vault_root)
    print(f"  Config:     {config_file}")
    print()
    print("  Run 'chaseos watch run --once' to scan watched folders.")
    return 0


