def cmd_watch_list(args: argparse.Namespace) -> int:
    """chaseos watch list"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    folders = list_folders(vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps({"folders": folders, "count": len(folders)}, indent=2))
        return 0

    config_file = watch_config_path(vault_root)
    print(f"Watched folders  ({len(folders)} configured)")
    print(f"  Config: {config_file}")
    print()

    if not folders:
        print("  No watched folders configured.")
        print()
        print("  Add one: chaseos watch add PATH --class CLASS --source SOURCE")
        return 0

    for i, f in enumerate(folders, 1):
        status = "enabled" if f.get("enabled", True) else "DISABLED"
        exists = Path(f["path"]).exists()
        exists_tag = "" if exists else "  [PATH MISSING]"
        print(f"  [{i}] {f['path']}{exists_tag}")
        print(f"       Class:      {f['input_class']}  |  Platform: {f['source_platform']}  |  {status}")
        print(f"       Extensions: {', '.join(f.get('extensions', []))}")
        hints = [k for k in ("domain_hint", "project_hint", "topic_hint", "workspace_hint") if f.get(k)]
        if hints:
            hint_str = "  ".join(f"{k.replace('_hint','')}={f[k]}" for k in hints)
            print(f"       Hints:      {hint_str}")

    print()
    return 0


