# ── Command: watch run ─────────────────────────────────────────────────────────

def cmd_watch_run(args: argparse.Namespace) -> int:
    """
    chaseos watch run --once | --interval N

    Scan all enabled watched folders for new files and route them to capture.

    --once:       Single scan pass. Exits after completing.
    --interval N: Polling loop -- scan, sleep N seconds, repeat.
                  Use Ctrl+C to stop.

    Output per folder:
        captured N  -- new files routed to quarantine
        dup N       -- already in dedup registry (not re-captured)
        skip N      -- unsupported extension or already processed
        err N       -- per-file errors (do not stop the scan)

    All captures land in 03_INPUTS/00_QUARANTINE/[class]/.
    No Source Intelligence Core trigger. No auto-promotion.
    """
    import time as _time

    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    output_json = getattr(args, "output_json", False)
    once = getattr(args, "once", False)
    interval = getattr(args, "interval", None)

    if not once and interval is None:
        print("ERROR: specify --once or --interval N", file=sys.stderr)
        return 1

    def _run_once() -> tuple[int, int, int, int]:
        """Run one scan pass. Returns (captured, duplicates, skipped, errors) totals."""
        results = scan_all_folders(vault_root)

        total_captured  = sum(len(r.captured)   for r in results)
        total_dups      = sum(len(r.duplicates) for r in results)
        total_skipped   = sum(len(r.skipped)    for r in results)
        total_errors    = sum(len(r.errors)     for r in results)

        if output_json:
            out = []
            for r in results:
                folder_out: dict = {
                    "folder":     str(r.folder_path),
                    "enabled":    r.enabled,
                    "exists":     r.exists,
                    "captured":   [{"file": str(c.file_path), "capture_id": c.result.get("capture_id")} for c in r.captured],
                    "duplicates": [{"file": str(d.file_path)} for d in r.duplicates],
                    "skipped":    [{"file": str(s.file_path), "reason": s.reason} for s in r.skipped],
                    "errors":     [{"file": str(e.file_path), "error": e.error} for e in r.errors],
                }
                if r.folder_error:
                    folder_out["folder_error"] = r.folder_error
                out.append(folder_out)
            print(json.dumps({
                "folders":         out,
                "total_captured":  total_captured,
                "total_duplicates": total_dups,
                "total_skipped":   total_skipped,
                "total_errors":    total_errors,
            }, indent=2))
        else:
            print(f"Watch scan: {len(results)} folder(s)")
            print()
            for r in results:
                if not r.enabled:
                    print(f"  [skip] {r.folder_path}  (disabled)")
                    continue
                if r.folder_error:
                    print(f"  [ERR]  {r.folder_path}")
                    print(f"         {r.folder_error}")
                    continue
                cap_n  = len(r.captured)
                dup_n  = len(r.duplicates)
                skip_n = len(r.skipped)
                err_n  = len(r.errors)
                status_parts = []
                if cap_n:  status_parts.append(f"captured {cap_n}")
                if dup_n:  status_parts.append(f"dup {dup_n}")
                if skip_n: status_parts.append(f"skip {skip_n}")
                if err_n:  status_parts.append(f"err {err_n}")
                status = "  |  ".join(status_parts) if status_parts else "nothing new"
                print(f"  [OK]   {r.folder_path}")
                print(f"         {status}")
                if r.captured:
                    for c in r.captured:
                        print(f"           + {c.file_path.name} -> {c.result.get('filename', '?')}")
                if r.errors:
                    for e in r.errors:
                        print(f"           ! {e.file_path.name}: {e.error}", file=sys.stderr)
            print()
            print(f"  Total: {total_captured} captured, {total_dups} dup, {total_skipped} skipped, {total_errors} errors")
            if total_captured:
                print()
                print("  Next steps: review quarantine, then promote via Gate.")
                print("  Source Intelligence Core ingestion happens after Gate promotion - not now.")

        return total_captured, total_dups, total_skipped, total_errors

    if once:
        _, _, _, errors = _run_once()
        return 0 if errors == 0 else 1

    # --interval N polling loop
    try:
        run_count = 0
        while True:
            run_count += 1
            if not output_json:
                print(f"[run #{run_count}]")
            _run_once()
            if not output_json:
                print(f"  Sleeping {interval}s...")
            _time.sleep(interval)
    except KeyboardInterrupt:
        if not output_json:
            print()
            print("Watch loop stopped.")
        return 0


# ── Command: maintain ──────────────────────────────────────────────────────────

def cmd_maintain(args: argparse.Namespace) -> int:
    """
    chaseos maintain [--dry-run] [--json]
    Executes the ChaseOS 3-stage graph maintenance suite.
    --json suppresses verbose output and emits a single JSON object to stdout.
    """
    import io
    import contextlib
    from types import SimpleNamespace

    output_json = getattr(args, "output_json", False)
    if getattr(args, "status", False):
        payload = {
            "status": "ok",
            "read_only": True,
            "mutates_vault": False,
            "supports_dry_run": True,
            "full_scan_deferred_from_ratchet": True,
            "deferred_reason": "full maintenance scans the active vault and can be slow; ratchet uses this status profile",
            "stages": [
                "vault_hygiene",
                "daily_hub_linker",
                "provenance_linker",
            ],
            "safe_routine_smoke": True,
            "writes_performed": False,
            "authority_flags": {
                "read_only": True,
                "maintenance_fix_allowed": False,
                "graph_review_queue_write_allowed": False,
                "canonical_writeback_allowed": False,
            },
        }
        if output_json:
            print(json.dumps(payload, indent=2))
        else:
            print("ChaseOS Maintain Status")
            print("  Mode: read-only status")
            print("  Full dry-run: available but deferred from routine ratchet smoke")
            print("  Writes performed: no")
        return 0

    fixture_root_arg = getattr(args, "fixture_root", None)
    fixture_root = Path(fixture_root_arg).resolve() if fixture_root_arg else None
    if fixture_root is not None:
        blocked_reasons: list[str] = []
        if not args.dry_run:
            blocked_reasons.append("--fixture-root requires --dry-run")
        if write_graph_review_queue := getattr(args, "write_graph_review_queue", False):
            blocked_reasons.append("--fixture-root cannot write graph review queue artifacts")
        if getattr(args, "propose_ambiguous_link_decisions", False):
            blocked_reasons.append("--fixture-root cannot write ambiguous-link proposals")
        if not fixture_root.exists() or not fixture_root.is_dir():
            blocked_reasons.append(f"--fixture-root does not exist or is not a directory: {fixture_root}")
        if not (fixture_root / "CLAUDE.md").exists():
            blocked_reasons.append("--fixture-root must look like a ChaseOS fixture root with CLAUDE.md")
        if blocked_reasons:
            payload = {
                "status": "blocked",
                "read_only": True,
                "dry_run": bool(args.dry_run),
                "bounded_fixture_mode": True,
                "bounded_fixture_root": str(fixture_root),
                "blocked_reasons": blocked_reasons,
                "writes_performed": False,
                "authority_flags": {
                    "read_only": True,
                    "maintenance_fix_allowed": False,
                    "graph_review_queue_write_allowed": False,
                    "canonical_writeback_allowed": False,
                },
            }
            if output_json:
                print(json.dumps(payload, indent=2))
            else:
                print("ERROR: " + "; ".join(blocked_reasons), file=sys.stderr)
            return 1

    fix = not args.dry_run
    strict_graph_review = getattr(args, "strict_graph_review", False)
    write_graph_review_queue = getattr(args, "write_graph_review_queue", False)
    fix_semantic_hub_gaps = getattr(args, "fix_semantic_hub_gaps", False)
    semantic_hub_gap_limit = getattr(args, "semantic_hub_gap_limit", 50)
    fix_ambiguous_links = getattr(args, "fix_ambiguous_links", False)
    ambiguous_link_limit = getattr(args, "ambiguous_link_limit", 50)
    review_ambiguous_links = getattr(args, "review_ambiguous_links", False)
    ambiguous_review_limit = getattr(args, "ambiguous_review_limit", 50)
    propose_ambiguous_link_decisions = getattr(args, "propose_ambiguous_link_decisions", False)
    ambiguous_proposal_path = getattr(args, "ambiguous_proposal_path", None)
    ambiguous_proposal_max_items = getattr(args, "ambiguous_proposal_max_items", 50)
    ambiguous_proposal_include_pending = getattr(args, "ambiguous_proposal_include_pending", False)
    review_unresolved_links = getattr(args, "review_unresolved_links", False)
    unresolved_link_limit = getattr(args, "unresolved_link_limit", 50)
    if propose_ambiguous_link_decisions:
        review_ambiguous_links = True
        if not ambiguous_proposal_include_pending:
            pending_count = len(hygiene_mod._pending_ambiguous_link_proposal_keys(
                hygiene_mod.VAULT_ROOT,
                exclude_rel=ambiguous_proposal_path,
            ))
            ambiguous_review_limit = max(
                ambiguous_review_limit,
                max(0, ambiguous_proposal_max_items) + pending_count,
            )
        else:
            ambiguous_review_limit = max(ambiguous_review_limit, max(0, ambiguous_proposal_max_items))

    if not output_json:
        print("\n[CHASEOS MAINTAIN] Starting graph integrity sweep...\n")

    # When --json, suppress all module stdout so only the JSON object reaches stdout.
    _null = io.StringIO() if output_json else None

    def _run_stage(fn, **kwargs):
        if output_json:
            with contextlib.redirect_stdout(_null):
                return fn(**kwargs)
        return fn(**kwargs)

    # 1. Hygiene run
    if not output_json:
        print("=== Stage 1: Vault Hygiene ===")
    hygiene_report = _run_stage(
        hygiene_mod.run,
        fix=fix,
        delete_junk=fix,
        json_output=output_json,
        write_report=not output_json,
        write_review_queue=write_graph_review_queue,
        strict_review_gate=strict_graph_review,
        fix_semantic_hub_gaps=fix_semantic_hub_gaps,
        semantic_hub_gap_limit=semantic_hub_gap_limit,
        fix_ambiguous_links=fix_ambiguous_links,
        ambiguous_link_limit=ambiguous_link_limit,
        review_ambiguous_links=review_ambiguous_links,
        ambiguous_review_limit=ambiguous_review_limit,
        review_unresolved_links=review_unresolved_links,
        unresolved_link_limit=unresolved_link_limit,
        vault_root=fixture_root,
        audit=fixture_root is None,
    )
    ambiguous_link_proposal = None
    if propose_ambiguous_link_decisions:
        ambiguous_link_proposal = _run_stage(
            hygiene_mod.propose_ambiguous_link_decisions,
            report=hygiene_report,
            vault_root=fixture_root or hygiene_mod.VAULT_ROOT,
            output_path=ambiguous_proposal_path,
            max_items=max(0, ambiguous_proposal_max_items),
            include_pending=ambiguous_proposal_include_pending,
        )
        if not output_json:
            print(
                f"[AMBIGUOUS-PROPOSAL] "
                f"{ambiguous_link_proposal['proposal_count']} decisions -> "
                f"{ambiguous_link_proposal['proposal_path']}"
            )
    if not output_json:
        print()

    strict_blocked = getattr(hygiene_report, "strict_gate_failed", False)
    if strict_blocked:
        if not output_json:
            print(
                f"[STRICT-GATE] Maintenance blocked: "
                f"{hygiene_report.strict_gate_review_count} loose-node review items remain.\n"
            )
            print("=== Stage 2: Daily Hub Linker ===")
            print("skipped because Stage 1 strict graph review gate failed\n")
            print("=== Stage 3: Provenance Linker ===")
            print("skipped because Stage 1 strict graph review gate failed\n")
        hub_report = SimpleNamespace(
            files_scanned=0,
            notes_created=0,
            notes_updated=0,
            backlinks_added=0,
            skipped=True,
        )
        prov_report = SimpleNamespace(
            files_scanned=0,
            files_modified=0,
            links_added={},
            skipped=True,
        )
    else:
        # 2. Daily Hub Linker
        if not output_json:
            print("=== Stage 2: Daily Hub Linker ===")
        hub_report = _run_stage(daily_hub_mod.run, fix=fix, update_index=fix, vault_root=fixture_root)
        if not output_json:
            print()

        # 3. Provenance Linker
        if not output_json:
            print("=== Stage 3: Provenance Linker ===")
        prov_report = _run_stage(provenance_mod.run, fix=fix, vault_root=fixture_root)
        if not output_json:
            print()

    if output_json:
        summary = {
            "status": "blocked_review_required" if strict_blocked else ("dry_run" if args.dry_run else "complete"),
            "review_required": strict_blocked,
            "errors": ["blocked_review_required"] if strict_blocked else [],
            "warnings": [],
            "dry_run": bool(args.dry_run),
            "read_only": bool(args.dry_run),
            "bounded_fixture_mode": fixture_root is not None,
            "bounded_fixture_root": str(fixture_root) if fixture_root is not None else None,
            "writes_performed": False if args.dry_run else None,
            "authority_flags": {
                "read_only": bool(args.dry_run),
                "maintenance_fix_allowed": not args.dry_run,
                "graph_review_queue_write_allowed": bool(write_graph_review_queue and not args.dry_run),
                "canonical_writeback_allowed": False,
                "fixture_root_only": fixture_root is not None,
            },
            "stage_1_vault_hygiene": {
                "files_scanned": getattr(hygiene_report, "files_scanned", 0),
                "total_issues": len(getattr(hygiene_report, "issues", [])),
                "category_counts": hygiene_mod.summarize_issues(hygiene_report),
                "node_category_counts": hygiene_mod.summarize_node_categories(hygiene_report),
                "loose_node_review_count": len(hygiene_mod.build_loose_node_review_queue(hygiene_report)),
                "strict_gate_failed": getattr(hygiene_report, "strict_gate_failed", False),
                "strict_gate_review_count": getattr(hygiene_report, "strict_gate_review_count", 0),
                "review_artifacts": getattr(hygiene_report, "review_artifacts", {}),
                "ambiguous_link_proposal": ambiguous_link_proposal,
                "files_fixed": getattr(hygiene_report, "files_fixed", 0),
                "wikilinks_fixed": getattr(hygiene_report, "wikilinks_fixed", 0),
                "nodes_wired": getattr(hygiene_report, "nodes_wired", 0),
                "indexes_created": getattr(hygiene_report, "indexes_created", 0),
                "visible_graph_audit": getattr(hygiene_report, "visible_graph_audit", {}),
            },
            "stage_2_daily_hub": {
                "files_scanned": getattr(hub_report, "files_scanned", 0),
                "notes_created": getattr(hub_report, "notes_created", 0),
                "notes_updated": getattr(hub_report, "notes_updated", 0),
                "backlinks_added": getattr(hub_report, "backlinks_added", 0),
                "skipped": getattr(hub_report, "skipped", False),
            },
            "stage_3_provenance": {
                "files_scanned": getattr(prov_report, "files_scanned", 0),
                "files_modified": getattr(prov_report, "files_modified", 0),
                "links_added": dict(getattr(prov_report, "links_added", {})),
                "skipped": getattr(prov_report, "skipped", False),
            },
        }
        print(json.dumps(summary))
        if strict_blocked:
            return 2
    else:
        if args.dry_run:
            print("[DRY-RUN] Maintenance sweep checked without modifications.\n")
        else:
            print("[MAINTAIN] Operations Complete. Vault graph integrity is verified.\n")
        if strict_blocked:
            return 2
    return 0


# ── Commands: memory ──────────────────────────────────────────────────────────

def cmd_memory_status(args: argparse.Namespace) -> int:
    """chaseos memory status"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.inspector import build_memory_status
    status = build_memory_status(vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps(status, indent=2))
        return 0

    layer_c = status["layer_c"]
    layer_d = status["layer_d"]
    print("ChaseOS Memory Status")
    print(f"  Layer C runtimes: {layer_c['runtime_count']}")
    print(f"  Layer D active task contexts: {layer_d['active_task_context_count']}")
    print()
    print("  Stores:")
    print(f"    profiles:   {layer_c['profile_store']}")
    print(f"    identity:   {layer_c['identity_ledger_store']}")
    print(f"    repair:     {layer_c['repair_store']}")
    print(f"    scorecards: {layer_c['scorecard_store']}")
    print(f"    tasks:      {layer_d['task_store']}")
    return 0


def cmd_memory_summary(args: argparse.Namespace) -> int:
    """chaseos memory summary"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.inspector import build_memory_summary
    summary = build_memory_summary(vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps(summary, indent=2))
        return 0 if summary["memory_posture"] != "blocked" else 1

    print("ChaseOS Memory Summary")
    print(f"  memory_posture: {summary['memory_posture']}")
    print(f"  read_only: {summary['read_only']}")
    runtime_summary = summary["runtime_summary"]
    task_summary = summary["task_summary"]
    print(f"  runtime_count: {runtime_summary['runtime_count']}")
    print(f"  active_task_context_count: {task_summary['active_task_context_count']}")
    print("  family_counts:")
    for family, count in sorted(runtime_summary["family_counts"].items()):
        print(f"    {family}: {count}")
    attention_items = summary.get("attention_items") or []
    if attention_items:
        print("  attention:")
        for item in attention_items:
            target = f" {item.get('target')}" if item.get("target") else ""
            print(f"    - [{item.get('severity')}] {item.get('code')}{target}: {item.get('message')}")
    else:
        print("  attention: none")
    return 0 if summary["memory_posture"] != "blocked" else 1


def cmd_memory_structure(args: argparse.Namespace) -> int:
    """chaseos memory structure"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.inspector import build_memory_file_structure
    structure = build_memory_file_structure(vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps(structure, indent=2))
        return 0 if structure["status"] != "degraded" else 1

    print("ChaseOS Agent Memory File Structure")
    print(f"  source_backlog_id: {structure['source_backlog_id']}")
    print(f"  status: {structure['status']}")
    print(f"  read_only: {structure['read_only']}")
    print("  surfaces: " + ", ".join(structure["product_surfaces"]))
    print("  required paths:")
    for item in structure["required_paths"]:
        marker = "OK" if item["exists"] else "MISSING"
        print(f"    [{marker}] {item['path']} ({item['layer']}; {item['surface']})")
    print("  blocked lane: " + structure["blocked_lower_authority_lane"]["blocked_action"])
    if structure["missing_paths"]:
        print("  missing:")
        for path in structure["missing_paths"]:
            print(f"    - {path}")
    return 0 if structure["status"] != "degraded" else 1


