def cmd_memory_list(args: argparse.Namespace) -> int:
    """chaseos memory list"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.inspector import list_runtime_memory
    runtimes = list_runtime_memory(vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps({"runtimes": runtimes, "count": len(runtimes)}, indent=2))
        return 0

    print(f"Layer C Runtime Memory ({len(runtimes)} runtime(s))")
    for item in runtimes:
        flags = []
        if item.get("profile_present"):
            flags.append("profile")
        if item.get("identity_ledger_present"):
            flags.append("identity")
        if item.get("nav_map_present"):
            flags.append("nav")
        if item.get("scorecard_present"):
            flags.append("scorecard")
        if item.get("repair_memory_present"):
            flags.append("repair")
        print(f"  {item['runtime_id']}: {', '.join(flags) if flags else 'no stores'}")
    return 0


def cmd_memory_show(args: argparse.Namespace) -> int:
    """chaseos memory show RUNTIME_ID"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.inspector import get_runtime_memory
    bundle = get_runtime_memory(args.runtime_id, vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps(bundle, indent=2))
        return 0

    profile = bundle["layer_c"]["profile"]
    identity = bundle["layer_c"]["identity_ledger"]
    repair = bundle["layer_c"]["repair_memory"]
    scorecard = bundle["layer_c"]["scorecard"]
    stats = scorecard.get("aggregate_stats", {})

    print(f"Runtime Memory: {args.runtime_id}")
    print("  Layer C:")
    print(f"    profile_status: {profile.get('status')}")
    print(f"    identity_status: {identity.get('status')}")
    print(f"    repair_status:  {repair.get('status')}")
    print(f"    executions:     {stats.get('total_executions', 0)}")
    print(f"    reliability:    {stats.get('reliability_rate', 0.0)}")
    print("  Layer D:")
    print(f"    active_tasks:   {len(bundle['layer_d']['active_task_contexts'])}")
    print()
    print(f"  Boundary: {bundle['boundaries']['authority']}")
    return 0


