def cmd_memory_validate(args: argparse.Namespace) -> int:
    """chaseos memory validate"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.inspector import validate_memory_substrate
    result = validate_memory_substrate(vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2))
        return 0 if result["valid"] else 1

    if result["valid"]:
        print(
            f"Memory validation: OK ({result['checked_json_files']} JSON file(s), "
            f"{result['runtime_count']} runtime(s), "
            f"{result['active_task_context_count']} active task context(s))"
        )
        return 0

    print(f"Memory validation: {result['error_count']} error(s)")
    for error in result["errors"]:
        print(f"  {error['path']}: {error['error']}")
    return 1


def cmd_memory_ledger(args: argparse.Namespace) -> int:
    """chaseos memory ledger RUNTIME_ID"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.inspector import load_identity_ledger
    ledger = load_identity_ledger(args.runtime_id, vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps(ledger, indent=2))
        return 0

    status = ledger.get("status", "unknown")
    if status == "missing":
        print(f"No identity ledger found for runtime: {args.runtime_id}")
        print(f"  Expected: runtime/memory/adapters/{args.runtime_id}/identity-ledger.json")
        return 1

    print(f"Agent Identity Ledger: {args.runtime_id}")
    summary = ledger.get("identity_summary", {})
    if summary:
        print(f"  Posture:  {summary.get('current_actor_posture', 'unknown')}")
        print(f"  Surface:  {summary.get('execution_surface', 'unknown')}")
        print(f"  Trust:    {summary.get('trust_tier', 'unknown')}")
    print(f"  Status:   {status}")

    tendencies = ledger.get("behavioral_tendencies", [])
    if tendencies:
        print(f"\n  Behavioral Tendencies ({len(tendencies)}):")
        for t in tendencies:
            print(f"    [{t.get('status', '?')}] {t.get('id', '?')}: {t.get('summary', '')}")

    corrections = ledger.get("correction_history", [])
    if corrections:
        print(f"\n  Corrections ({len(corrections)}):")
        for c in corrections:
            print(f"    [{c.get('status', '?')}] {c.get('id', '?')}: {c.get('summary', '')}")

    drift = ledger.get("drift_signals", [])
    print(f"\n  Drift signals: {len(drift)}")

    print(f"\n  Boundary: {ledger.get('governance_boundary', 'advisory only')}")
    return 0


def cmd_memory_export(args: argparse.Namespace) -> int:
    """chaseos memory export RUNTIME_ID"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.growth import export_memory_snapshot
    snapshot = export_memory_snapshot(args.runtime_id, vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps(snapshot, indent=2, default=str))
        return 0

    if "export_error" in snapshot:
        print(f"ERROR: {snapshot['export_error']}", file=sys.stderr)
        return 1

    print(f"Memory Export: {args.runtime_id}")
    print(f"  exported_at: {snapshot.get('exported_at', '')[:19]}Z")
    for surface in ("profile", "nav_map", "repair_memory", "scorecard"):
        data = snapshot.get(surface, {})
        status = data.get("status", "missing")
        print(f"  {surface}: status={status}")
    return 0


