def cmd_scorecard_show(args: argparse.Namespace) -> int:
    """chaseos scorecard show RUNTIME_ID"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.scorecards.scorecard_updater import load_scorecard
    sc = load_scorecard(args.runtime_id, vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps(sc, indent=2))
        return 0

    stats = sc.get("aggregate_stats", {})
    executions = sc.get("executions", [])
    print(f"Agent Scorecard: {args.runtime_id}")
    print(f"  Schema version: {sc.get('schema_version', '?')}")
    print(f"  Total executions: {stats.get('total_executions', 0)}")
    print(f"  Success: {stats.get('success_count', 0)}  |  Escalated: {stats.get('escalated_count', 0)}  |  Failed: {stats.get('failed_count', 0)}")
    print(f"  Reliability: {stats.get('reliability_rate', 0.0) * 100:.1f}%  |  Overreach rate: {stats.get('overreach_rate', 0.0) * 100:.1f}%  |  CGL compliance: {stats.get('compliance_rate', 0.0) * 100:.1f}%")
    print(f"  Last updated: {sc.get('last_updated', 'unknown')}")
    print()
    if executions:
        limit = getattr(args, "limit", 10) or 10
        print(f"  Last {min(limit, len(executions))} execution(s):")
        for ex in executions[-limit:]:
            accepted = ex.get("operator_acceptance")
            accept_tag = ""
            if accepted is True:
                accept_tag = "  [accepted]"
            elif accepted is False:
                accept_tag = "  [rejected]"
            ts = ex.get("timestamp_utc", "")[:19].replace("T", " ")
            overreach = len(ex.get("overreach_events", []))
            cgl = len(ex.get("cgl_violations", []))
            flags = []
            if overreach:
                flags.append(f"overreach:{overreach}")
            if cgl:
                flags.append(f"cgl:{cgl}")
            flag_str = "  [" + ", ".join(flags) + "]" if flags else ""
            print(f"    {ts}  {ex.get('workflow_id', '?'):30s}  {ex.get('outcome', '?')}{accept_tag}{flag_str}")
            print(f"      audit_id: {ex.get('audit_id', '?')}")
    else:
        print("  No executions recorded yet.")
    return 0


def cmd_scorecard_accept(args: argparse.Namespace) -> int:
    """chaseos scorecard accept RUNTIME_ID AUDIT_ID"""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.memory.scorecards.scorecard_updater import mark_operator_acceptance
    ok = mark_operator_acceptance(args.runtime_id, args.audit_id, accepted=True, vault_root=vault_root)

    if getattr(args, "output_json", False):
        print(json.dumps({"runtime_id": args.runtime_id, "audit_id": args.audit_id, "accepted": True, "updated": ok}, indent=2))
        return 0 if ok else 1

    if ok:
        print(f"Marked accepted: {args.runtime_id} / {args.audit_id}")
        return 0
    print(f"ERROR: audit_id not found in scorecard for {args.runtime_id}", file=sys.stderr)
    return 1


