def cmd_sbp_promote_draft(args: argparse.Namespace) -> int:
    """chaseos sbp promote-draft — promote an SBP Discord draft to live delivery."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    draft_filename = getattr(args, "draft_filename", None) or ""
    dry_run = getattr(args, "dry_run", False)
    output_json = getattr(args, "output_json", False)
    draft_dir = vault_root / "07_LOGS" / "SBP-Runs" / "_drafts"

    # List mode — no filename given
    if not draft_filename:
        drafts = sorted(draft_dir.glob("*-discord-draft.md")) if draft_dir.is_dir() else []
        promoted = {p.stem for p in draft_dir.glob("*-discord-draft.promoted")} if draft_dir.is_dir() else set()
        payload: dict = {
            "drafts": [
                {
                    "filename": d.name,
                    "promoted": d.stem in promoted,
                    "size_bytes": d.stat().st_size,
                }
                for d in drafts
            ],
            "draft_dir": str(draft_dir),
            "count": len(drafts),
        }
        if output_json:
            print(json.dumps(payload, indent=2, default=str))
        else:
            print(f"SBP Discord Drafts — {draft_dir}")
            if not drafts:
                print("  No drafts found.")
            for d in drafts:
                marker = " [PROMOTED]" if d.stem in promoted else ""
                print(f"  {d.name}{marker}")
        return 0

    # Promote mode — specific draft
    draft_path = draft_dir / draft_filename
    if not draft_path.is_file():
        print(f"ERROR: draft not found: {draft_path}", file=sys.stderr)
        return 1

    marker_path = draft_dir / (draft_path.stem + ".promoted")
    if marker_path.exists():
        if output_json:
            print(json.dumps({"ok": False, "error": "already_promoted", "draft": draft_filename}, indent=2))
        else:
            print(f"ERROR: draft already promoted: {draft_filename}", file=sys.stderr)
        return 1

    # Parse pipeline_id from filename: <date>-<pipeline_id>-discord-draft.md
    stem = draft_path.stem  # e.g. "2026-05-18-sbp_strikezone_digest-discord-draft"
    pipeline_id = ""
    if "-discord-draft" in stem:
        # Everything between first date segment and "-discord-draft"
        after_date = stem[len("2026-05-18-"):] if stem.startswith("20") else stem
        after_date = after_date.split("-", 1)[-1] if after_date.startswith("20") else after_date
        # More robust: strip the trailing "-discord-draft"
        pipeline_id = stem.replace("-discord-draft", "")
        # Remove leading date (YYYY-MM-DD-)
        import re
        pipeline_id = re.sub(r"^\d{4}-\d{2}-\d{2}-", "", pipeline_id)

    # Find webhook env var from manifest
    webhook_env_var = "DISCORD_WEBHOOK_URL"
    manifest_path = vault_root / "runtime" / "workflows" / "registry" / f"{pipeline_id}.yaml"
    if manifest_path.is_file():
        try:
            import yaml  # type: ignore[import]
            manifest = yaml.safe_load(manifest_path.read_text(encoding="utf-8")) or {}
            for da in (manifest.get("sbp_config") or {}).get("delivery_adapters") or []:
                if da.get("type") == "discord" and da.get("webhook_env_var"):
                    webhook_env_var = da["webhook_env_var"]
                    break
        except Exception:
            pass

    content = draft_path.read_text(encoding="utf-8")

    if dry_run:
        payload = {
            "ok": True,
            "dry_run": True,
            "draft": draft_filename,
            "pipeline_id": pipeline_id,
            "webhook_env_var": webhook_env_var,
            "content_length": len(content),
            "would_promote": True,
        }
        if output_json:
            print(json.dumps(payload, indent=2, default=str))
        else:
            print(f"DRY RUN — would promote: {draft_filename}")
            print(f"  pipeline_id:     {pipeline_id}")
            print(f"  webhook_env_var: {webhook_env_var}")
            print(f"  content_length:  {len(content)} chars")
        return 0

    from runtime.sbp.delivery_adapters import DiscordDeliveryAdapter
    adapter = DiscordDeliveryAdapter()
    delivery_context = {
        "vault_root": str(vault_root),
        "pipeline_id": pipeline_id,
        "date": draft_path.stem[:10],
        "webhook_env_var": webhook_env_var,
        "draft_review_required": False,  # promoting — skip draft gate
    }
    result = adapter.deliver(content, delivery_context)

    if result.get("success"):
        marker_path.write_text(
            json.dumps(
                {
                    "promoted_at": _now_utc() if "_now_utc" in dir() else "",
                    "draft": draft_filename,
                    "pipeline_id": pipeline_id,
                    "webhook_env_var": webhook_env_var,
                    "chunks_sent": result.get("chunks_sent"),
                },
                indent=2,
            ),
            encoding="utf-8",
        )

    payload = {
        "ok": result.get("success", False),
        "draft": draft_filename,
        "pipeline_id": pipeline_id,
        "webhook_env_var": webhook_env_var,
        "delivery": result,
        "marker_written": marker_path.exists(),
    }
    if output_json:
        print(json.dumps(payload, indent=2, default=str))
    else:
        status = "PROMOTED" if result.get("success") else "FAILED"
        print(f"{status}: {draft_filename}")
        print(f"  {result.get('details', '')}")
    return 0 if result.get("success") else 1


def cmd_acquisition_run(args: argparse.Namespace) -> int:
    """chaseos acquisition run — run the StrikeZone acquisition pipeline."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    plan_id = getattr(args, "plan_id", "strikezone-daily")
    dry_run = getattr(args, "dry_run", False)

    if dry_run:
        # Show what would run without touching the network
        from runtime.acquisition.live_sources import (
            STRIKEZONE_LIVE_QUERIES,
            STRIKEZONE_RSS_FEEDS,
            STRIKEZONE_WEB_PAGES,
            STRIKEZONE_EMAIL_SPECS,
            STRIKEZONE_GOOGLE_DOCS,
            STRIKEZONE_GOOGLE_DRIVE_FOLDERS,
        )
        summary = {
            "plan_id": plan_id,
            "dry_run": True,
            "sources": {
                "ai_queries": [s.source_id for s in STRIKEZONE_LIVE_QUERIES],
                "rss_feeds": [s.source_id for s in STRIKEZONE_RSS_FEEDS],
                "web_pages": [s.source_id for s in STRIKEZONE_WEB_PAGES],
                "email_specs": [s.source_id for s in STRIKEZONE_EMAIL_SPECS],
                "google_docs": [s.source_id for s in STRIKEZONE_GOOGLE_DOCS],
                "google_drive": [s.source_id for s in STRIKEZONE_GOOGLE_DRIVE_FOLDERS],
            },
        }
        if getattr(args, "output_json", False):
            print(json.dumps(summary, indent=2))
        else:
            print(f"Acquisition dry-run: plan_id={plan_id}")
            for category, ids in summary["sources"].items():
                if ids:
                    print(f"  {category}: {', '.join(ids)}")
                else:
                    print(f"  {category}: (none configured)")
        return 0

    # Live run — delegate to the registered workflow handler
    if plan_id != "strikezone-daily":
        print(f"ERROR: only 'strikezone-daily' is registered; got {plan_id!r}", file=sys.stderr)
        return 1

    from runtime.workflows.strikezone_acquisition import run_strikezone_acquisition, WorkflowExecutionError
    try:
        result = run_strikezone_acquisition({}, vault_root)
    except WorkflowExecutionError as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"error": str(exc)}, indent=2))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2, default=str))
        return 0

    live_count = result.get("live_source_count", 0)
    packet_count = len(result.get("source_packet_paths", []))
    print(f"Acquisition complete: plan={plan_id}")
    print(f"  Live sources captured: {live_count}")
    print(f"  Source packets built:  {packet_count}")
    briefing = result.get("briefing_ready_input_set_path", "")
    if briefing:
        print(f"  Briefing input set:    {briefing}")
    return 0


def cmd_acquisition_visual_capture_preview(args: argparse.Namespace) -> int:
    """chaseos acquisition visual-capture-preview - preview one reviewed Capture to Markdown capture."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.acquisition.adapters.visual_capture_adapter import (
        VisualCapturePreviewError,
        preview_visual_capture_acquisition,
    )
    from runtime.acquisition.validators import AcquisitionValidationError

    try:
        result = preview_visual_capture_acquisition(
            vault_root,
            getattr(args, "capture_path", ""),
            reviewed_by=getattr(args, "reviewed_by", "operator"),
        )
    except (VisualCapturePreviewError, AcquisitionValidationError) as exc:
        payload = {
            "ok": False,
            "surface": "acquisition.visual_capture_preview",
            "status": "blocked",
            "read_only": True,
            "write_performed": False,
            "error": str(exc),
            "authority": {
                "aor_dispatch_allowed": False,
                "sic_ingestion_allowed": False,
                "canonical_mutation_allowed": False,
                "graph_index_mutation_allowed": False,
                "provider_call_allowed": False,
                "external_send_allowed": False,
            },
        }
        if getattr(args, "output_json", False):
            print(json.dumps(payload, indent=2, default=str))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2, default=str))
        return 0

    capture = result.get("capture") or {}
    print("Visual capture acquisition preview: preview_ready")
    print(f"  Capture:          {capture.get('content_path')}")
    print(f"  Sidecar:          {capture.get('sidecar_path')}")
    print(f"  Packet:           {capture.get('visual_capture_packet_path') or '(missing)'}")
    print(f"  Source packets:   {len(result.get('source_packets') or [])}")
    print(f"  Pack root:        {Path(result.get('normalized_source_pack_path', '')).parent}")
    print(f"  Briefing input:   {result.get('briefing_ready_input_set_path')}")
    print("  Writes:           none (read-only preview)")
    print("  Agent Orchestration Runtime / Source Intelligence Core: not dispatched / not ingested")
    return 0


