def cmd_studio_list_pending(args: argparse.Namespace) -> int:
    """chaseos studio list-pending - list pending Studio write approval requests."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.service import StudioService
    svc = StudioService(vault_root)
    pending = svc.list_pending()

    if getattr(args, "output_json", False):
        print(json.dumps({"ok": True, "pending": [r.to_dict() for r in pending], "count": len(pending)}, indent=2, default=str))
        return 0

    if not pending:
        print("No pending Studio approval requests.")
        return 0

    for req in pending:
        print(f"[{req.approval_id}] {req.action_spec.action_type} → {req.action_spec.target_path}")
        print(f"  submitted: {req.submitted_at}  by: {req.action_spec.submitted_by}")
        if req.action_spec.note:
            print(f"  note: {req.action_spec.note}")
    return 0


def cmd_studio_chat_poll_loop(args: argparse.Namespace) -> int:
    """chaseos studio chat-poll-loop - drain runtime event spools on a timer (local-only)."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    from runtime.studio.chat.poll_loop import run_poll_cycle, run_poll_loop

    once = getattr(args, "once", False)
    if once:
        result = run_poll_cycle(vault_root)
        if getattr(args, "output_json", False):
            print(json.dumps(result, indent=2, default=str))
        else:
            print(f"poll cycle: imported={result.get('imported', 0)} rejected={result.get('rejected', 0)}")
        return 0
    interval = float(getattr(args, "interval", 2.0) or 2.0)
    max_cycles = getattr(args, "max_cycles", None)

    def _print_cycle(r: dict) -> None:
        if not getattr(args, "output_json", False):
            print(f"  cycle: imported={r.get('imported', 0)} rejected={r.get('rejected', 0)}")

    result = run_poll_loop(vault_root, interval_seconds=interval, max_cycles=max_cycles, on_cycle=_print_cycle)
    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2, default=str))
    else:
        print(f"poll loop done: cycles={result['cycles']} imported={result['imported']}")
    return 0


def cmd_runtime_events_check(args: argparse.Namespace) -> int:
    """chaseos runtime-events check --adapter hermes - bridge self-check."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    from runtime.studio.chat.bridge_smoke import check_runtime_events

    result = check_runtime_events(vault_root, getattr(args, "adapter", "hermes") or "hermes")
    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2, default=str))
        return 0 if result["ok"] else 1
    print(f"runtime-events check — {result['adapter_id']}: {result['summary']}")
    for name, ok in result["checks"].items():
        print(f"  [{'ok' if ok else 'FAIL'}] {name}")
    return 0 if result["ok"] else 1


def cmd_runtime_events_smoke(args: argparse.Namespace) -> int:
    """chaseos runtime-events smoke --adapter hermes - bounded event-bridge smoke."""
