def cmd_studio_chat_import_adapter_events(args: argparse.Namespace) -> int:
    """chaseos studio chat-import-adapter-events - import new runtime adapter spool events into Chat state.

    Local-only, cursor-based, visibility-only. No provider/shell/connector/network.
    """
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.chat.adapter_event_poller import (
        get_poll_status,
        poll_adapter_event_spool,
    )

    spool_path = getattr(args, "spool_path", None)
    if getattr(args, "status_only", False):
        result = get_poll_status(vault_root, spool_path=spool_path or None)
    else:
        result = poll_adapter_event_spool(
            vault_root,
            spool_path=spool_path or None,
            max_events=getattr(args, "limit", None),
        )

    if getattr(args, "output_json", False):
        print(json.dumps(result, indent=2, default=str))
        return 0 if result.get("ok", True) else 1

    if not result.get("ok", True):
        print(f"BLOCKED: {result.get('blocked_reason', 'unknown')}", file=sys.stderr)
        return 1
    if getattr(args, "status_only", False):
        print(f"spool: {result.get('spool_path')}")
        print(f"  cursor offset: {result.get('cursor_offset')}  pending bytes: {result.get('pending_bytes')}")
        print(f"  imported total: {result.get('imported_total')}")
        return 0
    print(f"spool: {result.get('spool_path')}")
    print(f"  imported: {result.get('imported')}  duplicates: {result.get('duplicates')}  rejected: {result.get('rejected')}")
    print(f"  cursor offset: {result.get('cursor_offset')}  more available: {result.get('more_available')}")
    for ref in result.get("imported_refs", [])[:10]:
        print(f"   + {ref.get('event_type')} → {ref.get('thread_id')} ({ref.get('source_event_id')})")
    for err in result.get("errors", [])[:5]:
        print(f"   ! {err}")
    return 0


def cmd_studio_approve(args: argparse.Namespace) -> int:
    """chaseos studio approve APPROVAL_ID - approve a pending Studio write request."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.service import StudioService, StudioServiceError
    svc = StudioService(vault_root)
    try:
        approved = svc.approve(args.approval_id, reviewed_by=getattr(args, "reviewed_by", "operator"))
        result = svc.execute_approved(args.approval_id)
    except StudioServiceError as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps({"ok": True, "approval_id": approved.approval_id, "status": result.status, "writes": result.writes}, indent=2, default=str))
        return 0

    print(f"Approved [{args.approval_id}] → {result.status}")
    for w in result.writes:
        print(f"  wrote: {w}")
    return 0


