def cmd_studio_provenance(args: argparse.Namespace) -> int:
    """chaseos studio provenance PATH - trace a file's capture and promotion history."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.provenance import inspect_provenance
    model = inspect_provenance(vault_root, args.file_path)

    if getattr(args, "output_json", False):
        print(json.dumps(model, indent=2, default=str))
        return 0 if model["ok"] else 1

    if not model["ok"]:
        print(f"ERROR: {model['error']}", file=sys.stderr)
        return 1

    print(f"Provenance: {model['file_name']}")
    chain = model["chain"]
    print(f"  Capture ID:       {chain.get('capture_id', 'unknown')}")
    print(f"  Captured at:      {chain.get('captured_at', 'unknown')}")
    print(f"  Source platform:  {chain.get('source_platform', 'unknown')}")
    print(f"  Input class:      {chain.get('input_class', 'unknown')}")
    print(f"  Capture method:   {chain.get('capture_method', 'unknown')}")
    print(f"  Promotion status: {model['promotion_status']}")
    print(f"  Trust state:      {model['trust_state']}")
    print(f"  Injection scan:   {model['injection_scan']}")
    print(f"  Dedup status:     {model['dedup_status']}")
    if chain.get("content_sha256"):
        print(f"  SHA-256:          {chain['content_sha256'][:16]}…")
    if chain.get("source_url"):
        print(f"  Source URL:       {chain['source_url']}")
    if chain.get("title"):
        print(f"  Title:            {chain['title']}")
    return 0


