def cmd_studio_schedule_inspect(args: argparse.Namespace) -> int:
    """chaseos studio schedule-inspect SCHEDULE_ID - full detail for a single schedule."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.schedule_inspector import inspect_schedule
    limit = getattr(args, "changes", 10)
    model = inspect_schedule(vault_root, args.schedule_id, state_log_limit=limit)

    if getattr(args, "output_json", False):
        print(json.dumps(model, indent=2, default=str))
        return 0

    if not model["ok"]:
        print(f"ERROR: {model['error']}", file=sys.stderr)
        return 1

    s = model["schedule"]
    print(f"Schedule: {s['schedule_id']}")
    print(f"  Workflow:         {s.get('workflow_id') or s.get('command_id') or '—'}")
    print(f"  Enabled:          {s['enabled']}")
    print(f"  Shadow mode:      {s['shadow_mode']}")
    print(f"  Cadence:          {s.get('cron_expression') or s.get('cadence_type') or '?'}  ({s.get('timezone') or ''})")
    print(f"  Runtime target:   {s.get('runtime_adapter_target')}")
    print(f"  Trigger source:   {s.get('trigger_source')}")
    print(f"  Approval policy:  {s.get('approval_policy')}")
    print(f"  Failure behavior: {s.get('failure_behavior')}")
    print(f"  Delivery target:  {s.get('delivery_primary_target')}")
    print(f"  Vault local only: {s.get('vault_local_only')}")
    print(f"  Task types:       {', '.join(s.get('allowed_workflow_task_types') or [])}")
    print(f"  Created:          {s.get('created_at')}  by {s.get('created_by')}")
    if s.get("rationale"):
        print(f"  Rationale:        {str(s['rationale'])[:120]}")

    changes = model.get("recent_state_changes") or []
    if changes:
        print(f"\nRecent state changes ({len(changes)}):")
        for c in changes:
            ts = (c.get("timestamp_utc") or "")[:19]
            print(f"  [{ts}]  {c.get('action')}  (was {c.get('previous_enabled')} → {c.get('new_enabled')})")
    else:
        print("\nNo state-change history recorded.")
    return 0


