def cmd_studio_graph_view_static_render(args: argparse.Namespace) -> int:
    """chaseos studio graph-view-static-render - render a local static graph artifact."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None)).resolve()
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.graph_view_static_renderer import (
        build_graph_view_static_render_model,
        render_graph_view_static_html,
        write_graph_view_static_html,
    )

    try:
        if getattr(args, "write", False):
            model = write_graph_view_static_html(
                vault_root,
                focus_node_id=getattr(args, "focus_node_id", None),
                focus_path=getattr(args, "focus_path", None),
                folder_path=getattr(args, "folder_path", None),
                max_files=getattr(args, "max_files", None),
                max_bytes_per_file=getattr(args, "max_bytes_per_file", None),
                max_nodes=getattr(args, "max_nodes", None),
                max_edges=getattr(args, "max_edges", None),
                layout_node_limit=getattr(args, "layout_node_limit", None),
                content_excerpt_bytes=getattr(args, "content_excerpt_bytes", None),
                output_path=getattr(args, "output_path", None),
            )
        else:
            model = build_graph_view_static_render_model(
                vault_root,
                focus_node_id=getattr(args, "focus_node_id", None),
                focus_path=getattr(args, "focus_path", None),
                folder_path=getattr(args, "folder_path", None),
                max_files=getattr(args, "max_files", None),
                max_bytes_per_file=getattr(args, "max_bytes_per_file", None),
                max_nodes=getattr(args, "max_nodes", None),
                max_edges=getattr(args, "max_edges", None),
                layout_node_limit=getattr(args, "layout_node_limit", None),
                content_excerpt_bytes=getattr(args, "content_excerpt_bytes", None),
            )
            html_text = render_graph_view_static_html(model)
            model["artifact"]["preview_html_bytes"] = len(html_text.encode("utf-8"))
    except Exception as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(model, indent=2, default=str))
        return 0 if model.get("ok", True) else 1

    mode = "WRITE" if getattr(args, "write", False) else "DRY RUN"
    summary = model.get("summary") or {}
    readiness = model.get("readiness") or {}
    artifact = model.get("artifact") or {}
    print(f"ChaseOS Studio Graph View Static Render [{mode}]")
    print(f"  status: {model.get('status')}")
    print(f"  visible: nodes={summary.get('visible_node_count', 0)} edges={summary.get('visible_edge_count', 0)}")
    print(f"  layout: {summary.get('layout_algorithm')}")
    print(f"  static_graph_renderer_ready: {readiness.get('static_graph_renderer_ready')}")
    print(f"  browser_visual_qa_ready: {readiness.get('browser_visual_qa_ready')}")
    print(f"  html_output_path: {artifact.get('html_output_path') or '(none)'}")
    print(f"  writes: {', '.join(model.get('writes') or []) or '(none)'}")
    print(f"  next_recommended_pass: {readiness.get('next_recommended_pass')}")
    if readiness.get("blockers"):
        print(f"  blockers: {', '.join(str(item) for item in readiness.get('blockers', []))}")
    if readiness.get("warnings"):
        print(f"  warnings: {', '.join(str(item) for item in readiness.get('warnings', []))}")
    print("  Boundary: local static graph render; HTML writes require --write and stay under 07_LOGS/Studio-Graph-Views; no server, graph-index writes, node edits, workflow execution, provider calls, or canonical writeback.")
    return 0 if model.get("ok", True) else 1


