    print(f"  local_app_built: {desktop.get('local_app_built')} url={desktop.get('local_app_url')}")
    startup = model.get("runtime_startup") or {}
    print(
        "  runtime_startup: "
        f"{startup.get('surface_count', 0)} surfaces, "
        f"{startup.get('manageable_surface_count', 0)} controllable, "
        f"{startup.get('visual_surface_count', 0)} visual"
    )
    readiness = startup.get("readiness_summary") or {}
    print(
        "  readiness: "
        f"{readiness.get('readiness_packet_count', 0)} packets, "
        f"{readiness.get('approval_missing_count', 0)} missing approvals, "
        f"host_mutation_allowed_now={readiness.get('host_mutation_allowed_now')}"
    )
    print("  surfaces:")
