def cmd_studio_desktop_shell_app(args: argparse.Namespace) -> int:
    """chaseos studio desktop-shell-app - serve the local read-only Studio MVP shell."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None)).resolve()
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.desktop_shell_app import (
        StudioDesktopShellAppError,
        build_studio_desktop_shell_app_plan,
        run_node_inspector_shell_panel_qa_runner,
        serve_studio_desktop_shell_app,
        smoke_test_studio_desktop_shell_app,
    )

    host = getattr(args, "host", "127.0.0.1")
    port = int(getattr(args, "port", 8772))
    runtime_id = getattr(args, "runtime_id", None)
    dry_run = bool(getattr(args, "dry_run", False))
    smoke = bool(getattr(args, "smoke", False))
    qa_runner = bool(getattr(args, "qa_runner", False))
    requested_planning_mode = getattr(args, "planning_mode", None)
    planning_mode = requested_planning_mode or ("full" if smoke or qa_runner else "fast")
    # Full dry-run proof is the operator's repeatable readiness check.  Do not
    # mark genuinely buildable read-only panels as degraded only because the
    # server/smoke responsiveness guard is set to 10s; long-running full dry-runs
    # may wait for the bounded panel builders to finish.  Interactive serving and
    # smoke paths keep the hard fail-open timeout so a slow panel cannot block the
    # shell from starting or completing a smoke probe.
    panel_timeout_seconds = 10.0 if planning_mode == "full" and not dry_run else None

    def _build_plan() -> dict:
        return build_studio_desktop_shell_app_plan(
            vault_root,
            runtime_id=runtime_id,
            host=host,
            port=port,
            planning_mode=planning_mode,
            panel_timeout_seconds=panel_timeout_seconds,
        )

    if getattr(args, "dry_run", False):
        try:
            plan = _build_plan()
        except StudioDesktopShellAppError as exc:
            if getattr(args, "output_json", False):
                print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
            else:
                print(f"ERROR: {exc}", file=sys.stderr)
            return 1
        if getattr(args, "output_json", False):
            print(json.dumps(plan, indent=2, default=str))
        else:
            print(f"ChaseOS Studio MVP app plan: {plan['url']}")
            print("  Dry run only; server not started.")
            print("  Boundary: localhost-only and read-only; full desktop shell remains planned.")
        return 0 if plan.get("ok", True) else 1

    if getattr(args, "smoke", False):
        try:
            smoke = smoke_test_studio_desktop_shell_app(
                vault_root,
                runtime_id=runtime_id,
                host=host,
                port=port if bool(getattr(args, "use_requested_port", False)) else 0,
                timeout_seconds=float(getattr(args, "smoke_timeout", 5.0)),
                planning_mode=planning_mode,
                panel_timeout_seconds=panel_timeout_seconds,
            )
        except StudioDesktopShellAppError as exc:
            if getattr(args, "output_json", False):
                print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
            else:
                print(f"ERROR: {exc}", file=sys.stderr)
            return 1
        if getattr(args, "output_json", False):
            print(json.dumps(smoke, indent=2, default=str))
        else:
            print(f"Studio Desktop Shell smoke: {'PASS' if smoke.get('ok') else 'FAIL'}")
            print(f"  base_url: {smoke.get('base_url')}")
            print(f"  server_stopped: {smoke.get('server_stopped')}")
            for check in smoke.get("checks") or []:
                print(f"  {check.get('route')}: {'ok' if check.get('ok') else 'failed'}")
        return 0 if smoke.get("ok") else 1

    if getattr(args, "qa_runner", False):
        qa = run_node_inspector_shell_panel_qa_runner(
            vault_root,
            runtime_id=runtime_id,
            host=host,
            timeout_seconds=float(getattr(args, "smoke_timeout", 90.0)),
            write_evidence=bool(getattr(args, "write_qa_evidence", False)),
            evidence_slug=getattr(args, "qa_evidence_slug", None),
        )
        if getattr(args, "output_json", False):
            print(json.dumps(qa, indent=2, default=str))
        else:
            print(f"Studio Node Inspector shell-panel QA runner: {'PASS' if qa.get('ok') else 'FAIL'}")
            print(f"  base_url: {qa.get('base_url')}")
            print(f"  server_stopped: {qa.get('server_stopped')}")
            print(f"  visual_browser_qa_complete: {qa.get('visual_browser_qa_complete')}")
            evidence = qa.get("evidence") or {}
            if evidence.get("written"):
                print(f"  evidence: {evidence.get('markdown_path')}")
        return 0 if qa.get("ok") else 1

    try:
        plan = _build_plan()
    except StudioDesktopShellAppError as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(plan, indent=2, default=str))
        sys.stdout.flush()
    else:
        print(f"ChaseOS Studio MVP serving at {plan['url']}")
        print("Boundary: localhost-only read-only shell mount; no workflow execution or startup mutation.")
        sys.stdout.flush()
    try:
        serve_studio_desktop_shell_app(
            vault_root,
            runtime_id=runtime_id,
            host=host,
            port=port,
            serve_seconds=getattr(args, "serve_seconds", None),
            planning_mode=planning_mode,
            panel_timeout_seconds=panel_timeout_seconds,
        )
    except KeyboardInterrupt:
        return 0
    except StudioDesktopShellAppError as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    return 0


def _print_studio_runtime_startup_controls_result(model: dict, as_json: bool) -> int:
    if as_json:
        print(json.dumps(model, indent=2, default=str))
        return 0 if model.get("ok", True) else 1

    print(f"{model.get('title', 'Runtime Startup Controls')}")
    if model.get("runtime_filter") is not None:
        print(f"  runtime_filter: {model.get('runtime_filter')}")
        print(f"  runtime_count: {model.get('runtime_count')}")
        print(f"  surface_count: {model.get('surface_count')}")
        print(f"  mutation_actions_enabled: {model.get('mutation_actions_enabled')}")
        for card in model.get("surface_cards", []):
            print(
                "  - "
                f"{card.get('runtime_id')}/{card.get('surface_id')}: "
                f"state={card.get('current_state')} "
                f"studio_control_enabled={card.get('studio_control_enabled')} "
                f"visual_ui_built={card.get('studio_visual_toggle_built')}"
            )
            commands = card.get("commands") or {}
            enable = (commands.get("enable") or {}).get("studio_toggle")
            disable = (commands.get("disable") or {}).get("studio_toggle")
            if enable:
                print(f"    enable: {enable}")
            if disable:
                print(f"    disable: {disable}")
    elif model.get("action"):
        action = model["action"]
        result = action.get("result") or {}
        print(
            "  action: "
            f"{action.get('id')} status={action.get('status')} "
            f"writes_host_startup={action.get('writes_host_startup')}"
        )
        print(
            "  target: "
            f"{model.get('runtime_id')}/{model.get('surface_id')} "
            f"intent={model.get('intent')} "
            f"before={result.get('before_state')} after={result.get('after_state')}"
        )
        if result.get("marker_path"):
            print(f"  marker_path: {result.get('marker_path')}")
        approval_gate = action.get("approval_gate") or {}
        if approval_gate:
            print(f"  approval_gate_ready: {approval_gate.get('ready')}")
            print(f"  approval_consumed: {approval_gate.get('approval_consumed')}")
            print(f"  idempotency_marker_written: {approval_gate.get('idempotency_marker_written')}")
            print(f"  host_mutation_attempted: {action.get('host_mutation_attempted')}")
    if model.get("errors"):
        print(f"  errors: {json.dumps(model.get('errors'), indent=2)}")
    print("  Boundary: Studio CLI wraps lifecycle startup-surface commands; use the desktop shell Runtime Cockpit panel for visual controls.")
    return 0 if model.get("ok", True) else 1


def cmd_studio_runtime_startup_controls(args: argparse.Namespace) -> int:
    """chaseos studio runtime-startup-controls - model or toggle runtime startup controls."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None)).resolve()
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.runtime_startup_controls import (
        RuntimeStartupControlError,
        run_runtime_startup_control_action,
    )

    action = getattr(args, "action", "model")
    runtime_id = getattr(args, "runtime_id", None)
    surface_id = getattr(args, "surface_id", None)
    intent = getattr(args, "startup_intent", None)
    if action in {"dry-run", "toggle"}:
        if not runtime_id or not surface_id or not intent:
            print(
                "ERROR: studio runtime-startup-controls --action dry-run|toggle requires --runtime, --surface, and --intent",
                file=sys.stderr,
            )
            return 1
        if action == "toggle" and not bool(getattr(args, "confirm_action", False)):
            print(
                "ERROR: studio runtime-startup-controls --action toggle requires --confirm-action; use --action dry-run first",
                file=sys.stderr,
            )
            return 1
        try:
            gate_context = build_startup_surface_gate_context(runtime_id, surface_id, intent)
        except ValueError as exc:
            print(f"ERROR: {exc}", file=sys.stderr)
            return 1
        blocked = _check_runtime_operation_or_block(
            args,
            str(gate_context["operation"]),
            write_targets=list(gate_context.get("write_targets") or []),
            external_api=str(gate_context.get("external_api") or ""),
            external_side_effect=bool(gate_context.get("external_side_effect")),
        )
        if blocked is not None:
            return blocked

    try:
        model = run_runtime_startup_control_action(
            vault_root,
            runtime_id=runtime_id,
            surface_id=surface_id,
            intent=intent,
            action=action,
            confirm_action=bool(getattr(args, "confirm_action", False)),
            requested_by=str(getattr(args, "requested_by", "studio") or "studio"),
            gate_approval_id=getattr(args, "gate_approval_id", None),
            plan_digest=getattr(args, "plan_digest", None),
        )
    except RuntimeStartupControlError as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    return _print_studio_runtime_startup_controls_result(model, as_json=getattr(args, "output_json", False))


def cmd_studio_acquisition_cockpit(args: argparse.Namespace) -> int:
    """chaseos studio acquisition-cockpit - render/read Phase 10A0 local intake cockpit."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None)).resolve()
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.acquisition_cockpit import (
        CockpitActionError,
        render_acquisition_cockpit_html,
        run_acquisition_cockpit_action,
    )

    try:
        model = run_acquisition_cockpit_action(
            vault_root,
            profile=getattr(args, "profile", "strikezone"),
            action=getattr(args, "action", "model"),
            source_class=getattr(args, "source_class", None),
            source_path=getattr(args, "source_path", None),
            open_target=getattr(args, "open_target", None),
            open_path=getattr(args, "open_path", None),
            briefing_input=getattr(args, "briefing_input", None),
            reviewed=bool(getattr(args, "reviewed", False)),
            reviewed_by=getattr(args, "reviewed_by", "operator"),
            allow_non_preview=bool(getattr(args, "allow_non_preview", False)),
            confirm_action=bool(getattr(args, "confirm_action", False)),
            pulse_recipient=getattr(args, "pulse_recipient", "Hermes"),
            pulse_candidate_kinds=getattr(args, "pulse_candidate_kinds", None),
            pulse_candidate_id=getattr(args, "pulse_candidate_id", None),
            pulse_limit=getattr(args, "pulse_limit", None),
            pulse_skip_duplicate_check=bool(getattr(args, "pulse_skip_duplicate_check", False)),
            pulse_schedule_ids=getattr(args, "pulse_schedule_ids", None),
            pulse_force_due=bool(getattr(args, "pulse_force_due", False)),
            operator_approved=bool(getattr(args, "operator_approved", False)),
            gate_policy_defined=bool(getattr(args, "gate_policy_defined", False)),
            external_sender_allowance_present=bool(
                getattr(args, "external_sender_allowance_present", False)
            ),
            duplicate_work_fingerprint_reviewed=bool(
                getattr(args, "duplicate_work_fingerprint_reviewed", False)
            ),
            operator_approval_ref=getattr(args, "operator_approval_ref", None),
            permission_envelope_ref=getattr(args, "permission_envelope_ref", None),
            run_queue_scope_ref=getattr(args, "run_queue_scope_ref", None),
            audit_identity_ref=getattr(args, "audit_identity_ref", None),
            runtime_adapter_scope_ref=getattr(args, "runtime_adapter_scope_ref", None),
            rollback_plan_ref=getattr(args, "rollback_plan_ref", None),
            external_scheduler_denial_ref=getattr(args, "external_scheduler_denial_ref", None),
            canonical_writeback_denial_ref=getattr(args, "canonical_writeback_denial_ref", None),
        )
        output_html = getattr(args, "output_html", None)
        if output_html:
            output_path = Path(output_html)
            if not output_path.is_absolute():
                output_path = Path.cwd() / output_path
            output_path = output_path.resolve()
            if output_path != vault_root and vault_root not in output_path.parents:
                raise ValueError("--output-html must stay inside the vault root")
            output_path.parent.mkdir(parents=True, exist_ok=True)
            output_path.write_text(render_acquisition_cockpit_html(model), encoding="utf-8")
            model = dict(model)
            model["html_output_path"] = str(output_path)
            model["writes"] = list(model.get("writes", [])) + [str(output_path)]
    except (ValueError, CockpitActionError) as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"error": str(exc)}, indent=2))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "output_json", False):
        print(json.dumps(model, indent=2, default=str))
        return 0

    print(f"{model['title']}: profile={model['profile']}")
    print(f"  Sources found: {model['status']['source_count']}")
    if model.get("action"):
        action = model["action"]
        print(f"  Action: {action['id']} [{action['status']}]")
        if action.get("writes"):
            print("  Action writes:")
            for path in action["writes"]:
                print(f"    - {path}")
    for card in model["source_class_cards"]:
        state = "missing" if card["missing"] else "ready"
        print(f"  {card['source_class']}: {card['file_count']} file(s) [{state}] -> {card['folder']}")
    if model.get("html_output_path"):
        print(f"  HTML written: {model['html_output_path']}")
    print("  Boundary: local-only; no browser/MCP/provider/delivery/canonical authority added")
    return 0


def cmd_studio_shell(args: argparse.Namespace) -> int:
    """chaseos studio shell - launch the ChaseOS Studio desktop window (Pass 10A)."""
    try:
        from runtime.studio.shell.main import main as shell_main
    except ImportError as exc:
        print(f"ERROR: PyWebView not installed. Run: pip install pywebview==6.2.1\nDetail: {exc}", file=sys.stderr)
        return 1

    vault_root_arg = getattr(args, "vault_root", None)
    dev = bool(getattr(args, "dev", False))
    initial_hash = getattr(args, "initial_hash", None)
    runtime_activity_services = bool(getattr(args, "runtime_activity_services", False))
    try:
        shell_main(
            vault_root_override=vault_root_arg,
            dev=dev,
            initial_hash=initial_hash,
            runtime_activity_services=runtime_activity_services,
        )
    except ValueError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1
    except KeyboardInterrupt:
        pass
    return 0


