def cmd_studio_packaged_app_visual_qa(args: argparse.Namespace) -> int:
    """chaseos studio packaged-app-visual-qa - capture bounded packaged app visual QA."""

    def _compact_all_pages_stdout_report(report: dict[str, Any]) -> dict[str, Any]:
        """Keep all-page CLI JSON bounded so completed batch runs return promptly."""

        evidence = report.get("evidence") if isinstance(report.get("evidence"), dict) else {}
        batch = report.get("batch") if isinstance(report.get("batch"), dict) else {}
        batch_result = batch.get("result") if isinstance(batch.get("result"), dict) else {}
        return {
            "ok": bool(report.get("ok")),
            "surface": report.get("surface"),
            "model_version": report.get("model_version"),
            "status": report.get("status"),
            "generated_at": report.get("generated_at"),
            "vault_root": report.get("vault_root"),
            "screenshot_root": report.get("screenshot_root"),
            "page_count": report.get("page_count"),
            "expected_page_count": report.get("expected_page_count"),
            "failed_page_count": report.get("failed_page_count"),
            "capture_mode": report.get("capture_mode"),
            "executable": report.get("executable"),
            "checks": report.get("checks") or [],
            "blockers": report.get("blockers") or [],
            "failed_pages": report.get("failed_pages") or [],
            "batch": {
                "overall_timeout_seconds": batch.get("overall_timeout_seconds"),
                "overall_timeout_config": batch.get("overall_timeout_config"),
                "wait": batch.get("wait"),
                "capture_recovery": batch.get("capture_recovery"),
                "captured_count": batch_result.get("captured_count"),
                "expected_count": batch_result.get("expected_count"),
                "completion_source": batch_result.get("completion_source"),
            },
            "screenshot_hashes": report.get("screenshot_hashes"),
            "write_sentinel": report.get("write_sentinel"),
            "authority": report.get("authority") or {},
            "unverified": report.get("unverified") or [],
            "next_recommended_pass": report.get("next_recommended_pass"),
            "evidence": evidence,
            "writes_performed": bool(report.get("writes_performed")),
            "full_report": {
                "written": bool(evidence.get("written")),
                "json_path": evidence.get("json_path"),
                "markdown_path": evidence.get("markdown_path"),
                "screenshot_root": evidence.get("screenshot_root"),
                "stdout_compacted": True,
                "reason": "all_pages_stdout",
                "recommendation": (
                    None
                    if evidence.get("written")
                    else "Use --write-evidence to persist the full per-page report."
                ),
            },
        }

    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None)).resolve()
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.studio.packaged_app_visual_qa import (
        DEFAULT_EVIDENCE_ROOT,
        _resolve_evidence_root,
        build_packaged_app_all_pages_composite_visual_qa,
        build_packaged_app_all_pages_visual_qa,
        build_packaged_app_visual_qa,
        write_all_pages_visual_qa_evidence,
        write_visual_qa_evidence,
    )

    from datetime import datetime, timezone

    screenshot_path = getattr(args, "screenshot_path", None)
    all_pages = bool(getattr(args, "all_pages", False))
    evidence_root = None
    slug = getattr(args, "evidence_slug", None)
    if getattr(args, "write_evidence", False) and (screenshot_path is None or all_pages):
        try:
            evidence_root = _resolve_evidence_root(
                vault_root,
                getattr(args, "evidence_root", None) or DEFAULT_EVIDENCE_ROOT,
            )
        except ValueError as exc:
            if getattr(args, "output_json", False):
                print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
            else:
                print(f"ERROR: {exc}", file=sys.stderr)
            return 1
        slug = slug or datetime.now(timezone.utc).strftime(
            "%Y-%m-%d-studio-packaged-app-visual-qa"
        )
        if all_pages:
            if getattr(args, "screenshot_root", None) is None:
                args.screenshot_root = evidence_root / f"{slug}-screenshots"
        elif screenshot_path is None:
            screenshot_path = evidence_root / f"{slug}.png"

    try:
        if all_pages:
            composite_evidence_paths = getattr(args, "compose_evidence_json", [])
            if composite_evidence_paths:
                report = build_packaged_app_all_pages_composite_visual_qa(
                    vault_root,
                    evidence_json_paths=composite_evidence_paths,
                )
            else:
                single_launch_batch = getattr(args, "single_launch_batch", None)
                report = build_packaged_app_all_pages_visual_qa(
                    vault_root,
                    executable_path=getattr(args, "executable_path", None),
                    screenshot_root=getattr(args, "screenshot_root", None),
                    webview2_user_data_root=getattr(args, "webview2_user_data_root", None),
                    temp_root=getattr(args, "temp_root", None),
                    allow_external_runtime_dirs=bool(getattr(args, "allow_external_runtime_dirs", False)),
                    settle_seconds=float(getattr(args, "settle_seconds", 10.0)),
                    window_timeout_seconds=float(getattr(args, "window_timeout_seconds", 15.0)),
                    terminate_timeout_seconds=float(getattr(args, "terminate_timeout_seconds", 5.0)),
                    require_nonblank=not getattr(args, "allow_blank_screenshot", False),
                    min_unique_colors=int(getattr(args, "min_unique_colors", 8)),
                    max_dominant_ratio=float(getattr(args, "max_dominant_ratio", 0.95)),
                    batch_launch=bool(single_launch_batch) if single_launch_batch is not None else True,
                    markdown_sentinel_retry_count=int(getattr(args, "markdown_sentinel_retry_count", 3)),
                    markdown_sentinel_ignore_paths=getattr(args, "markdown_sentinel_ignore_path", []),
                    visual_readiness_retry_count=int(getattr(args, "visual_readiness_retry_count", 2)),
                    visual_readiness_retry_settle_seconds=float(getattr(args, "visual_readiness_retry_settle_seconds", 45.0)),
                    panel_ids=getattr(args, "panel_id", []),
                    overall_timeout_seconds=getattr(args, "overall_timeout_seconds", None),
                )
        else:
            report = build_packaged_app_visual_qa(
                vault_root,
                executable_path=getattr(args, "executable_path", None),
                screenshot_path=screenshot_path,
                initial_hash=getattr(args, "initial_hash", None),
                webview2_user_data_root=getattr(args, "webview2_user_data_root", None),
                temp_root=getattr(args, "temp_root", None),
                allow_external_runtime_dirs=bool(getattr(args, "allow_external_runtime_dirs", False)),
                settle_seconds=float(getattr(args, "settle_seconds", 10.0)),
                window_timeout_seconds=float(getattr(args, "window_timeout_seconds", 15.0)),
                terminate_timeout_seconds=float(getattr(args, "terminate_timeout_seconds", 5.0)),
                require_nonblank=not getattr(args, "allow_blank_screenshot", False),
                min_unique_colors=int(getattr(args, "min_unique_colors", 8)),
                max_dominant_ratio=float(getattr(args, "max_dominant_ratio", 0.95)),
                markdown_sentinel_ignore_paths=getattr(args, "markdown_sentinel_ignore_path", []),
            )
    except ValueError as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    if getattr(args, "write_evidence", False):
        try:
            if all_pages:
                report["evidence"] = write_all_pages_visual_qa_evidence(
                    vault_root,
                    report,
                    evidence_slug=getattr(args, "evidence_slug", None),
                    evidence_root=getattr(args, "evidence_root", None),
                )
            else:
                report["evidence"] = write_visual_qa_evidence(
                    vault_root,
                    report,
                    evidence_slug=getattr(args, "evidence_slug", None),
                    evidence_root=getattr(args, "evidence_root", None),
                )
        except ValueError as exc:
            if getattr(args, "output_json", False):
                print(json.dumps({"ok": False, "error": str(exc)}, indent=2))
            else:
                print(f"ERROR: {exc}", file=sys.stderr)
            return 1
        report["writes_performed"] = True
    else:
        report["writes_performed"] = False

    if getattr(args, "output_json", False):
        output_report = (
            _compact_all_pages_stdout_report(report)
            if all_pages
            else report
        )
        print(json.dumps(output_report, indent=2, default=str))
        return 0 if report.get("ok") else 1

    if all_pages:
        print(f"Studio packaged app all-page visual QA: {'PASS' if report.get('ok') else 'FAIL'}")
        print(f"  status: {report.get('status')}")
        print(f"  pages: {report.get('page_count')} / {report.get('expected_page_count')}")
        print(f"  failed_pages: {report.get('failed_page_count')}")
        print(f"  screenshot_root: {report.get('screenshot_root')}")
        evidence = report.get("evidence") or {}
        if evidence.get("written"):
            print(f"  evidence: {evidence.get('markdown_path')}")
        return 0 if report.get("ok") else 1

    print(f"Studio packaged app visual QA: {'PASS' if report.get('ok') else 'FAIL'}")
    print(f"  status: {report.get('status')}")
    launch = report.get("launch") or {}
    screenshot = report.get("screenshot") or {}
    print(f"  started: {launch.get('started')}")
    print(f"  pid: {launch.get('process_id')}")
    print(f"  alive_before_capture: {launch.get('process_alive_before_capture')}")
    print(f"  screenshot: {screenshot.get('path')}")
    print(f"  screenshot_exists: {screenshot.get('exists')}")
    visual = screenshot.get("visual_verification") or {}
    print(f"  screenshot_nonblank: {visual.get('ok')}")
    print(f"  unique_colors: {visual.get('unique_color_count')}")
    print(f"  dominant_color_ratio: {visual.get('dominant_color_ratio')}")
    host_policy = (launch.get("host_policy") or report.get("host_policy") or {})
    print(f"  host_policy: {host_policy.get('status')}")
    runtime_dirs = (launch.get("runtime_dirs") or {})
    if runtime_dirs.get("webview2_user_data_root") or runtime_dirs.get("temp_root"):
        print(f"  webview2_user_data_root: {runtime_dirs.get('webview2_user_data_root')}")
        print(f"  temp_root: {runtime_dirs.get('temp_root')}")
    print(f"  terminated: {(report.get('termination') or {}).get('terminated')}")
    evidence = report.get("evidence") or {}
    if evidence.get("written"):
        print(f"  evidence: {evidence.get('markdown_path')}")
    return 0 if report.get("ok") else 1


