def cmd_acquisition_promote(args: argparse.Namespace) -> int:
    """chaseos acquisition promote ARTIFACT_ID --target PATH — promote artifact to vault .md node."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    artifact_id = getattr(args, "artifact_id", None)
    target_path = getattr(args, "target", None)
    note_class  = getattr(args, "note_class", "synthesized")

    if not artifact_id:
        print("ERROR: ARTIFACT_ID is required", file=sys.stderr)
        return 1
    if not target_path:
        print("ERROR: --target PATH is required", file=sys.stderr)
        return 1

    from runtime.acquisition.artifact_store import _connect
    try:
        with _connect(vault_root) as conn:
            cur = conn.execute("SELECT * FROM artifacts WHERE id = ?", (int(artifact_id),))
            row = cur.fetchone()
    except Exception as exc:
        print(f"ERROR: could not read artifact store: {exc}", file=sys.stderr)
        return 1

    if not row:
        print(f"ERROR: artifact id {artifact_id!r} not found in store", file=sys.stderr)
        return 1

    row = dict(row)
    title      = row.get("title") or row.get("source_id") or "Untitled"
    platform   = row.get("source_platform", "unknown")
    url        = row.get("url", "")
    captured   = row.get("captured_at", "")
    text       = row.get("text_content", "")

    # Build vault node with provenance frontmatter
    frontmatter = (
        f"---\n"
        f"title: {title}\n"
        f"type: acquired-note\n"
        f"knowledge_class: {note_class}\n"
        f"cgl_trust_level: external\n"
        f"cgl_sensitivity: internal\n"
        f"cgl_promotion_stage: reviewed\n"
        f"source_platform: {platform}\n"
        f"source_url: {url}\n"
        f"acquired_at: {captured}\n"
        f"promoted_at: {__import__('datetime').datetime.now(__import__('datetime').timezone.utc).replace(microsecond=0).isoformat()}\n"
        f"artifact_store_id: {artifact_id}\n"
        f"---\n\n"
    )
    note_content = frontmatter + text.strip() + "\n"

    # Resolve target path — must be inside vault root and not in a forbidden zone
    norm_target = target_path.replace("\\", "/").lstrip("/")
    abs_target  = (vault_root / norm_target).resolve()
    if not str(abs_target).startswith(str(vault_root.resolve())):
        print("ERROR: target path escapes vault root", file=sys.stderr)
        return 1

    abs_target.parent.mkdir(parents=True, exist_ok=True)
    abs_target.write_text(note_content, encoding="utf-8")

    if getattr(args, "output_json", False):
        print(json.dumps({
            "artifact_id": artifact_id,
            "target": norm_target,
            "title": title,
            "chars": len(text),
        }, indent=2))
        return 0

    print(f"Promoted artifact {artifact_id} → {norm_target}")
    print(f"  Title:    {title}")
    print(f"  Platform: {platform}")
    print(f"  Chars:    {len(text):,}")
    return 0


# ── Argument parser ────────────────────────────────────────────────────────────

def _build_parser() -> argparse.ArgumentParser:
    root = argparse.ArgumentParser(
        prog="chaseos",
        description="ChaseOS -- local-first governed intake and intelligence OS",
    )
    sub = root.add_subparsers(dest="command", metavar="COMMAND")
    sub.required = True

    runtime_parser = sub.add_parser("runtime", help="Runtime inspection, lifecycle health, and coordination-watch surfaces")
    runtime_parser.add_argument(
        "runtime_command",
        choices=[
            "resolve",
            "inventory",
            "status",
            "supervision",
            "provider-status",
            "adapter-governance",
            "surfaces",
            "workspace-mode",
            "providers",
            "fallback-status",
            "queue",
            "provider",
            "browser-cdp",
            "recover",
            "audit-tail",
            "health",
            "health-debug",
            "launch-smoke-inventory",
            "startup-surfaces",
            "startup-surface-settings",
            "startup-surface-toggle-plan",
            "startup-surface-mutation-contract",
            "startup-surface-approval-request",
            "startup-surface-approval-decision",
            "startup-surface-approval-consumption",
            "startup-surface-executor-preflight",
            "startup-surface-transaction-order",
            "startup-surface-executor-readiness",
            "startup-surface-host-boundary-policy",
            "startup-surface-host-mutation-audit-template",
            "startup-surface-success-marker-evidence-verifier",
            "startup-surface-success-marker-acceptance-policy",
            "startup-surface-host-mutation-executor",
            "startup-surface-toggle",
            "coordination-watch",
            "coordination-watch-supervisor",
            "coordination-watch-bootstrap",
            "hermes-gateway-config",
            "doctor",
            "daemon",
            "bus-check",
        ],
        help="Runtime command",
    )
    runtime_parser.add_argument(
        "runtime_subcommand",
        nargs="?",
        default=None,
        help="Optional runtime subcommand, such as queue list/show/retry or provider probe",
    )
    runtime_parser.add_argument(
        "runtime_target",
        nargs="?",
        default=None,
        help="Optional runtime subcommand target, such as a queue item id or primary/fallback",
    )
    runtime_parser.add_argument("--runtime", dest="runtime_id", default=None, help="Runtime id, or 'all' for every discovered runtime")
    runtime_parser.add_argument("--surface", dest="surface_id", default=None, help="Startup surface id for startup-surface toggle/report commands")
    runtime_parser.add_argument("--capability", dest="capability_id", default=None, help="ARSL capability id for runtime surfaces route-review")
    runtime_parser.add_argument(
        "--workspace-path",
        dest="workspace_path",
        default=None,
        metavar="PATH",
        help="Workspace file or folder path for workspace-mode previews",
    )
    runtime_parser.add_argument(
        "--workflow-id",
        dest="workflow_id",
        default=None,
        metavar="WORKFLOW_ID",
        help="Agent Orchestration Runtime workflow id to preview against workspace-mode policy",
    )
    runtime_parser.add_argument(
        "--adapter",
        dest="adapter_id",
        default=None,
        metavar="ADAPTER",
        help="Runtime adapter id for workspace-mode route preview",
    )
    runtime_parser.add_argument(
        "--profile",
        dest="profile_path",
        default=None,
        metavar="PATH",
        help="Explicit workspace-mode profile path for route preview",
    )
    runtime_parser.add_argument(
        "--intent",
        dest="startup_intent",
        choices=["enable", "disable"],
        default=None,
        help="Startup surface toggle intent for startup-surface toggle/report commands",
    )
    runtime_parser.add_argument("--plan-digest", dest="plan_digest", default=None, help="Expected startup surface plan digest for executor preflight")
    runtime_parser.add_argument(
        "--candidate-evidence-json",
        dest="candidate_evidence_json",
        default=None,
        metavar="PATH",
        help="Read-only candidate host-mutation evidence JSON for startup-surface success-marker verifier",
    )
    runtime_parser.add_argument("--vault-root", default=None, metavar="PATH", help="Override vault root path")
    runtime_parser.add_argument("--daemon-interval", type=int, default=None, metavar="SECONDS", dest="daemon_interval", help="Poll interval in seconds for runtime daemon (omit for one-shot)")
    runtime_parser.add_argument("--daemon-max-tasks", type=int, default=5, metavar="N", dest="daemon_max_tasks", help="Max tasks to claim per daemon cycle (default: 5)")
    runtime_parser.add_argument("--daemon-once", action="store_true", dest="daemon_once", help="Run daemon watch loop exactly once and exit")
    runtime_parser.add_argument("--daemon-task-id", default="", metavar="TASK_ID", dest="daemon_task_id", help="One-shot daemon target task id for bounded Chat/runtime proof")
    runtime_parser.add_argument("--synthesize", action="store_true", dest="daemon_synthesize", help="Enable LLM synthesis for chat tasks (requires runtime model credentials)")
    runtime_parser.add_argument("--bus-check-runtime", default="all", metavar="RUNTIME", dest="bus_check_runtime", help="Runtime to bus-check: hermes|openclaw|all (default: all)")
    runtime_parser.add_argument("--bus-check-timeout", type=float, default=30.0, metavar="SECONDS", dest="bus_check_timeout", help="Seconds to wait for bus round-trip in bus-check (default: 30)")
    runtime_parser.add_argument("--refresh", action="store_true", help="Reserved compatibility flag for state refresh")
    runtime_parser.add_argument("--json", action="store_true", dest="output_json", help="Print JSON output")
    runtime_parser.add_argument("--timeout", type=int, default=5, help="Timeout in seconds for runtime health checks")
    runtime_parser.add_argument("--dry-run", action="store_true", help="Plan or inspect without executing controlled recovery actions")
    runtime_parser.add_argument("--confirm", action="store_true", help="Required acknowledgement for live startup-surface enable/disable")
    runtime_parser.add_argument(
        "--allowed-users",
        default=None,
        help="Comma-separated Hermes gateway user ids to add to GATEWAY_ALLOWED_USERS for hermes-gateway-config",
    )
