    from runtime.pulse.native_schedule_activation_gate import REQUIRED_EVIDENCE_SLOTS
    from runtime.pulse.native_schedule_supervised_activation_execution import (
        build_pulse_native_schedule_supervised_activation_execution,
        write_pulse_native_schedule_supervised_activation_execution_proof,
    )

    evidence_refs = {
        "operator_approval_ref": getattr(args, "operator_approval_ref", None),
        "permission_envelope_ref": getattr(args, "permission_envelope_ref", None),
        "run_queue_scope_ref": getattr(args, "run_queue_scope_ref", None),
        "audit_identity_ref": getattr(args, "audit_identity_ref", None),
        "runtime_adapter_scope_ref": getattr(args, "runtime_adapter_scope_ref", None),
        "rollback_plan_ref": getattr(args, "rollback_plan_ref", None),
        "external_scheduler_denial_ref": getattr(args, "external_scheduler_denial_ref", None),
        "canonical_writeback_denial_ref": getattr(args, "canonical_writeback_denial_ref", None),
    }
    schedule_ids = tuple(getattr(args, "schedule_ids", None) or ())
    schedule_ids_arg = schedule_ids if schedule_ids else None

    try:
        if bool(getattr(args, "write_proof", False)) or bool(getattr(args, "execute_activation", False)):
            result = write_pulse_native_schedule_supervised_activation_execution_proof(
                vault_root,
                schedule_ids=schedule_ids_arg,
                evidence_refs=evidence_refs,
                execute_activation=bool(getattr(args, "execute_activation", False)),
            )
        else:
            result = build_pulse_native_schedule_supervised_activation_execution(
                vault_root,
                schedule_ids=schedule_ids_arg,
                evidence_refs=evidence_refs,
            )
    except ValueError as exc:
        if getattr(args, "output_json", False):
            print(json.dumps({"error": str(exc)}, indent=2))
        else:
            print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    payload = result.to_dict()
    if getattr(args, "output_json", False):
        print(json.dumps(payload, indent=2, default=str))
        return 0

    if getattr(args, "execute_activation", False):
        mode = "EXECUTE ACTIVATION"
    elif getattr(args, "write_proof", False):
        mode = "WRITE PROOF"
    else:
        mode = "DRY RUN"
    print(f"Pulse native schedule supervised activation execution proof [{mode}]: {result.execution_status}")
    print(f"  schedules:                   {', '.join(result.schedule_ids)}")
    print(f"  gate_status:                 {result.gate_status}")
    print(f"  run_queue_proof_status:      {result.run_queue_proof_status}")
    print(f"  missing_evidence_slots:      {len(result.missing_evidence_slots)}/{len(REQUIRED_EVIDENCE_SLOTS)}")
    print(f"  execute_requested:           {result.execute_requested}")
    print(f"  manifest_patch_count:        {result.manifest_patch_count}")
    print(f"  schedule_activation_executed:{result.schedule_activation_executed}")
    print(f"  schedule_daemon_started:     {result.schedule_daemon_started}")
    print(f"  real_run_queue_written:      {result.real_run_queue_written}")
    print(f"  agent_bus_task_write_allowed:{result.agent_bus_task_write_allowed}")
    print(f"  runtime_dispatch_allowed:    {result.runtime_dispatch_allowed}")
    print(f"  workflow_execution_allowed:  {result.workflow_execution_allowed}")
    print(f"  provider_or_connector_calls: {result.provider_or_connector_call_allowed}")
    print(f"  canonical_writeback_allowed: {result.canonical_writeback_allowed}")
    if result.writes:
        print("  writes:")
        for path in result.writes:
            print(f"    - {path}")
    return 0


