def cmd_pulse_generate_decks(args: argparse.Namespace) -> int:
    """chaseos pulse generate-decks [--write] [--json]."""
    try:
        vault_root = _resolve_vault(getattr(args, "vault_root", None))
    except RuntimeError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    from runtime.pulse.multi_audience_decks import build_pulse_multi_audience_decks

    result = build_pulse_multi_audience_decks(
        vault_root,
        audiences=getattr(args, "audiences", None),
        slug_prefix=getattr(args, "slug_prefix", None),
        write=bool(getattr(args, "write", False)),
    )
    if getattr(args, "output_json", False):
        print(json.dumps(result.to_dict(), indent=2, default=str))
        return 0

    mode = "WRITE" if result.write_executed else "DRY RUN"
    print(f"Pulse multi-audience deck generation [{mode}]: {result.deck_count} deck(s)")
    for deck in result.decks:
        print(f"  - {deck.audience}: {deck.card_count} cards ({deck.deck_id})")
        if deck.artifact_written:
            print(f"    markdown: {deck.markdown_path}")
            print(f"    json:     {deck.json_path}")
    if not result.write_executed:
        print("  no files written; pass --write to write log-only artifacts")
    return 0


